{
  "name": "WorkShield UAE",
  "description": "An AI assistant that helps UAE employees understand their rights, prepare for MOHRE / freezone disputes, and respond safely to employers."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type EmployerType = 'Mainland' | 'Freezone' | 'Unknown';
export type CaseStage = 'Pre-complaint' | 'Complaint Filed' | 'Mediation' | 'Court' | 'Closed';

export interface EvidenceItem {
  id: string;
  type: 'Contract' | 'Payment Proof' | 'Communication' | 'Other';
  description: string;
  summary: string;
  extractedText?: string;
  tags: string[];
  dateAdded: string;
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface Case {
  id: string;
  title: string;
  employerType: EmployerType;
  issueTypes: string[];
  description: string;
  aiDiagnosis?: string;
  riskLevel?: 'Low' | 'Medium' | 'High';
  stage: CaseStage;
  createdAt: string;
  evidence: EvidenceItem[];
  chatHistory: ChatMessage[];
}

export interface ReplySuggestion {
  tone: 'Soft' | 'Firm' | 'Assertive';
  subject: string;
  body: string;
  rationale: string;
}

export interface KnowledgeArticle {
  id: string;
  title: string;
  category: string;
  content: string;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { Case, ChatMessage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const SYSTEM_INSTRUCTION_CORE = `
You are WorkShield UAE, an expert AI assistant for UAE labour rights. 
Your goal is to help employees understand their rights, organize evidence, and communicate professionally.
WARNING: You are NOT a lawyer. Do NOT give binding legal advice. Always add a disclaimer if the user asks for legal guarantees.
Tone: Professional, calm, objective, supportive, but realistic.
Context: UAE Labour Law (Federal Decree-Law No. 33 of 2021) and Freezone regulations.
`;

export const diagnoseCase = async (description: string, issues: string[], employerType: string): Promise<{ diagnosis: string; risk: 'Low' | 'Medium' | 'High'; recommendations: string[] }> => {
  const prompt = `
    Analyze this UAE labour case.
    Employer Type: ${employerType}
    Issues: ${issues.join(', ')}
    User Description: "${description}"

    Provide a JSON response with:
    1. "diagnosis": A 2-sentence summary of the legal situation.
    2. "risk": "Low", "Medium", or "High" (based on likelihood of bans, financial loss, or legal trouble).
    3. "recommendations": An array of 3-5 immediate specific actionable steps (e.g., "File complaint via app", "Don't sign X").
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION_CORE,
        responseMimeType: 'application/json'
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Diagnosis Error:", error);
    return {
      diagnosis: "Could not analyze at this time. Please try again.",
      risk: "Medium",
      recommendations: ["Consult a legal professional", "Call MOHRE for advice"]
    };
  }
};

export const chatWithAI = async (history: ChatMessage[], newMessage: string, caseContext?: Case): Promise<string> => {
  const contextStr = caseContext ? `
    Current Case Context:
    - Type: ${caseContext.employerType}
    - Issues: ${caseContext.issueTypes.join(', ')}
    - Summary: ${caseContext.summary}
  ` : "";

  // Convert history to Gemini format (simplification for single turn or limited history)
  // For simplicity in this demo, we'll just send the last few messages + context + new message
  // In a real app, strict history mapping is needed.

  const prompt = `
    ${contextStr}

    User Query: ${newMessage}

    Answer the user specifically regarding UAE labour rules. Keep it concise.
  `;

  try {
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-latest',
        contents: prompt,
        config: { systemInstruction: SYSTEM_INSTRUCTION_CORE }
    });
    return response.text || "I apologize, I couldn't generate a response.";
  } catch (error) {
    console.error("Chat Error", error);
    return "Sorry, I am having trouble connecting to the server.";
  }
};

export const analyzeEvidence = async (base64Data: string, mimeType: string): Promise<{ type: string; summary: string; tags: string[] }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest',
      contents: {
        parts: [
          { inlineData: { mimeType, data: base64Data } },
          { text: "Analyze this image (document or chat screenshot) for a UAE labour dispute case. Extract what this is (Contract, Email, WhatsApp, etc.), summarize the key content relevant to a dispute (admissions of debt, threats, dates), and suggest tags." }
        ]
      },
      config: {
        systemInstruction: SYSTEM_INSTRUCTION_CORE,
        responseMimeType: 'application/json',
        responseSchema: {
            type: "OBJECT",
            properties: {
                type: { type: "STRING" },
                summary: { type: "STRING" },
                tags: { type: "ARRAY", items: { type: "STRING" } }
            }
        }
      }
    });
    const text = response.text;
    if(!text) throw new Error("No text");
    return JSON.parse(text);
  } catch (e) {
    console.error(e);
    return { type: "Unknown", summary: "Failed to analyze", tags: [] };
  }
};

export const generateReplies = async (incomingText: string, caseContext: Case): Promise<any[]> => {
    const prompt = `
    The user received this message from their employer: "${incomingText}"
    Case Context: ${caseContext.summary}
    Employer Type: ${caseContext.employerType}

    Generate 3 reply options in JSON format:
    1. Soft/Neutral (Polite inquiry)
    2. Firm (Professional assertion of rights)
    3. Assertive (Warning of escalation)

    JSON Structure:
    [
        { "tone": "Soft", "subject": "...", "body": "...", "rationale": "..." },
        ...
    ]
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-latest',
            contents: prompt,
            config: {
                systemInstruction: SYSTEM_INSTRUCTION_CORE,
                responseMimeType: 'application/json'
            }
        });
        return JSON.parse(response.text || "[]");
    } catch (e) {
        console.error(e);
        return [];
    }
}

export const generateCallPrep = async (caseContext: Case, meetingType: string): Promise<string> => {
     const prompt = `
    The user has a "${meetingType}" coming up for their UAE labour case.
    Case Summary: ${caseContext.summary}
    Employer Type: ${caseContext.employerType}

    Provide a coaching script in Markdown:
    1. **Key Narrative**: A clean, 3-bullet summary of facts they should state.
    2. **Likely Questions**: 3 questions the officer/manager will ask.
    3. **Suggested Answers**: How to answer those questions safely.
    4. **Traps to Avoid**: What NOT to say.
    `;

    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-latest',
        contents: prompt,
        config: { systemInstruction: SYSTEM_INSTRUCTION_CORE }
    });
    return response.text || "Could not generate prep.";
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import CaseList from './components/CaseList';
import NewCaseWizard from './components/NewCaseWizard';
import CaseDetail from './components/CaseDetail';
import KnowledgeBase from './components/KnowledgeBase';
import DisclaimerModal from './components/DisclaimerModal';
import { Case } from './types';

const App: React.FC = () => {
  const [cases, setCases] = useState<Case[]>([]);
  const [acceptedDisclaimer, setAcceptedDisclaimer] = useState(false);

  // Load from local storage on mount
  useEffect(() => {
    const storedCases = localStorage.getItem('ws_cases');
    if (storedCases) {
      setCases(JSON.parse(storedCases));
    }
    const storedDisclaimer = localStorage.getItem('ws_disclaimer');
    if (storedDisclaimer === 'true') {
      setAcceptedDisclaimer(true);
    }
  }, []);

  // Save to local storage on change
  useEffect(() => {
    localStorage.setItem('ws_cases', JSON.stringify(cases));
  }, [cases]);

  const handleDisclaimerAccept = () => {
    setAcceptedDisclaimer(true);
    localStorage.setItem('ws_disclaimer', 'true');
  };

  const addCase = (newCase: Case) => {
    setCases([newCase, ...cases]);
  };

  const updateCase = (updatedCase: Case) => {
    setCases(cases.map(c => c.id === updatedCase.id ? updatedCase : c));
  };

  const deleteCase = (id: string) => {
    setCases(cases.filter(c => c.id !== id));
  };

  return (
    <HashRouter>
      {!acceptedDisclaimer && <DisclaimerModal onAccept={handleDisclaimerAccept} />}
      <Layout>
        <Routes>
          <Route path="/" element={<CaseList cases={cases} onDelete={deleteCase} />} />
          <Route path="/new" element={<NewCaseWizard onSave={addCase} />} />
          <Route path="/case/:id/*" element={<CaseDetail cases={cases} onUpdate={updateCase} />} />
          <Route path="/knowledge" element={<KnowledgeBase />} />
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

export default App;

