import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ISSUE_TYPES } from '../constants';
import { diagnoseCase } from '../services/geminiService';
import { Case, EmployerType } from '../types';
import { Loader2, CheckCircle } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid'; // Using a simple random ID generator

// Simple UUID polyfill if uuid lib not avail, but let's assume standard JS Math random for simple ID
const generateId = () => Math.random().toString(36).substr(2, 9);

interface Props {
  onSave: (c: Case) => void;
}

const NewCaseWizard: React.FC<Props> = ({ onSave }) => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    employerType: 'Unknown' as EmployerType,
    issues: [] as string[],
    description: '',
    title: ''
  });

  const [aiResult, setAiResult] = useState<{diagnosis: string, risk: 'Low' | 'Medium' | 'High', recommendations: string[]} | null>(null);

  const toggleIssue = (issue: string) => {
    setFormData(prev => ({
      ...prev,
      issues: prev.issues.includes(issue) 
        ? prev.issues.filter(i => i !== issue) 
        : [...prev.issues, issue]
    }));
  };

  const handleDiagnose = async () => {
    if (!formData.description) return;
    setLoading(true);
    try {
      const result = await diagnoseCase(formData.description, formData.issues, formData.employerType);
      setAiResult(result);
      setStep(3);
    } catch (error) {
      console.error(error);
      // Fallback
      setStep(3);
    } finally {
      setLoading(false);
    }
  };

  const handleSave = () => {
    const newCase: Case = {
      id: generateId(),
      title: formData.title || `Case ${new Date().toLocaleDateString()}`,
      employerType: formData.employerType,
      issueTypes: formData.issues,
      description: formData.description,
      aiDiagnosis: aiResult?.diagnosis,
      riskLevel: aiResult?.risk,
      stage: 'Pre-complaint',
      createdAt: new Date().toISOString(),
      evidence: [],
      chatHistory: []
    };
    onSave(newCase);
    navigate(`/case/${newCase.id}`);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
      <div className="mb-6 flex justify-between items-center text-sm text-gray-400">
        <span className={step >= 1 ? "text-blue-600 font-bold" : ""}>1. Details</span>
        <span className="w-8 h-px bg-gray-200"></span>
        <span className={step >= 2 ? "text-blue-600 font-bold" : ""}>2. Situation</span>
        <span className="w-8 h-px bg-gray-200"></span>
        <span className={step >= 3 ? "text-blue-600 font-bold" : ""}>3. Review</span>
      </div>

      {step === 1 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Employer Type</label>
            <div className="grid grid-cols-3 gap-3">
              {['Mainland', 'Freezone', 'Unknown'].map((type) => (
                <button
                  key={type}
                  onClick={() => setFormData({...formData, employerType: type as EmployerType})}
                  className={`py-3 px-2 rounded-lg border text-sm font-medium transition ${
                    formData.employerType === type 
                      ? 'bg-blue-50 border-blue-500 text-blue-700' 
                      : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'
                  }`}
                >
                  {type}
                </button>
              ))}
            </div>
            {formData.employerType === 'Freezone' && (
              <p className="text-xs text-gray-500 mt-2">e.g., DMCC, JAFZA, DSO, TECOM</p>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">What is the issue? (Select all that apply)</label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
              {ISSUE_TYPES.map(issue => (
                <button
                  key={issue}
                  onClick={() => toggleIssue(issue)}
                  className={`text-left px-3 py-2 rounded border text-sm transition ${
                    formData.issues.includes(issue)
                      ? 'bg-blue-50 border-blue-500 text-blue-700'
                      : 'border-gray-200 text-gray-600 hover:bg-gray-50'
                  }`}
                >
                  {issue}
                </button>
              ))}
            </div>
          </div>

          <button 
            disabled={formData.issues.length === 0}
            onClick={() => setStep(2)}
            className="w-full bg-blue-600 disabled:bg-gray-300 text-white font-bold py-3 rounded-lg mt-4"
          >
            Next
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
           <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Case Title</label>
            <input 
              type="text"
              placeholder="e.g. Unpaid Salary 2 Months"
              className="w-full border border-gray-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none"
              value={formData.title}
              onChange={e => setFormData({...formData, title: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Describe what happened</label>
            <textarea
              className="w-full border border-gray-300 rounded-lg p-3 h-40 focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="I haven't been paid since January. My boss keeps saying next week. Now they want me to resign..."
              value={formData.description}
              onChange={e => setFormData({...formData, description: e.target.value})}
            ></textarea>
            <p className="text-xs text-gray-500 mt-2">
              Include details like dates, amounts, and if you have a contract. Do not include sensitive names/passwords here.
            </p>
          </div>

          <button 
            onClick={handleDiagnose}
            disabled={loading || !formData.description || !formData.title}
            className="w-full bg-blue-600 disabled:bg-gray-300 text-white font-bold py-3 rounded-lg flex justify-center items-center"
          >
            {loading ? <Loader2 className="animate-spin mr-2" /> : 'Analyze My Case'}
          </button>
        </div>
      )}

      {step === 3 && aiResult && (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
          <div className={`p-4 rounded-lg border ${
            aiResult.risk === 'High' ? 'bg-red-50 border-red-200' : 
            aiResult.risk === 'Medium' ? 'bg-amber-50 border-amber-200' : 'bg-green-50 border-green-200'
          }`}>
            <h3 className="font-bold text-lg mb-2 flex items-center">
              Risk Level: {aiResult.risk}
            </h3>
            <p className="text-gray-700 text-sm mb-3">
              {aiResult.diagnosis}
            </p>
          </div>

          <div>
            <h4 className="font-bold text-gray-800 mb-3">Recommended Next Steps:</h4>
