import React, { useState, useRef, useEffect } from 'react';
import { Case, ChatMessage } from '../types';
import { chatWithAI } from '../services/geminiService';
import { Send, User, Bot, Loader2 } from 'lucide-react';

interface Props {
  currentCase: Case;
  onUpdate: (c: Case) => void;
}

const ChatInterface: React.FC<Props> = ({ currentCase, onUpdate }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  // Initialize with some history if empty? Or just use existing.
  const messages = currentCase.chatHistory || [];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    const newHistory = [...messages, userMsg];

    // Optimistic update
    onUpdate({
      ...currentCase,
      chatHistory: newHistory
    });
    setInput('');
    setLoading(true);

    try {
      const aiResponseText = await chatWithAI(messages, input, currentCase);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: aiResponseText,
        timestamp: Date.now()
      };
      onUpdate({
        ...currentCase,
        chatHistory: [...newHistory, aiMsg]
      });
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full h-[500px]">
      <div className="flex-grow overflow-y-auto space-y-4 pr-2" ref={scrollRef}>
        {messages.length === 0 && (
           <div className="text-center text-gray-400 mt-10">
             <Bot className="w-10 h-10 mx-auto mb-2 opacity-50" />
             <p>Ask me specifically about your {currentCase.issueTypes[0]} situation.</p>
           </div>
        )}
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex items-start max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${
                msg.role === 'user' ? 'bg-blue-600 ml-2' : 'bg-emerald-600 mr-2'
              }`}>
                {msg.role === 'user' ? <User className="w-5 h-5 text-white" /> : <Bot className="w-5 h-5 text-white" />}
              </div>
              <div className={`p-3 rounded-lg text-sm ${
                msg.role === 'user' 
                  ? 'bg-blue-600 text-white rounded-tr-none' 
                  : 'bg-white border border-gray-200 text-gray-800 rounded-tl-none shadow-sm'
              }`}>
                <div className="whitespace-pre-wrap">{msg.text}</div>
              </div>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
             <div className="flex items-center space-x-2 bg-gray-100 rounded-lg p-3">
               <Loader2 className="w-4 h-4 animate-spin text-gray-500" />
               <span className="text-xs text-gray-500">Analyzing...</span>
             </div>
          </div>
        )}
      </div>

      <div className="mt-4 border-t pt-4">
        <div className="flex space-x-2">
          <input
            type="text"
            className="flex-grow border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
            placeholder="Type your question..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            disabled={loading}
          />
          <button
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="bg-blue-600 text-white p-2 rounded-lg hover:bg-blue-700 disabled:bg-gray-300 transition"
          >
            <Send className="w-5 h-5" />
          </button>
        </div>
        <p className="text-xs text-gray-400 mt-2 text-center">AI responses are for guidance only. Not legal advice.</p>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState } from 'react';
import { Case, EvidenceItem } from '../types';
import { analyzeEvidence } from '../services/geminiService';
import { Upload, FileText, Tag, Trash2, Loader2, Plus } from 'lucide-react';

interface Props {
  currentCase: Case;
  onUpdate: (c: Case) => void;
}

const EvidenceAnalyzer: React.FC<Props> = ({ currentCase, onUpdate }) => {
  const [analyzing, setAnalyzing] = useState(false);

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setAnalyzing(true);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1]; // Remove data URL prefix

      try {
        const analysis = await analyzeEvidence(base64Data, file.type);

        const newEvidence: EvidenceItem = {
          id: Date.now().toString(),
          type: analysis.type as any || 'Other',
          description: file.name,
          summary: analysis.summary,
          tags: analysis.tags,
          dateAdded: new Date().toISOString()
        };

        onUpdate({
          ...currentCase,
          evidence: [newEvidence, ...currentCase.evidence]
        });
      } catch (error) {
        alert("Failed to analyze image. Please try again.");
      } finally {
        setAnalyzing(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const deleteEvidence = (id: string) => {
    onUpdate({
        ...currentCase,
        evidence: currentCase.evidence.filter(e => e.id !== id)
    })
  }

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm text-center">
        <input 
          type="file" 
          id="evidence-upload" 
          className="hidden" 
          accept="image/*"
          onChange={handleFileUpload}
          disabled={analyzing}
        />
        <label 
          htmlFor="evidence-upload"
          className="cursor-pointer flex flex-col items-center justify-center p-8 border-2 border-dashed border-blue-200 rounded-xl bg-blue-50 hover:bg-blue-100 transition"
        >
          {analyzing ? (
            <Loader2 className="w-10 h-10 text-blue-600 animate-spin mb-3" />
          ) : (
            <Upload className="w-10 h-10 text-blue-600 mb-3" />
          )}
          <span className="text-blue-900 font-bold">
            {analyzing ? "Analyzing Document..." : "Upload Screenshot or Document"}
          </span>
          <span className="text-blue-600 text-sm mt-1">Images only (PNG, JPG)</span>
        </label>
        <p className="text-xs text-gray-500 mt-4">
          The AI will read the text, detect dates/threats/admissions, and organize it for you.
        </p>
      </div>

      <div className="space-y-4">
        <h3 className="font-bold text-gray-700 flex items-center">
          <FileText className="w-5 h-5 mr-2" />
          Analyzed Evidence ({currentCase.evidence.length})
        </h3>

        {currentCase.evidence.length === 0 && (
            <p className="text-gray-400 italic text-sm">No evidence uploaded yet.</p>
        )}

        {currentCase.evidence.map((item) => (
          <div key={item.id} className="bg-white p-4 rounded-lg border border-gray-200 shadow-sm">
            <div className="flex justify-between items-start mb-2">
              <span className="font-bold text-gray-800 text-sm">{item.type}</span>
              <button onClick={() => deleteEvidence(item.id)} className="text-gray-400 hover:text-red-500">
                <Trash2 className="w-4 h-4" />
              </button>
            </div>
            <p className="text-sm text-gray-600 mb-3 bg-gray-50 p-2 rounded">
              {item.summary}
            </p>
            <div className="flex flex-wrap gap-2">
              {item.tags.map((tag, idx) => (
                <span key={idx} className="inline-flex items-center text-xs bg-indigo-50 text-indigo-700 px-2 py-1 rounded">
                  <Tag className="w-3 h-3 mr-1" /> {tag}
                </span>
              ))}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default EvidenceAnalyzer;

import React, { useState } from 'react';
import { Case, ReplySuggestion } from '../types';
import { generateReplies } from '../services/geminiService';
import { Mail, Copy, Check, Sparkles, Loader2 } from 'lucide-react';

interface Props {
  currentCase: Case;
}

const ReplyGenerator: React.FC<Props> = ({ currentCase }) => {
  const [incomingText, setIncomingText] = useState('');
  const [suggestions, setSuggestions] = useState<ReplySuggestion[]>([]);
  const [loading, setLoading] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);

  const handleGenerate = async () => {
    if (!incomingText) return;
    setLoading(true);
    try {
      const results = await generateReplies(incomingText, currentCase);
      setSuggestions(results);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopiedIndex(index);
    setTimeout(() => setCopiedIndex(null), 2000);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-4 rounded-lg border border-gray-200">
        <label className="block text-sm font-medium text-gray-700 mb-2">
          Paste the message you received (Email/WhatsApp):
        </label>
        <textarea
          className="w-full border border-gray-300 rounded-lg p-3 h-24 focus:ring-2 focus:ring-blue-500 outline-none text-sm"
          placeholder='"We cannot pay you this month. If you complain, we will cancel your visa."'
          value={incomingText}
          onChange={e => setIncomingText(e.target.value)}
        ></textarea>
        <button
          onClick={handleGenerate}
          disabled={loading || !incomingText}
          className="mt-3 w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-2 rounded-lg flex items-center justify-center transition"
        >
          {loading ? <Loader2 className="animate-spin w-4 h-4 mr-2" /> : <Sparkles className="w-4 h-4 mr-2" />}
          Generate Safe Replies
        </button>
      </div>

      <div className="space-y-4">
        {suggestions.map((suggestion, idx) => (
          <div key={idx} className="bg-white rounded-lg border border-gray-200 shadow-sm overflow-hidden">
             <div className={`px-4 py-2 border-b flex justify-between items-center ${
                 suggestion.tone === 'Soft' ? 'bg-blue-50 text-blue-800' :
                 suggestion.tone === 'Firm' ? 'bg-amber-50 text-amber-800' :
                 'bg-red-50 text-red-800'
             }`}>
                <span className="font-bold text-sm">{suggestion.tone} Tone</span>
                <span className="text-xs opacity-75">{suggestion.rationale}</span>
             </div>
             <div className="p-4">
                <div className="bg-gray-50 p-3 rounded text-sm text-gray-800 whitespace-pre-wrap mb-3 border border-gray-100">
                    {suggestion.body}
                </div>
                <button
                    onClick={() => copyToClipboard(suggestion.body, idx)}
                    className="flex items-center text-xs text-gray-500 hover:text-gray-900"
                >
                    {copiedIndex === idx ? <Check className="w-3 h-3 mr-1 text-green-500" /> : <Copy className="w-3 h-3 mr-1" />}
                    {copiedIndex === idx ? 'Copied' : 'Copy Text'}
                </button>
             </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default ReplyGenerator;

