import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ISSUE_TYPES } from '../constants';
import { diagnoseCase } from '../services/geminiService';
import { Case, EmployerType } from '../types';
import { Loader2, CheckCircle, XCircle } from 'lucide-react';

// Simple UUID polyfill if uuid lib not avail, but let's assume standard JS Math random for simple ID
const generateId = () => Math.random().toString(36).substr(2, 9);

interface Props {
  onSave: (c: Case) => void;
}

const NewCaseWizard: React.FC<Props> = ({ onSave }) => {
  const navigate = useNavigate();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    employerType: 'Unknown' as EmployerType,
    issues: [] as string[],
    description: '',
    title: ''
  });

  const [aiResult, setAiResult] = useState<{diagnosis: string, risk: 'Low' | 'Medium' | 'High', dos: string[], donts: string[]} | null>(null);

  const toggleIssue = (issue: string) => {
    setFormData(prev => ({
      ...prev,
      issues: prev.issues.includes(issue) 
        ? prev.issues.filter(i => i !== issue) 
        : [...prev.issues, issue]
    }));
  };

  const handleDiagnose = async () => {
    if (!formData.description) return;
    setLoading(true);
    try {
      const result = await diagnoseCase(formData.description, formData.issues, formData.employerType);
      setAiResult(result);
      setStep(3);
    } catch (error) {
      console.error(error);
      setStep(3);
    } finally {
      setLoading(false);
    }
  };

  const handleSave = () => {
    const newCase: Case = {
      id: generateId(),
      title: formData.title || `Case ${new Date().toLocaleDateString()}`,
      employerType: formData.employerType,
      issueTypes: formData.issues,
      description: formData.description,
      aiDiagnosis: aiResult?.diagnosis,
      riskLevel: aiResult?.risk,
      actionableDos: aiResult?.dos,
      actionableDonts: aiResult?.donts,
      stage: 'Pre-complaint',
      createdAt: new Date().toISOString(),
      evidence: [],
      chatHistory: []
    };
    onSave(newCase);
    navigate(`/case/${newCase.id}`);
  };

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-200 p-6">
      <div className="mb-6 flex justify-between items-center text-sm text-gray-400">
        <span className={step >= 1 ? "text-blue-600 font-bold" : ""}>1. Details</span>
        <span className="w-8 h-px bg-gray-200"></span>
        <span className={step >= 2 ? "text-blue-600 font-bold" : ""}>2. Situation</span>
        <span className="w-8 h-px bg-gray-200"></span>
        <span className={step >= 3 ? "text-blue-600 font-bold" : ""}>3. Review</span>
      </div>

      {step === 1 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Employer Type</label>
            <div className="grid grid-cols-3 gap-3">
              {['Mainland', 'Freezone', 'Unknown'].map((type) => (
                <button
                  key={type}
                  onClick={() => setFormData({...formData, employerType: type as EmployerType})}
                  className={`py-3 px-2 rounded-lg border text-sm font-medium transition ${
                    formData.employerType === type 
                      ? 'bg-blue-50 border-blue-500 text-blue-700' 
                      : 'bg-white border-gray-200 text-gray-600 hover:bg-gray-50'
                  }`}
                >
                  {type}
                </button>
              ))}
            </div>
            {formData.employerType === 'Freezone' && (
              <p className="text-xs text-gray-500 mt-2">e.g., DMCC, JAFZA, DSO, TECOM</p>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">What is the issue? (Select all that apply)</label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
              {ISSUE_TYPES.map(issue => (
                <button
                  key={issue}
                  onClick={() => toggleIssue(issue)}
                  className={`text-left px-3 py-2 rounded border text-sm transition ${
                    formData.issues.includes(issue)
                      ? 'bg-blue-50 border-blue-500 text-blue-700'
                      : 'border-gray-200 text-gray-600 hover:bg-gray-50'
                  }`}
                >
                  {issue}
                </button>
              ))}
            </div>
          </div>

          <button 
            disabled={formData.issues.length === 0}
            onClick={() => setStep(2)}
            className="w-full bg-blue-600 disabled:bg-gray-300 text-white font-bold py-3 rounded-lg mt-4"
          >
            Next
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
           <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Case Title</label>
            <input 
              type="text"
              placeholder="e.g. Unpaid Salary 2 Months"
              className="w-full border border-gray-300 rounded-lg p-3 focus:ring-2 focus:ring-blue-500 outline-none"
              value={formData.title}
              onChange={e => setFormData({...formData, title: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-medium text-gray-700 mb-2">Describe what happened</label>
            <textarea
              className="w-full border border-gray-300 rounded-lg p-3 h-40 focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="I haven't been paid since January. My boss keeps saying next week. Now they want me to resign..."
              value={formData.description}
              onChange={e => setFormData({...formData, description: e.target.value})}
            ></textarea>
            <p className="text-xs text-gray-500 mt-2">
              Include details like dates, amounts, and if you have a contract. Do not include sensitive names/passwords here.
            </p>
          </div>

          <button 
            onClick={handleDiagnose}
            disabled={loading || !formData.description || !formData.title}
            className="w-full bg-blue-600 disabled:bg-gray-300 text-white font-bold py-3 rounded-lg flex justify-center items-center"
          >
            {loading ? <Loader2 className="animate-spin mr-2" /> : 'Analyze My Case'}
          </button>
        </div>
      )}

      {step === 3 && aiResult && (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
          <div className={`p-4 rounded-lg border ${
            aiResult.risk === 'High' ? 'bg-red-50 border-red-200' : 
            aiResult.risk === 'Medium' ? 'bg-amber-50 border-amber-200' : 'bg-green-50 border-green-200'
          }`}>
            <h3 className="font-bold text-lg mb-2 flex items-center">
              Risk Level: {aiResult.risk}
            </h3>
            <p className="text-gray-700 text-sm mb-3">
              {aiResult.diagnosis}
            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="bg-green-50 p-4 rounded-lg border border-green-100">
              <h4 className="font-bold text-green-800 mb-3 flex items-center">
                <CheckCircle className="w-4 h-4 mr-2" /> Do This
              </h4>
              <ul className="space-y-2">
                {aiResult.dos?.map((rec, i) => (
                  <li key={i} className="text-sm text-gray-700 flex items-start">
                    <span className="mr-2">•</span> {rec}
                  </li>
                ))}
              </ul>
            </div>

            <div className="bg-red-50 p-4 rounded-lg border border-red-100">
              <h4 className="font-bold text-red-800 mb-3 flex items-center">
                <XCircle className="w-4 h-4 mr-2" /> Avoid This
              </h4>
              <ul className="space-y-2">
                {aiResult.donts?.map((rec, i) => (
                  <li key={i} className="text-sm text-gray-700 flex items-start">
                    <span className="mr-2">•</span> {rec}
                  </li>
                ))}
              </ul>
            </div>
          </div>

          <button 
            onClick={handleSave}
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 rounded-lg"
          >
            Create Case Dashboard
          </button>
        </div>
      )}
    </div>
  );
};

export default NewCaseWizard;

import React, { useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Case } from '../types';
import { MessageSquare, FileText, Send, PhoneCall, LayoutDashboard, ChevronLeft, CheckCircle, XCircle } from 'lucide-react';
import ChatInterface from './ChatInterface';
import EvidenceAnalyzer from './EvidenceAnalyzer';
import ReplyGenerator from './ReplyGenerator';
import CallCoach from './CallCoach';

interface Props {
  cases: Case[];
  onUpdate: (c: Case) => void;
}

type Tab = 'overview' | 'chat' | 'evidence' | 'reply' | 'coach';

const CaseDetail: React.FC<Props> = ({ cases, onUpdate }) => {
  const { id } = useParams<{ id: string }>();
  const [activeTab, setActiveTab] = useState<Tab>('overview');

  const currentCase = cases.find(c => c.id === id);

  if (!currentCase) {
    return <div>Case not found</div>;
  }

  const renderTabContent = () => {
    switch (activeTab) {
      case 'overview':
        return (
          <div className="space-y-6">
            <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm">
              <h2 className="text-xl font-bold mb-4">Case Summary</h2>
              <p className="text-gray-700 mb-4">{currentCase.description}</p>
              <div className="grid grid-cols-2 gap-4 text-sm">
                 <div>
                    <span className="block text-gray-500">Employer Type</span>
                    <span className="font-medium">{currentCase.employerType}</span>
                 </div>
                 <div>
                    <span className="block text-gray-500">Status</span>
                    <span className="font-medium">{currentCase.status}</span>
                 </div>
                 <div>
                    <span className="block text-gray-500">Risk Level</span>
                    <span className={`font-medium ${
                        currentCase.riskLevel === 'High' ? 'text-red-600' : 
                        currentCase.riskLevel === 'Medium' ? 'text-amber-600' : 'text-green-600'
                    }`}>
                        {currentCase.riskLevel}
                    </span>
                 </div>
                 <div>
                    <span className="block text-gray-500">Created</span>
                    <span className="font-medium">{new Date(currentCase.createdAt).toLocaleDateString()}</span>
                 </div>
              </div>
            </div>

            <div className="bg-blue-50 p-6 rounded-xl border border-blue-100">
               <h3 className="font-bold text-blue-900 mb-2">AI Diagnosis</h3>
               <p className="text-blue-800 text-sm mb-4">{currentCase.aiDiagnosis || "No diagnosis available."}</p>
            </div>

            {(currentCase.actionableDos || currentCase.actionableDonts) && (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {currentCase.actionableDos && (
                        <div className="bg-white p-5 rounded-xl border border-gray-200 shadow-sm">
                             <h4 className="font-bold text-green-700 mb-3 flex items-center">
                                <CheckCircle className="w-5 h-5 mr-2" /> Recommended Actions
                             </h4>
                             <ul className="space-y-2">
                                {currentCase.actionableDos.map((item, i) => (
                                    <li key={i} className="text-sm text-gray-700 flex items-start">
                                        <span className="mr-2 text-green-500">•</span> {item}
                                    </li>
                                ))}
                             </ul>
                        </div>
                    )}
                    {currentCase.actionableDonts && (
                        <div className="bg-white p-5 rounded-xl border border-gray-200 shadow-sm">
                             <h4 className="font-bold text-red-700 mb-3 flex items-center">
                                <XCircle className="w-5 h-5 mr-2" /> Critical Warnings
                             </h4>
                             <ul className="space-y-2">
                                {currentCase.actionableDonts.map((item, i) => (
                                    <li key={i} className="text-sm text-gray-700 flex items-start">
                                        <span className="mr-2 text-red-500">•</span> {item}
                                    </li>
                                ))}
                             </ul>
                        </div>
                    )}
                </div>
            )}
          </div>
        );
      case 'chat':
        return <ChatInterface currentCase={currentCase} onUpdate={onUpdate} />;
      case 'evidence':
        return <EvidenceAnalyzer currentCase={currentCase} onUpdate={onUpdate} />;
      case 'reply':
        return <ReplyGenerator currentCase={currentCase} />;
      case 'coach':
        return <CallCoach currentCase={currentCase} />;
      default:
        return null;
    }
  };

  const TabButton = ({ id, label, icon: Icon }: { id: Tab, label: string, icon: any }) => (
    <button
      onClick={() => setActiveTab(id)}
      className={`flex flex-col items-center py-2 px-1 text-xs md:text-sm md:flex-row md:space-x-2 md:px-4 md:py-3 border-b-2 transition ${
        activeTab === id 
        ? 'border-blue-600 text-blue-600' 
        : 'border-transparent text-gray-500 hover:text-gray-800'
      }`}
    >
      <Icon className="w-5 h-5 mb-1 md:mb-0" />
      <span>{label}</span>
    </button>
