import React, { createContext, useContext, useState, useEffect } from 'react';
import { AppLanguage } from '../types';
import { TRANSLATIONS } from '../translations';

interface LanguageContextType {
  language: AppLanguage;
  setLanguage: (lang: AppLanguage) => void;
  t: (key: string) => string;
  dir: 'ltr' | 'rtl';
}

const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export const LanguageProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguage] = useState<AppLanguage>('en');

  useEffect(() => {
    const storedLang = localStorage.getItem('ws_lang') as AppLanguage;
    if (storedLang && TRANSLATIONS[storedLang]) {
      setLanguage(storedLang);
    }
  }, []);

  const handleSetLanguage = (lang: AppLanguage) => {
    setLanguage(lang);
    localStorage.setItem('ws_lang', lang);
    // Update document direction
    const dir = (lang === 'ar' || lang === 'ur') ? 'rtl' : 'ltr';
    document.documentElement.dir = dir;
    document.documentElement.lang = lang;
  };

  const t = (key: string) => {
    return TRANSLATIONS[language]?.[key] || TRANSLATIONS['en'][key] || key;
  };

  const dir = (language === 'ar' || language === 'ur') ? 'rtl' : 'ltr';

  return (
    <LanguageContext.Provider value={{ language, setLanguage: handleSetLanguage, t, dir }}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
};

import { GoogleGenAI } from "@google/genai";
import { Case, ChatMessage, AppLanguage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// We inject the user's language preference into the system prompt.
const getSystemInstruction = (lang: AppLanguage) => `
You are WorkShield UAE, an expert AI assistant for UAE labour rights. 
User Language: ${lang}. 
CRITICAL: Respond ONLY in ${lang}. If the user speaks English, use English. If Arabic, use Arabic, etc.
Context: UAE Labour Law (Federal Decree-Law No. 33 of 2021) and Freezone regulations.
Tone: Simple, clear, calming, professional. Avoid complex legal jargon. Use bullet points.
Safety: You are NOT a lawyer. Never guarantee results. If unsure, say "Generally..." or "Please check with MOHRE".
`;

export const diagnoseCase = async (description: string, issues: string[], employerType: string, lang: AppLanguage): Promise<{ diagnosis: string; risk: 'Low' | 'Medium' | 'High'; dos: string[]; donts: string[] }> => {
  const prompt = `
    Analyze this UAE labour case in ${lang}.
    Employer Type: ${employerType}
    Issues: ${issues.join(', ')}
    User Description: "${description}"

    Provide a JSON response with:
    1. "diagnosis": A 2-sentence summary of the legal situation (in ${lang}).
    2. "risk": "Low", "Medium", or "High" (High = threats of bans, absconding, large financial loss).
    3. "dos": An array of 3 specific actions the user SHOULD take immediately (in ${lang}).
    4. "donts": An array of 3 specific actions the user must AVOID (in ${lang}).
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest',
      contents: prompt,
      config: {
        systemInstruction: getSystemInstruction(lang),
        responseMimeType: 'application/json'
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");
    return JSON.parse(text);
  } catch (error) {
    console.error("Diagnosis Error:", error);
    return {
      diagnosis: "Could not analyze at this time. Please try again.",
      risk: "Medium",
      dos: ["Consult a legal professional"],
      donts: ["Sign documents without reading"]
    };
  }
};

export const chatWithAI = async (history: ChatMessage[], newMessage: string, caseContext: Case, lang: AppLanguage): Promise<{ text: string; isFlagged: boolean }> => {
  const contextStr = `
    Current Case Context:
    - Type: ${caseContext.employerType}
    - Issues: ${caseContext.issueTypes.join(', ')}
    - Summary: ${caseContext.description}
    - Previous Advice (DO): ${caseContext.actionableDos?.join(', ')}
    - Previous Advice (DON'T): ${caseContext.actionableDonts?.join(', ')}
  `;

  const prompt = `
    ${contextStr}
    User Query: ${newMessage}

    Answer specifically regarding UAE labour rules in ${lang}.
    If you are unsure about a specific regulation, admit it politely and suggest contacting MOHRE.
    If the user asks something new or complex not covered by standard rules, add a [FLAG] tag at the end of your response hidden from the user logic (I will parse it).
  `;

  try {
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-latest',
        contents: prompt,
        config: { systemInstruction: getSystemInstruction(lang) }
    });

    let text = response.text || "I apologize, I couldn't generate a response.";

    // Simple "Learning" mechanism: Detect uncertainty to flag for review
    const uncertaintyKeywords = ["unsure", "not clear", "consult a lawyer", "don't know", "can't say", "unclear"];
    const isFlagged = uncertaintyKeywords.some(keyword => text.toLowerCase().includes(keyword));

    return { text, isFlagged };
  } catch (error) {
    console.error("Chat Error", error);
    return { text: "Sorry, I am having trouble connecting to the server.", isFlagged: false };
  }
};

export const analyzeEvidence = async (base64Data: string, mimeType: string, lang: AppLanguage): Promise<{ type: string; summary: string; tags: string[] }> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-latest',
      contents: {
        parts: [
          { inlineData: { mimeType, data: base64Data } },
          { text: `Analyze this image for a UAE labour dispute. Respond in ${lang}. Extract Type, Summarize key content (dates, amounts, threats, admissions), and suggest tags.` }
        ]
      },
      config: {
        systemInstruction: getSystemInstruction(lang),
        responseMimeType: 'application/json',
        responseSchema: {
            type: "OBJECT",
            properties: {
                type: { type: "STRING" },
                summary: { type: "STRING" },
                tags: { type: "ARRAY", items: { type: "STRING" } }
            }
        }
      }
    });
    const text = response.text;
    if(!text) throw new Error("No text");
    return JSON.parse(text);
  } catch (e) {
    console.error(e);
    return { type: "Unknown", summary: "Failed to analyze", tags: [] };
  }
};

export const generateReplies = async (incomingText: string, caseContext: Case, lang: AppLanguage): Promise<any[]> => {
    const prompt = `
    The user received this message: "${incomingText}"
    Context: ${caseContext.description}
    Language: ${lang}

    Generate 3 reply options in JSON format in ${lang}:
    1. Soft/Neutral
    2. Firm (citing regulations generally)
    3. Assertive (warning of MOHRE escalation)

    JSON Structure:
    [
        { "tone": "Soft", "subject": "...", "body": "...", "rationale": "..." },
        ...
    ]
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-2.5-flash-latest',
            contents: prompt,
            config: {
                systemInstruction: getSystemInstruction(lang),
                responseMimeType: 'application/json'
            }
        });
        return JSON.parse(response.text || "[]");
    } catch (e) {
        console.error(e);
        return [];
    }
}

export const generateCallPrep = async (caseContext: Case, meetingType: string, lang: AppLanguage): Promise<string> => {
     const prompt = `
    Meeting: "${meetingType}"
    Case: ${caseContext.description}
    Language: ${lang}

    Provide a coaching script in Markdown in ${lang}.
    `;

    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-latest',
        contents: prompt,
        config: { systemInstruction: getSystemInstruction(lang) }
    });
    return response.text || "Could not generate prep.";
}

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import CaseList from './components/CaseList';
import NewCaseWizard from './components/NewCaseWizard';
import CaseDetail from './components/CaseDetail';
import KnowledgeBase from './components/KnowledgeBase';
import DisclaimerModal from './components/DisclaimerModal';
import Settings from './components/Settings';
import { Case } from './types';
import { LanguageProvider } from './contexts/LanguageContext';

const AppContent: React.FC = () => {
  const [cases, setCases] = useState<Case[]>([]);
  const [acceptedDisclaimer, setAcceptedDisclaimer] = useState(false);

  // Load from local storage on mount
  useEffect(() => {
    const storedCases = localStorage.getItem('ws_cases');
    if (storedCases) {
      setCases(JSON.parse(storedCases));
    }
    const storedDisclaimer = localStorage.getItem('ws_disclaimer');
    if (storedDisclaimer === 'true') {
      setAcceptedDisclaimer(true);
    }
  }, []);

  // Save to local storage on change
  useEffect(() => {
    localStorage.setItem('ws_cases', JSON.stringify(cases));
  }, [cases]);

  const handleDisclaimerAccept = () => {
    setAcceptedDisclaimer(true);
    localStorage.setItem('ws_disclaimer', 'true');
  };

  const addCase = (newCase: Case) => {
    setCases([newCase, ...cases]);
  };

  const updateCase = (updatedCase: Case) => {
    setCases(cases.map(c => c.id === updatedCase.id ? updatedCase : c));
  };

  const deleteCase = (id: string) => {
    setCases(cases.filter(c => c.id !== id));
  };

  return (
    <HashRouter>
      {!acceptedDisclaimer && <DisclaimerModal onAccept={handleDisclaimerAccept} />}
      <Layout>
        <Routes>
          <Route path="/" element={<CaseList cases={cases} onDelete={deleteCase} />} />
          <Route path="/new" element={<NewCaseWizard onSave={addCase} />} />
          <Route path="/case/:id/*" element={<CaseDetail cases={cases} onUpdate={updateCase} />} />
          <Route path="/knowledge" element={<KnowledgeBase />} />
          <Route path="/settings" element={<Settings />} />
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

const App: React.FC = () => {
  return (
    <LanguageProvider>
      <AppContent />
    </LanguageProvider>
  );
};

export default App;

