import React, { useState, useRef, useEffect } from 'react';
import { Case, ChatMessage } from '../types';
import { chatWithAI } from '../services/geminiService';
import { Send, User, Bot, Loader2, Flag } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface Props {
  currentCase: Case;
  onUpdate: (c: Case) => void;
}

const ChatInterface: React.FC<Props> = ({ currentCase, onUpdate }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const { language, t, dir } = useLanguage();

  const messages = currentCase.chatHistory || [];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    const newHistory = [...messages, userMsg];

    // Optimistic update
    onUpdate({
      ...currentCase,
      chatHistory: newHistory
    });
    setInput('');
    setLoading(true);

    try {
      const result = await chatWithAI(messages, input, currentCase, language);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: result.text,
        timestamp: Date.now(),
        isFlaggedForReview: result.isFlagged
      };
      onUpdate({
        ...currentCase,
        chatHistory: [...newHistory, aiMsg]
      });
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-full h-[500px]" dir={dir}>
      <div className="flex-grow overflow-y-auto space-y-4 pr-2" ref={scrollRef}>
        {messages.length === 0 && (
           <div className="text-center text-gray-400 mt-10">
             <Bot className="w-10 h-10 mx-auto mb-2 opacity-50" />
             <p>Ask me specifically about your {currentCase.issueTypes[0]} situation.</p>
           </div>
        )}
        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex items-start max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 ${
                msg.role === 'user' ? 'bg-blue-600 mx-2' : 'bg-emerald-600 mx-2'
              }`}>
                {msg.role === 'user' ? <User className="w-5 h-5 text-white" /> : <Bot className="w-5 h-5 text-white" />}
              </div>
              <div className="flex flex-col">
                <div className={`p-3 rounded-lg text-sm ${
                  msg.role === 'user' 
                    ? 'bg-blue-600 text-white rounded-tr-none rtl:rounded-tl-none rtl:rounded-tr-lg' 
                    : 'bg-white border border-gray-200 text-gray-800 rounded-tl-none rtl:rounded-tr-none rtl:rounded-tl-lg shadow-sm'
                }`}>
                  <div className="whitespace-pre-wrap">{msg.text}</div>
                </div>
                {msg.role === 'model' && (
                  <div className="mt-1">
                      <p className="text-[10px] text-gray-400 px-1">{t('inline_disclaimer')}</p>
                      {msg.isFlaggedForReview && (
                        <div className="flex items-center text-[10px] text-amber-600 mt-1 px-1">
                          <Flag className="w-3 h-3 mr-1" /> Flagged for review (Uncertainty detected)
                        </div>
                      )}
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start">
             <div className="flex items-center space-x-2 bg-gray-100 rounded-lg p-3">
               <Loader2 className="w-4 h-4 animate-spin text-gray-500" />
               <span className="text-xs text-gray-500">Analyzing...</span>
             </div>
          </div>
        )}
      </div>

      <div className="mt-4 border-t pt-4">
        <div className="flex space-x-2">
          <input
            type="text"
            className="flex-grow border border-gray-300 rounded-lg px-4 py-2 focus:ring-2 focus:ring-blue-500 outline-none"
            placeholder="Type your question..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            disabled={loading}
          />
          <button
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="bg-blue-600 text-white p-2 rounded-lg hover:bg-blue-700 disabled:bg-gray-300 transition"
          >
            <Send className="w-5 h-5 rtl:rotate-180" />
          </button>
        </div>
        <p className="text-xs text-gray-400 mt-2 text-center">{t('inline_disclaimer')}</p>
      </div>
    </div>
  );
};

export default ChatInterface;

import React, { useState } from 'react';
import { Case, ReplySuggestion } from '../types';
import { generateReplies } from '../services/geminiService';
import { Copy, Check, Sparkles, Loader2 } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface Props {
  currentCase: Case;
}

const ReplyGenerator: React.FC<Props> = ({ currentCase }) => {
  const [incomingText, setIncomingText] = useState('');
  const [suggestions, setSuggestions] = useState<ReplySuggestion[]>([]);
  const [loading, setLoading] = useState(false);
  const [copiedIndex, setCopiedIndex] = useState<number | null>(null);
  const { language, t } = useLanguage();

  const handleGenerate = async () => {
    if (!incomingText) return;
    setLoading(true);
    try {
      const results = await generateReplies(incomingText, currentCase, language);
      setSuggestions(results);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const copyToClipboard = (text: string, index: number) => {
    navigator.clipboard.writeText(text);
    setCopiedIndex(index);
    setTimeout(() => setCopiedIndex(null), 2000);
  };

  return (
    <div className="space-y-6">
      <div className="bg-white p-4 rounded-lg border border-gray-200">
        <label className="block text-sm font-medium text-gray-700 mb-2">
          Paste the message you received (Email/WhatsApp):
        </label>
        <textarea
          className="w-full border border-gray-300 rounded-lg p-3 h-24 focus:ring-2 focus:ring-blue-500 outline-none text-sm"
          placeholder="..."
          value={incomingText}
          onChange={e => setIncomingText(e.target.value)}
        ></textarea>
        <button
          onClick={handleGenerate}
          disabled={loading || !incomingText}
          className="mt-3 w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-2 rounded-lg flex items-center justify-center transition"
        >
          {loading ? <Loader2 className="animate-spin w-4 h-4 mr-2" /> : <Sparkles className="w-4 h-4 mr-2" />}
          Generate Safe Replies
        </button>
      </div>

      <div className="space-y-4">
        {suggestions.map((suggestion, idx) => (
          <div key={idx} className="bg-white rounded-lg border border-gray-200 shadow-sm overflow-hidden">
             <div className={`px-4 py-2 border-b flex justify-between items-center ${
                 suggestion.tone === 'Soft' ? 'bg-blue-50 text-blue-800' :
                 suggestion.tone === 'Firm' ? 'bg-amber-50 text-amber-800' :
                 'bg-red-50 text-red-800'
             }`}>
                <span className="font-bold text-sm">{suggestion.tone} Tone</span>
                <span className="text-xs opacity-75">{suggestion.rationale}</span>
             </div>
             <div className="p-4">
                <div className="bg-gray-50 p-3 rounded text-sm text-gray-800 whitespace-pre-wrap mb-3 border border-gray-100">
                    {suggestion.body}
                </div>
                <div className="flex justify-between items-center">
                    <button
                        onClick={() => copyToClipboard(suggestion.body, idx)}
                        className="flex items-center text-xs text-gray-500 hover:text-gray-900"
                    >
                        {copiedIndex === idx ? <Check className="w-3 h-3 mr-1 text-green-500" /> : <Copy className="w-3 h-3 mr-1" />}
                        {copiedIndex === idx ? 'Copied' : 'Copy Text'}
                    </button>
                    <span className="text-[10px] text-gray-400 italic">{t('inline_disclaimer')}</span>
                </div>
             </div>
          </div>
        ))}
      </div>
    </div>
  );
};

