import React, { useState } from 'react';
import { Case, EvidenceItem } from '../types';
import { analyzeEvidence } from '../services/geminiService';
import { Upload, FileText, Tag, Trash2, Loader2 } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface Props {
  currentCase: Case;
  onUpdate: (c: Case) => void;
}

const EvidenceAnalyzer: React.FC<Props> = ({ currentCase, onUpdate }) => {
  const [analyzing, setAnalyzing] = useState(false);
  const { language, t } = useLanguage();

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setAnalyzing(true);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1]; // Remove data URL prefix

      try {
        const analysis = await analyzeEvidence(base64Data, file.type, language);

        const newEvidence: EvidenceItem = {
          id: Date.now().toString(),
          type: analysis.type as any || 'Other',
          description: file.name,
          summary: analysis.summary,
          tags: analysis.tags,
          dateAdded: new Date().toISOString()
        };

        onUpdate({
          ...currentCase,
          evidence: [newEvidence, ...currentCase.evidence]
        });
      } catch (error) {
        alert("Failed to analyze image. Please try again.");
      } finally {
        setAnalyzing(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const deleteEvidence = (id: string) => {
    onUpdate({
        ...currentCase,
        evidence: currentCase.evidence.filter(e => e.id !== id)
    })
  }

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-xl border border-gray-200 shadow-sm text-center">
        <input 
          type="file" 
          id="evidence-upload" 
          className="hidden" 
          accept="image/*"
          onChange={handleFileUpload}
          disabled={analyzing}
        />
        <label 
          htmlFor="evidence-upload"
          className="cursor-pointer flex flex-col items-center justify-center p-8 border-2 border-dashed border-blue-200 rounded-xl bg-blue-50 hover:bg-blue-100 transition"
        >
          {analyzing ? (
            <Loader2 className="w-10 h-10 text-blue-600 animate-spin mb-3" />
          ) : (
            <Upload className="w-10 h-10 text-blue-600 mb-3" />
          )}
          <span className="text-blue-900 font-bold">
            {analyzing ? "Analyzing Document..." : "Upload Screenshot or Document"}
          </span>
          <span className="text-blue-600 text-sm mt-1">Images only (PNG, JPG)</span>
        </label>
        <p className="text-xs text-gray-500 mt-4">
          The AI will read the text, detect dates/threats/admissions, and organize it for you.
        </p>
      </div>

      <div className="space-y-4">
        <h3 className="font-bold text-gray-700 flex items-center">
          <FileText className="w-5 h-5 mr-2" />
          Analyzed Evidence ({currentCase.evidence.length})
        </h3>

        {currentCase.evidence.length === 0 && (
            <p className="text-gray-400 italic text-sm">No evidence uploaded yet.</p>
        )}

        {currentCase.evidence.map((item) => (
          <div key={item.id} className="bg-white p-4 rounded-lg border border-gray-200 shadow-sm">
            <div className="flex justify-between items-start mb-2">
              <span className="font-bold text-gray-800 text-sm">{item.type}</span>
              <button onClick={() => deleteEvidence(item.id)} className="text-gray-400 hover:text-red-500">
                <Trash2 className="w-4 h-4" />
              </button>
            </div>
            <p className="text-sm text-gray-600 mb-3 bg-gray-50 p-2 rounded">
              {item.summary}
            </p>
            <div className="flex flex-wrap gap-2">
              {item.tags.map((tag, idx) => (
                <span key={idx} className="inline-flex items-center text-xs bg-indigo-50 text-indigo-700 px-2 py-1 rounded">
                  <Tag className="w-3 h-3 mr-1" /> {tag}
                </span>
              ))}
            </div>
          </div>
        ))}
      </div>
      <p className="text-[10px] text-center text-gray-400 mt-2">{t('inline_disclaimer')}</p>
    </div>
  );
};

