import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ISSUE_TYPES, FREEZONES } from '../constants';
import { diagnoseCase } from '../services/geminiService';
import { Case, EmployerType } from '../types';
import { Loader2, CheckCircle, XCircle, ChevronRight, AlertCircle, Building2, HelpCircle } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

const generateId = () => Math.random().toString(36).substr(2, 9);

interface Props {
  onSave: (c: Case) => void;
}

const NewCaseWizard: React.FC<Props> = ({ onSave }) => {
  const navigate = useNavigate();
  const { t, language } = useLanguage();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    employerType: 'Unknown' as EmployerType,
    freezone: '',
    issues: [] as string[],
    description: '',
    title: ''
  });

  const [aiResult, setAiResult] = useState<{diagnosis: string, risk: 'Low' | 'Medium' | 'High', dos: string[], donts: string[]} | null>(null);

  const toggleIssue = (issue: string) => {
    setFormData(prev => ({
      ...prev,
      issues: prev.issues.includes(issue) 
        ? prev.issues.filter(i => i !== issue) 
        : [...prev.issues, issue]
    }));
  };

  const handleDiagnose = async () => {
    if (!formData.description) return;
    setLoading(true);
    try {
      const result = await diagnoseCase(formData.description, formData.issues, formData.employerType, formData.freezone, language);
      setAiResult(result);
      setStep(3);
    } catch (error) {
      console.error(error);
      setStep(3);
    } finally {
      setLoading(false);
    }
  };

  const handleSave = () => {
    const newCase: Case = {
      id: generateId(),
      title: formData.title || `Case ${new Date().toLocaleDateString()}`,
      employerType: formData.employerType,
      freezone: formData.employerType === 'Freezone' ? formData.freezone : undefined,
      issueTypes: formData.issues,
      description: formData.description,
      aiDiagnosis: aiResult?.diagnosis,
      riskLevel: aiResult?.risk,
      actionableDos: aiResult?.dos,
      actionableDonts: aiResult?.donts,
      stage: 'Pre-complaint',
      createdAt: new Date().toISOString(),
      evidence: [],
      chatHistory: []
    };
    onSave(newCase);
    navigate(`/case/${newCase.id}`);
  };

  return (
    <div className="bg-white rounded-2xl shadow-sm border border-slate-200 p-6 md:p-8 transition-all duration-300">
      {/* Progress */}
      <div className="mb-8">
        <div className="flex justify-between items-center text-xs font-bold uppercase tracking-widest text-slate-400 mb-3">
            <span className={step >= 1 ? "text-slate-900" : ""}>1. Profile</span>
            <span className={step >= 2 ? "text-slate-900" : ""}>2. Situation</span>
            <span className={step >= 3 ? "text-slate-900" : ""}>3. Analysis</span>
        </div>
        <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden">
            <div 
                className="h-full bg-slate-900 transition-all duration-500 ease-out"
                style={{ width: `${(step / 3) * 100}%` }}
            />
        </div>
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-in fade-in slide-in-from-right-4 duration-300">
          <div>
            <label className="block text-sm font-bold text-slate-800 mb-4">{t('label_employer_type')}</label>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
              {[
                  { id: 'Mainland', icon: Building2, desc: 'MOHRE Regulated' },
                  { id: 'Freezone', icon: Building2, desc: 'DMCC, JAFZA, etc.' },
                  { id: 'Unknown', icon: HelpCircle, desc: 'I am not sure' }
              ].map((type) => (
                <button
                  key={type.id}
                  onClick={() => setFormData({...formData, employerType: type.id as EmployerType, freezone: ''})}
                  className={`py-4 px-4 rounded-xl border flex flex-col items-center justify-center text-center transition-all duration-200 ${
                    formData.employerType === type.id 
                      ? 'bg-slate-900 border-slate-900 text-white shadow-md scale-[1.02]' 
                      : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50 hover:border-slate-300'
                  }`}
                >
                  <type.icon className={`w-6 h-6 mb-2 ${formData.employerType === type.id ? 'text-indigo-300' : 'text-slate-400'}`} />
                  <span className="font-bold text-sm">{type.id}</span>
                  <span className={`text-[10px] mt-1 ${formData.employerType === type.id ? 'text-slate-300' : 'text-slate-400'}`}>{type.desc}</span>
                </button>
              ))}
            </div>

            {/* Freezone Selector */}
            {formData.employerType === 'Freezone' && (
                <div className="mt-4 animate-in fade-in slide-in-from-top-2">
                    <label className="block text-xs font-bold text-slate-600 mb-2 uppercase tracking-wide">Which Freezone Authority?</label>
                    <select
                        value={formData.freezone}
                        onChange={(e) => setFormData({...formData, freezone: e.target.value})}
                        className="w-full p-4 rounded-xl border border-indigo-200 bg-indigo-50/50 text-slate-800 focus:ring-2 focus:ring-slate-900 outline-none transition font-medium"
                    >
                        <option value="">Select specific Freezone...</option>
                        {FREEZONES.map(fz => <option key={fz} value={fz}>{fz}</option>)}
                    </select>
                    <p className="text-[10px] text-slate-500 mt-2 ml-1">
                        Selecting the correct authority helps us give you accurate filing instructions (e.g., DMCC portal vs. MOHRE).
                    </p>
                </div>
            )}
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-800 mb-4">{t('label_issues')}</label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {ISSUE_TYPES.map(issue => (
                <button
                  key={issue}
                  onClick={() => toggleIssue(issue)}
                  className={`relative text-left rtl:text-right px-4 py-3 rounded-xl border text-sm font-medium transition-all duration-200 ${
                    formData.issues.includes(issue)
                      ? 'bg-indigo-50 border-indigo-500 text-indigo-900 shadow-sm'
                      : 'border-slate-200 text-slate-600 hover:bg-slate-50'
                  }`}
                >
                  {issue}
                  {formData.issues.includes(issue) && (
                      <div className="absolute top-0 right-0 p-1">
                          <div className="w-2 h-2 bg-indigo-500 rounded-full"></div>
                      </div>
                  )}
                </button>
              ))}
            </div>
          </div>

          <button 
            disabled={formData.issues.length === 0 || (formData.employerType === 'Freezone' && !formData.freezone)}
            onClick={() => setStep(2)}
            className="w-full bg-slate-900 disabled:bg-slate-200 disabled:text-slate-400 text-white font-bold py-4 rounded-xl mt-4 hover:bg-slate-800 transition-all shadow-lg flex justify-center items-center"
          >
            Next Step <ChevronRight className="w-5 h-5 ml-2 rtl:rotate-180" />
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
           <div>
            <label className="block text-sm font-bold text-slate-800 mb-2">Give your case a title</label>
            <input 
              type="text"
              placeholder="e.g. Unpaid Salary 2 Months"
              className="w-full border border-slate-300 rounded-xl p-4 focus:ring-2 focus:ring-slate-900 focus:border-transparent outline-none transition shadow-sm"
              value={formData.title}
              onChange={e => setFormData({...formData, title: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-800 mb-2">{t('label_desc')}</label>
            <textarea
              className="w-full border border-slate-300 rounded-xl p-4 h-48 focus:ring-2 focus:ring-slate-900 focus:border-transparent outline-none transition resize-none shadow-sm"
              placeholder="Start typing..."
              value={formData.description}
              onChange={e => setFormData({...formData, description: e.target.value})}
            ></textarea>
            <div className="flex items-center mt-3 text-xs text-slate-500 bg-slate-50 p-3 rounded-lg border border-slate-100">
                <AlertCircle className="w-4 h-4 mr-2 text-indigo-500 flex-shrink-0" />
                <span>Tip: Include dates, amounts, and whether you have a written contract.</span>
            </div>
          </div>

          <button 
            onClick={handleDiagnose}
            disabled={loading || !formData.description || !formData.title}
            className="w-full bg-slate-900 disabled:bg-slate-300 text-white font-bold py-4 rounded-xl flex justify-center items-center shadow-lg hover:bg-slate-800 transition"
          >
            {loading ? <Loader2 className="animate-spin mr-2" /> : t('btn_analyze')}
          </button>
        </div>
      )}

      {step === 3 && aiResult && (
        <div className="space-y-6 animate-in fade-in slide-in-from-right-4 duration-300">
          <div className={`p-6 rounded-2xl border-l-4 shadow-sm ${
            aiResult.risk === 'High' ? 'bg-red-50 border-red-500' : 
            aiResult.risk === 'Medium' ? 'bg-amber-50 border-amber-500' : 'bg-emerald-50 border-emerald-500'
          }`}>
            <h3 className={`font-bold text-lg mb-2 flex items-center ${
                 aiResult.risk === 'High' ? 'text-red-900' : 
                 aiResult.risk === 'Medium' ? 'text-amber-900' : 'text-emerald-900'
            }`}>
              {t('app_name')} Assessment: {aiResult.risk}
            </h3>
            <p className="text-slate-800 text-sm leading-relaxed">
              {aiResult.diagnosis}
            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="bg-white p-5 rounded-2xl border border-emerald-100 shadow-sm">
              <h4 className="font-bold text-emerald-700 mb-4 flex items-center">
                <CheckCircle className="w-5 h-5 mr-2" /> Immediate Actions
              </h4>
              <ul className="space-y-3">
                {aiResult.dos?.map((rec, i) => (
                  <li key={i} className="text-sm text-slate-700 flex items-start">
                    <span className="mr-2 text-emerald-500 font-bold">•</span> {rec}
                  </li>
                ))}
              </ul>
            </div>

            <div className="bg-white p-5 rounded-2xl border border-red-100 shadow-sm">
              <h4 className="font-bold text-red-700 mb-4 flex items-center">
                <XCircle className="w-5 h-5 mr-2" /> Avoid This
              </h4>
              <ul className="space-y-3">
                {aiResult.donts?.map((rec, i) => (
                  <li key={i} className="text-sm text-slate-700 flex items-start">
                    <span className="mr-2 text-red-500 font-bold">•</span> {rec}
                  </li>
                ))}
              </ul>
            </div>
          </div>

          <button 
            onClick={handleSave}
            className="w-full bg-slate-900 hover:bg-slate-800 text-white font-bold py-4 rounded-xl shadow-lg transition transform active:scale-95"
          >
            {t('btn_save_dashboard')}
          </button>
        </div>
      )}
    </div>
  );
};

