import React, { useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Case } from '../types';
import { MessageSquare, FileText, Send, PhoneCall, LayoutDashboard, ChevronLeft, CheckCircle, XCircle } from 'lucide-react';
import ChatInterface from './ChatInterface';
import EvidenceAnalyzer from './EvidenceAnalyzer';
import ReplyGenerator from './ReplyGenerator';
import CallCoach from './CallCoach';

interface Props {
  cases: Case[];
  onUpdate: (c: Case) => void;
}

type Tab = 'overview' | 'chat' | 'evidence' | 'reply' | 'coach';

const CaseDetail: React.FC<Props> = ({ cases, onUpdate }) => {
  const { id } = useParams<{ id: string }>();
  const [activeTab, setActiveTab] = useState<Tab>('overview');

  const currentCase = cases.find(c => c.id === id);

  if (!currentCase) {
    return <div className="p-8 text-center text-slate-500">Case not found</div>;
  }

  const renderTabContent = () => {
    switch (activeTab) {
      case 'overview':
        return (
          <div className="space-y-6 animate-in fade-in slide-in-from-bottom-2 duration-300">
            {/* Summary Card */}
            <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
              <div className="flex justify-between items-start mb-4">
                 <h2 className="text-lg font-bold text-slate-900">Case Dashboard</h2>
                 <span className="text-[10px] bg-slate-100 text-slate-500 px-2 py-1 rounded border border-slate-200">ID: {currentCase.id.substring(0,6)}</span>
              </div>

              <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 mb-6">
                <p className="text-slate-700 leading-relaxed text-sm">
                    {currentCase.description}
                </p>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 text-sm border-t border-slate-100 pt-4">
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Type</span>
                    <span className="font-bold text-slate-800" title={currentCase.freezone}>
                        {currentCase.employerType === 'Freezone' && currentCase.freezone 
                            ? currentCase.freezone.split('(')[0].trim() 
                            : currentCase.employerType}
                    </span>
                 </div>
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Status</span>
                    <span className="font-bold text-slate-800">{currentCase.stage}</span>
                 </div>
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Risk</span>
                    <span className={`font-bold px-2 py-0.5 rounded-md inline-block w-fit ${
                        currentCase.riskLevel === 'High' ? 'bg-red-50 text-red-600' : 
                        currentCase.riskLevel === 'Medium' ? 'bg-amber-50 text-amber-600' : 'bg-emerald-50 text-emerald-600'
                    }`}>
                        {currentCase.riskLevel}
                    </span>
                 </div>
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Date</span>
                    <span className="font-bold text-slate-800">{new Date(currentCase.createdAt).toLocaleDateString()}</span>
                 </div>
              </div>
            </div>

            {/* Actionable Advice */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               {currentCase.actionableDos && currentCase.actionableDos.length > 0 && (
                   <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                       <h3 className="font-bold text-emerald-700 mb-4 flex items-center text-sm uppercase tracking-wide">
                           <CheckCircle className="w-5 h-5 mr-2" /> Recommended Actions
                       </h3>
                       <ul className="space-y-3">
                           {currentCase.actionableDos.map((item, i) => (
                               <li key={i} className="text-sm text-slate-700 flex items-start">
                                   <span className="mr-2 text-emerald-500 font-bold">•</span> {item}
                               </li>
                           ))}
                       </ul>
                   </div>
               )}

               {currentCase.actionableDonts && currentCase.actionableDonts.length > 0 && (
                   <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
                       <h3 className="font-bold text-red-700 mb-4 flex items-center text-sm uppercase tracking-wide">
                           <XCircle className="w-5 h-5 mr-2" /> What To Avoid
                       </h3>
                       <ul className="space-y-3">
                           {currentCase.actionableDonts.map((item, i) => (
                               <li key={i} className="text-sm text-slate-700 flex items-start">
                                   <span className="mr-2 text-red-500 font-bold">•</span> {item}
                               </li>
                           ))}
                       </ul>
                   </div>
               )}
            </div>
          </div>
        );
      case 'chat':
        return <ChatInterface currentCase={currentCase} onUpdate={onUpdate} />;
      case 'evidence':
        return <EvidenceAnalyzer currentCase={currentCase} onUpdate={onUpdate} />;
      case 'reply':
        return <ReplyGenerator currentCase={currentCase} />;
      case 'coach':
        return <CallCoach currentCase={currentCase} />;
      default:
        return null;
    }
  };

  const tabs: { id: Tab; label: string; icon: any }[] = [
    { id: 'overview', label: 'Overview', icon: LayoutDashboard },
    { id: 'chat', label: 'AI Assistant', icon: MessageSquare },
    { id: 'evidence', label: 'Evidence', icon: FileText },
    { id: 'reply', label: 'Reply Gen', icon: Send },
    { id: 'coach', label: 'Call Prep', icon: PhoneCall },
  ];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center space-x-4 mb-2">
        <Link to="/" className="p-2 rounded-full bg-white border border-slate-200 text-slate-500 hover:text-slate-900 hover:bg-slate-50 transition shadow-sm">
          <ChevronLeft className="w-5 h-5 rtl:rotate-180" />
        </Link>
        <div>
           <h1 className="text-2xl font-bold text-slate-900 tracking-tight">{currentCase.title}</h1>
           <div className="flex space-x-2 text-xs text-slate-500 font-medium">
              <span>{currentCase.issueTypes.join(', ')}</span>
           </div>
        </div>
      </div>

      {/* Tabs Navigation */}
      <div className="flex overflow-x-auto pb-2 space-x-2 no-scrollbar rtl:space-x-reverse border-b border-slate-200">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex items-center px-4 py-3 rounded-t-xl text-sm font-bold whitespace-nowrap transition-all duration-200 border-b-2 ${
              activeTab === tab.id
                ? 'border-slate-900 text-slate-900 bg-slate-50'
                : 'border-transparent text-slate-500 hover:text-slate-700 hover:bg-slate-50/50'
            }`}
          >
            <tab.icon className={`w-4 h-4 mr-2 rtl:ml-2 ${activeTab === tab.id ? 'text-indigo-600' : 'text-slate-400'}`} />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Tab Content */}
      <div className="min-h-[400px]">
        {renderTabContent()}
      </div>
    </div>
  );
};

export default CaseDetail;

