              <h3 className="text-lg font-bold text-slate-900 mb-2 leading-tight group-hover:text-royal-700 transition-colors">
                  {c.title}
              </h3>

              <p className="text-slate-500 text-sm line-clamp-2 mb-4 font-normal leading-relaxed">
                {c.description}
              </p>

              <div className="flex items-center justify-between pt-3 border-t border-slate-50">
                 <span className="text-xs font-medium text-slate-400 group-hover:text-royal-600 transition-colors flex items-center">
                    View Details <ChevronRight className="w-3 h-3 ml-1 rtl:rotate-180" />
                 </span>

                 <button 
                    onClick={(e) => { e.preventDefault(); onDelete(c.id); }}
                    className="p-2 -mr-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-full transition-colors opacity-0 group-hover:opacity-100"
                    title="Delete Case"
                  >
                    <Trash2 className="w-4 h-4" />
                 </button>
              </div>
            </div>
          </div>
        </Link>
      ))}
      </div>
    </div>
  );
};

export default CaseList;

import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ISSUE_TYPES, FREEZONES } from '../constants';
import { diagnoseCase } from '../services/geminiService';
import { Case, EmployerType } from '../types';
import { Loader2, CheckCircle, XCircle, ChevronRight, AlertCircle, Building2, HelpCircle } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

const generateId = () => Math.random().toString(36).substr(2, 9);

interface Props {
  onSave: (c: Case) => void;
}

const NewCaseWizard: React.FC<Props> = ({ onSave }) => {
  const navigate = useNavigate();
  const { t, language } = useLanguage();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);

  const [formData, setFormData] = useState({
    employerType: 'Unknown' as EmployerType,
    freezone: '',
    issues: [] as string[],
    description: '',
    title: ''
  });

  const [aiResult, setAiResult] = useState<{diagnosis: string, risk: 'Low' | 'Medium' | 'High', dos: string[], donts: string[]} | null>(null);

  const toggleIssue = (issue: string) => {
    setFormData(prev => ({
      ...prev,
      issues: prev.issues.includes(issue) 
        ? prev.issues.filter(i => i !== issue) 
        : [...prev.issues, issue]
    }));
  };

  const handleDiagnose = async () => {
    if (!formData.description) return;
    setLoading(true);
    try {
      const result = await diagnoseCase(formData.description, formData.issues, formData.employerType, formData.freezone, language);
      setAiResult(result);
      setStep(3);
    } catch (error) {
      console.error(error);
      setStep(3);
    } finally {
      setLoading(false);
    }
  };

  const handleSave = () => {
    const newCase: Case = {
      id: generateId(),
      title: formData.title || `Case ${new Date().toLocaleDateString()}`,
      employerType: formData.employerType,
      freezone: formData.employerType === 'Freezone' ? formData.freezone : undefined,
      issueTypes: formData.issues,
      description: formData.description,
      aiDiagnosis: aiResult?.diagnosis,
      riskLevel: aiResult?.risk,
      actionableDos: aiResult?.dos,
      actionableDonts: aiResult?.donts,
      stage: 'Pre-complaint',
      createdAt: new Date().toISOString(),
      evidence: [],
      chatHistory: []
    };
    onSave(newCase);
    navigate(`/case/${newCase.id}`);
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 p-6 md:p-8 transition-all duration-500">
      {/* Progress */}
      <div className="mb-8">
        <div className="flex justify-between items-center text-[10px] font-bold uppercase tracking-widest text-slate-300 mb-3">
            <span className={`transition-colors duration-300 ${step >= 1 ? "text-royal-600" : ""}`}>1. Profile</span>
            <span className={`transition-colors duration-300 ${step >= 2 ? "text-royal-600" : ""}`}>2. Situation</span>
            <span className={`transition-colors duration-300 ${step >= 3 ? "text-royal-600" : ""}`}>3. Analysis</span>
        </div>
        <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
            <div 
                className="h-full bg-royal-900 rounded-full transition-all duration-700 ease-in-out shadow-[0_0_10px_rgba(12,74,110,0.3)]"
                style={{ width: `${(step / 3) * 100}%` }}
            />
        </div>
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-fade-in-up">
          <div>
            <label className="block text-sm font-bold text-slate-900 mb-4">{t('label_employer_type')}</label>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {[
                  { id: 'Mainland', icon: Building2, desc: 'MOHRE Regulated' },
                  { id: 'Freezone', icon: Building2, desc: 'DMCC, JAFZA, etc.' },
                  { id: 'Unknown', icon: HelpCircle, desc: 'Not sure' }
              ].map((type) => (
                <button
                  key={type.id}
                  onClick={() => setFormData({...formData, employerType: type.id as EmployerType, freezone: ''})}
                  className={`relative overflow-hidden group py-5 px-4 rounded-2xl border-2 flex flex-col items-center justify-center text-center transition-all duration-200 ${
                    formData.employerType === type.id 
                      ? 'bg-royal-50 border-royal-600 text-royal-900 shadow-md' 
                      : 'bg-white border-slate-100 text-slate-500 hover:border-slate-300 hover:bg-slate-50'
                  }`}
                >
                  <type.icon className={`w-8 h-8 mb-2 transition-colors duration-200 ${formData.employerType === type.id ? 'text-royal-600' : 'text-slate-300 group-hover:text-slate-400'}`} strokeWidth={1.5} />
                  <span className="font-bold text-sm">{type.id}</span>
                  <span className="text-[10px] mt-1 opacity-60 font-medium">{type.desc}</span>
                  {formData.employerType === type.id && <div className="absolute top-2 right-2 w-2 h-2 bg-royal-600 rounded-full animate-pulse" />}
                </button>
              ))}
            </div>

            {/* Freezone Selector */}
            {formData.employerType === 'Freezone' && (
                <div className="mt-6 animate-fade-in-up">
                    <label className="block text-xs font-bold text-slate-500 mb-2 uppercase tracking-wide">Which Freezone Authority?</label>
                    <select
                        value={formData.freezone}
                        onChange={(e) => setFormData({...formData, freezone: e.target.value})}
                        className="w-full p-4 rounded-2xl border border-slate-200 bg-slate-50 text-slate-900 focus:ring-2 focus:ring-royal-500 focus:border-royal-500 outline-none transition font-medium appearance-none"
                        style={{ backgroundImage: 'none' }} // Custom arrow could be added here
                    >
                        <option value="">Select specific Freezone...</option>
                        {FREEZONES.map(fz => <option key={fz} value={fz}>{fz}</option>)}
                    </select>
                    <p className="text-[10px] text-royal-600 mt-2 ml-1 flex items-center font-medium">
                        <AlertCircle className="w-3 h-3 mr-1" />
                        We'll customize the advice based on this selection.
                    </p>
                </div>
            )}
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-900 mb-4">{t('label_issues')}</label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {ISSUE_TYPES.map(issue => (
                <button
                  key={issue}
                  onClick={() => toggleIssue(issue)}
                  className={`relative text-left rtl:text-right px-5 py-4 rounded-2xl border transition-all duration-200 text-sm font-medium ${
                    formData.issues.includes(issue)
                      ? 'bg-royal-900 text-white border-royal-900 shadow-lg shadow-royal-900/20 transform scale-[1.01]'
                      : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50 hover:border-slate-300'
                  }`}
                >
                  {issue}
                </button>
              ))}
            </div>
          </div>

          <button 
            disabled={formData.issues.length === 0 || (formData.employerType === 'Freezone' && !formData.freezone)}
            onClick={() => setStep(2)}
            className="w-full bg-royal-600 disabled:bg-slate-200 disabled:text-slate-400 text-white font-bold py-5 rounded-2xl mt-4 hover:bg-royal-700 transition-all shadow-xl shadow-royal-600/20 active:scale-95 flex justify-center items-center"
          >
            Continue <ChevronRight className="w-5 h-5 ml-2 rtl:rotate-180" />
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-fade-in-up">
           <div>
            <label className="block text-sm font-bold text-slate-900 mb-2">Give your case a title</label>
            <input 
              type="text"
              placeholder="e.g. Unpaid Salary 2 Months"
              className="w-full border border-slate-200 rounded-2xl p-5 focus:ring-2 focus:ring-royal-500 focus:border-royal-500 outline-none transition shadow-sm font-medium text-slate-900 placeholder:text-slate-300"
              value={formData.title}
              onChange={e => setFormData({...formData, title: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-900 mb-2">{t('label_desc')}</label>
            <textarea
              className="w-full border border-slate-200 rounded-2xl p-5 h-48 focus:ring-2 focus:ring-royal-500 focus:border-royal-500 outline-none transition resize-none shadow-sm text-slate-900 placeholder:text-slate-300 leading-relaxed"
              placeholder="Start typing..."
              value={formData.description}
              onChange={e => setFormData({...formData, description: e.target.value})}
            ></textarea>
            <div className="flex items-start mt-3 text-xs text-slate-600 bg-slate-50 p-4 rounded-xl border border-slate-100">
                <AlertCircle className="w-4 h-4 mr-2 text-royal-500 flex-shrink-0 mt-0.5" />
                <span className="leading-relaxed">Tip: Include dates, specific amounts owed, and mention if you have a written contract or salary slips. This helps the AI be more accurate.</span>
            </div>
          </div>

          <button 
            onClick={handleDiagnose}
            disabled={loading || !formData.description || !formData.title}
            className="w-full bg-royal-900 disabled:bg-slate-200 text-white font-bold py-5 rounded-2xl flex justify-center items-center shadow-xl shadow-royal-900/20 hover:bg-royal-800 transition-all active:scale-95"
          >
            {loading ? <Loader2 className="animate-spin mr-2" /> : t('btn_analyze')}
          </button>
        </div>
      )}

      {step === 3 && aiResult && (
        <div className="space-y-6 animate-fade-in-up">
          <div className={`p-6 rounded-3xl border shadow-sm ${
            aiResult.risk === 'High' ? 'bg-red-50 border-red-100' : 
            aiResult.risk === 'Medium' ? 'bg-amber-50 border-amber-100' : 'bg-emerald-50 border-emerald-100'
          }`}>
            <h3 className={`font-extrabold text-lg mb-2 flex items-center ${
                 aiResult.risk === 'High' ? 'text-red-900' : 
                 aiResult.risk === 'Medium' ? 'text-amber-900' : 'text-emerald-900'
            }`}>
              {t('app_name')} Assessment: {aiResult.risk}
            </h3>
            <p className="text-slate-800 text-sm leading-relaxed opacity-90">
              {aiResult.diagnosis}
            </p>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="bg-white p-6 rounded-3xl border border-emerald-100 shadow-sm relative overflow-hidden">
               <div className="absolute top-0 right-0 w-20 h-20 bg-emerald-50 rounded-full -mr-10 -mt-10 blur-xl"></div>
              <h4 className="font-bold text-emerald-700 mb-4 flex items-center relative z-10">
                <CheckCircle className="w-5 h-5 mr-2" /> Immediate Actions
              </h4>
              <ul className="space-y-3 relative z-10">
                {aiResult.dos?.map((rec, i) => (
                  <li key={i} className="text-sm text-slate-700 flex items-start">
                    <span className="mr-2 text-emerald-500 font-bold">•</span> {rec}
                  </li>
                ))}
              </ul>
            </div>

            <div className="bg-white p-6 rounded-3xl border border-red-100 shadow-sm relative overflow-hidden">
              <div className="absolute top-0 right-0 w-20 h-20 bg-red-50 rounded-full -mr-10 -mt-10 blur-xl"></div>
              <h4 className="font-bold text-red-700 mb-4 flex items-center relative z-10">
                <XCircle className="w-5 h-5 mr-2" /> Avoid This
              </h4>
              <ul className="space-y-3 relative z-10">
                {aiResult.donts?.map((rec, i) => (
                  <li key={i} className="text-sm text-slate-700 flex items-start">
                    <span className="mr-2 text-red-500 font-bold">•</span> {rec}
                  </li>
                ))}
              </ul>
            </div>
          </div>

          <button 
            onClick={handleSave}
            className="w-full bg-royal-900 hover:bg-royal-800 text-white font-bold py-5 rounded-2xl shadow-xl shadow-royal-900/20 transition transform active:scale-95"
          >
            {t('btn_save_dashboard')}
          </button>
        </div>
      )}
    </div>
  );
};

export default NewCaseWizard;

import React, { useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Case } from '../types';
import { MessageSquare, FileText, Send, PhoneCall, LayoutDashboard, ChevronLeft, CheckCircle, XCircle } from 'lucide-react';
import ChatInterface from './ChatInterface';
import EvidenceAnalyzer from './EvidenceAnalyzer';
import ReplyGenerator from './ReplyGenerator';
import CallCoach from './CallCoach';

interface Props {
  cases: Case[];
  onUpdate: (c: Case) => void;
}

type Tab = 'overview' | 'chat' | 'evidence' | 'reply' | 'coach';

const CaseDetail: React.FC<Props> = ({ cases, onUpdate }) => {
  const { id } = useParams<{ id: string }>();
  const [activeTab, setActiveTab] = useState<Tab>('overview');

  const currentCase = cases.find(c => c.id === id);

  if (!currentCase) {
    return <div className="p-12 text-center text-slate-400 font-medium">Case not found</div>;
  }

  const renderTabContent = () => {
    switch (activeTab) {
      case 'overview':
        return (
          <div className="space-y-6 animate-fade-in-up">
            {/* Summary Card */}
            <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/50">
              <div className="flex justify-between items-start mb-6">
                 <div>
                    <h2 className="text-lg font-extrabold text-slate-900">Case Dashboard</h2>
                    <span className="text-[10px] text-slate-400 font-mono">#{currentCase.id.substring(0,8)}</span>
                 </div>
                 <div className={`px-3 py-1 rounded-full text-xs font-bold ${
                    currentCase.stage === 'Closed' ? 'bg-slate-100 text-slate-500' : 'bg-royal-50 text-royal-700'
                 }`}>
                    {currentCase.stage}
                 </div>
              </div>

              <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100 mb-6">
                <p className="text-slate-700 leading-relaxed text-sm font-medium">
                    {currentCase.description}
                </p>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-6 text-sm">
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Jurisdiction</span>
                    <span className="font-bold text-slate-900" title={currentCase.freezone}>
                        {currentCase.employerType === 'Freezone' && currentCase.freezone 
                            ? currentCase.freezone.split('(')[0].trim() 
                            : currentCase.employerType}
                    </span>
                 </div>
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Main Issue</span>
                    <span className="font-bold text-slate-900 truncate">{currentCase.issueTypes[0]}</span>
                 </div>
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Risk</span>
                    <span className={`font-bold px-2 py-0.5 rounded-md inline-block w-fit text-xs ${
                        currentCase.riskLevel === 'High' ? 'bg-red-50 text-red-600' : 
                        currentCase.riskLevel === 'Medium' ? 'bg-amber-50 text-amber-600' : 'bg-emerald-50 text-emerald-600'
                    }`}>
                        {currentCase.riskLevel}
                    </span>
                 </div>
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Created</span>
                    <span className="font-bold text-slate-900">{new Date(currentCase.createdAt).toLocaleDateString()}</span>
                 </div>
              </div>
            </div>

            {/* Actionable Advice */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               {currentCase.actionableDos && currentCase.actionableDos.length > 0 && (
                   <div className="bg-white p-6 rounded-3xl border border-emerald-100 shadow-sm">
                       <h3 className="font-bold text-emerald-700 mb-4 flex items-center text-sm uppercase tracking-wide">
                           <CheckCircle className="w-5 h-5 mr-2" /> Recommended Actions
                       </h3>
                       <ul className="space-y-3">
                           {currentCase.actionableDos.map((item, i) => (
                               <li key={i} className="text-sm text-slate-700 flex items-start">
                                   <span className="mr-2 text-emerald-500 font-bold">•</span> {item}
                               </li>
                           ))}
                       </ul>
                   </div>
               )}

               {currentCase.actionableDonts && currentCase.actionableDonts.length > 0 && (
                   <div className="bg-white p-6 rounded-3xl border border-red-100 shadow-sm">
                       <h3 className="font-bold text-red-700 mb-4 flex items-center text-sm uppercase tracking-wide">
                           <XCircle className="w-5 h-5 mr-2" /> What To Avoid
                       </h3>
                       <ul className="space-y-3">
                           {currentCase.actionableDonts.map((item, i) => (
                               <li key={i} className="text-sm text-slate-700 flex items-start">
                                   <span className="mr-2 text-red-500 font-bold">•</span> {item}
                               </li>
                           ))}
                       </ul>
                   </div>
               )}
            </div>
          </div>
        );
      case 'chat':
        return <ChatInterface currentCase={currentCase} onUpdate={onUpdate} />;
      case 'evidence':
        return <EvidenceAnalyzer currentCase={currentCase} onUpdate={onUpdate} />;
      case 'reply':
        return <ReplyGenerator currentCase={currentCase} />;
      case 'coach':
        return <CallCoach currentCase={currentCase} />;
      default:
        return null;
    }
  };

  const tabs: { id: Tab; label: string; icon: any }[] = [
    { id: 'overview', label: 'Overview', icon: LayoutDashboard },
    { id: 'chat', label: 'AI Assistant', icon: MessageSquare },
    { id: 'evidence', label: 'Evidence', icon: FileText },
    { id: 'reply', label: 'Reply Gen', icon: Send },
    { id: 'coach', label: 'Call Prep', icon: PhoneCall },
  ];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center space-x-4 mb-2">
        <Link to="/" className="p-2.5 rounded-full bg-white border border-slate-200 text-slate-500 hover:text-royal-900 hover:bg-royal-50 transition shadow-sm">
          <ChevronLeft className="w-5 h-5 rtl:rotate-180" />
        </Link>
        <div>
           <h1 className="text-2xl font-extrabold text-slate-900 tracking-tight leading-tight">{currentCase.title}</h1>
           <div className="flex space-x-2 text-xs text-slate-500 font-medium mt-1">
              <span>{currentCase.issueTypes.join(', ')}</span>
           </div>
        </div>
      </div>

      {/* Modern Pill Tabs */}
      <div className="flex overflow-x-auto pb-4 space-x-3 no-scrollbar rtl:space-x-reverse px-1">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex items-center px-5 py-3 rounded-full text-sm font-bold whitespace-nowrap transition-all duration-300 border ${
              activeTab === tab.id
                ? 'bg-royal-900 text-white border-royal-900 shadow-lg shadow-royal-900/20 transform scale-[1.02]'
                : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50 hover:text-slate-700'
            }`}
          >
            <tab.icon className={`w-4 h-4 mr-2 rtl:ml-2 ${activeTab === tab.id ? 'text-royal-200' : 'text-slate-400'}`} />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Tab Content */}
      <div className="min-h-[400px]">
        {renderTabContent()}
      </div>
    </div>
  );
};

export default CaseDetail;

import React, { useState, useRef, useEffect } from 'react';
import { Case, ChatMessage } from '../types';
import { chatWithAI } from '../services/geminiService';
import { Send, User, Shield, Loader2, Flag } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface Props {
  currentCase: Case;
  onUpdate: (c: Case) => void;
}

const ChatInterface: React.FC<Props> = ({ currentCase, onUpdate }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const { language, t, dir } = useLanguage();

  const messages = currentCase.chatHistory || [];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    const newHistory = [...messages, userMsg];

    // Optimistic update
    onUpdate({
      ...currentCase,
      chatHistory: newHistory
    });
    setInput('');
    setLoading(true);

    try {
      const result = await chatWithAI(messages, input, currentCase, language);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: result.text,
        timestamp: Date.now(),
        isFlaggedForReview: result.isFlagged
      };
      onUpdate({
        ...currentCase,
        chatHistory: [...newHistory, aiMsg]
      });
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden animate-fade-in-up" dir={dir}>
      <div className="flex-grow overflow-y-auto space-y-6 p-6" ref={scrollRef}>
        {messages.length === 0 && (
           <div className="flex flex-col items-center justify-center h-full text-center text-slate-400">
             <div className="bg-royal-50 p-4 rounded-full mb-4">
                 <Shield className="w-8 h-8 text-royal-600" />
             </div>
             <p className="font-medium text-slate-600">I know the details of your case.</p>
             <p className="text-sm mt-1">Ask me specifically about your {currentCase.issueTypes[0]} situation.</p>
           </div>
        )}

        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex items-end max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>

              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 mb-1 shadow-sm ${
                msg.role === 'user' ? 'bg-royal-600 mx-2' : 'bg-white border border-slate-200 mx-2'
              }`}>
                {msg.role === 'user' ? <User className="w-5 h-5 text-white" /> : <Shield className="w-5 h-5 text-royal-600" />}
              </div>

              <div className="flex flex-col">
                <div className={`p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${
                  msg.role === 'user' 
                    ? 'bg-royal-600 text-white rounded-br-none rtl:rounded-bl-none rtl:rounded-br-2xl' 
                    : 'bg-slate-50 text-slate-800 rounded-bl-none rtl:rounded-br-none rtl:rounded-bl-2xl border border-slate-100'
                }`}>
                  <div className="whitespace-pre-wrap">{msg.text}</div>
                </div>
                {msg.role === 'model' && (
                  <div className="mt-1.5 pl-1">
                      {msg.isFlaggedForReview && (
                        <div className="flex items-center text-[10px] text-amber-600 mb-1">
                          <Flag className="w-3 h-3 mr-1" /> Uncertain - Please verify
                        </div>
                      )}
                      <p className="text-[10px] text-slate-300">{t('inline_disclaimer')}</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}

        {loading && (
          <div className="flex justify-start">
             <div className="flex items-center space-x-2 bg-slate-50 rounded-2xl p-4 border border-slate-100">
               <Loader2 className="w-4 h-4 animate-spin text-royal-600" />
               <span className="text-xs text-slate-500 font-medium">Analyzing UAE regulations...</span>
             </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-slate-100">
        <div className="flex space-x-2 items-center bg-slate-50 p-2 rounded-2xl border border-slate-200 focus-within:ring-2 focus-within:ring-royal-500/20 focus-within:border-royal-500 transition-all">
          <input
            type="text"
            className="flex-grow bg-transparent px-3 py-2 outline-none text-slate-900 placeholder:text-slate-400"
            placeholder="Type your question..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            disabled={loading}
          />
          <button
            onClick={handleSend}
            disabled={loading || !input.trim()}
            className="bg-royal-900 text-white p-2.5 rounded-xl hover:bg-royal-800 disabled:bg-slate-300 disabled:text-slate-400 transition shadow-sm"
          >
            <Send className="w-5 h-5 rtl:rotate-180" />
          </button>
        </div>
      </div>
    </div>
  );
};

