export const simulateOfficerTurn = async (history: {role: string, text: string}[]): Promise<string> => {
    await new Promise(resolve => setTimeout(resolve, 1000));
    const lastUserMsg = history[history.length - 1].text.toLowerCase();

    if (history.length <= 1) return "Hello. I am the MOHRE case officer. Can you please state your name and the name of your company?";

    if (lastUserMsg.includes('salary')) return "I understand. How many months of salary are currently pending? Do you have bank statements?";
    if (lastUserMsg.includes('terminate') || lastUserMsg.includes('fired')) return "Was this termination verbal or did you receive a written letter?";

    return "Thank you. Do you have any evidence to support this claim, like emails or messages?";
};

