interface Props {
  currentCase: Case;
}

const CallCoach: React.FC<Props> = ({ currentCase }) => {
  const [mode, setMode] = useState<'script' | 'simulator'>('script');
  const [prepType, setPrepType] = useState('MOHRE Call');
  const [script, setScript] = useState('');
  const [loading, setLoading] = useState(false);

  // Simulator State
  const [simHistory, setSimHistory] = useState<{role: string, text: string}[]>([]);
  const [simInput, setSimInput] = useState('');
  const [simLoading, setSimLoading] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  const { language, t } = useLanguage();

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [simHistory]);

  const handleGenerateScript = async () => {
    setLoading(true);
    try {
      const result = await generateCallPrep(currentCase, prepType, language);
      setScript(result);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const startSimulation = async () => {
      setMode('simulator');
      setSimLoading(true);
      setSimHistory([]);
      try {
          const firstMsg = await simulateOfficerTurn([]);
          setSimHistory([{ role: 'officer', text: firstMsg }]);
      } finally {
          setSimLoading(false);
      }
  };

  const handleSimSend = async () => {
      if (!simInput.trim()) return;
      const userMsg = { role: 'user', text: simInput };
      const newHistory = [...simHistory, userMsg];
      setSimHistory(newHistory);
      setSimInput('');
      setSimLoading(true);

      try {
          const officerMsg = await simulateOfficerTurn(newHistory);
          setSimHistory([...newHistory, { role: 'officer', text: officerMsg }]);
      } finally {
          setSimLoading(false);
      }
  };

  return (
    <div className="space-y-6">
      {/* Mode Switcher */}
      <div className="flex p-1 bg-slate-100 rounded-xl">
          <button 
            onClick={() => setMode('script')}
            className={`flex-1 py-2 rounded-lg text-sm font-bold transition ${mode === 'script' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500'}`}
          >
              Script & Tips
          </button>
          <button 
            onClick={() => setMode('simulator')}
            className={`flex-1 py-2 rounded-lg text-sm font-bold transition ${mode === 'simulator' ? 'bg-white shadow-sm text-slate-900' : 'text-slate-500'}`}
          >
              Live Simulator
          </button>
      </div>

      {mode === 'script' ? (
        <div className="animate-in fade-in slide-in-from-left-4">
            <div className="bg-white p-6 rounded-2xl border border-slate-200 mb-6">
                <h3 className="text-lg font-bold mb-4">Select Meeting Type</h3>
                <div className="grid grid-cols-3 gap-3 mb-6">
                {[
                    { id: 'MOHRE Call', icon: Phone },
                    { id: 'HR Meeting', icon: Users },
                    { id: 'Court Hearing', icon: Gavel }
                ].map((type) => (
                    <button
                    key={type.id}
                    onClick={() => setPrepType(type.id)}
                    className={`flex flex-col items-center p-3 rounded-xl border transition ${
                        prepType === type.id 
                        ? 'bg-royal-50 border-royal-500 text-royal-700' 
                        : 'bg-white border-slate-100 hover:bg-slate-50 text-slate-600'
                    }`}
                    >
                    <type.icon className="w-6 h-6 mb-2" />
                    <span className="text-xs font-medium">{type.id}</span>
                    </button>
                ))}
                </div>

                <button
                onClick={handleGenerateScript}
                disabled={loading}
                className="w-full bg-royal-600 hover:bg-royal-700 text-white font-bold py-4 rounded-xl flex items-center justify-center shadow-lg shadow-royal-600/20"
                >
                {loading ? <Loader2 className="animate-spin mr-2" /> : "Generate Coaching Script"}
                </button>
            </div>

            {script && (
                <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="prose prose-sm prose-slate max-w-none">
                    {script.split('\n').map((line, i) => (
                    <p key={i} className={`
                        ${line.startsWith('**') ? 'font-bold text-slate-900 mt-4' : 'text-slate-700'}
                        ${line.startsWith('-') || line.startsWith('1.') ? 'ml-4 rtl:mr-4 rtl:ml-0' : ''}
                    `}>
                        {line.replace(/\*\*/g, '')}
                    </p>
                    ))}
                </div>
                </div>
            )}
        </div>
      ) : (
        <div className="bg-white rounded-2xl border border-slate-200 shadow-lg overflow-hidden flex flex-col h-[500px] animate-in fade-in slide-in-from-right-4">
            {simHistory.length === 0 && !simLoading && (
                <div className="flex flex-col items-center justify-center h-full text-center p-8">
                    <div className="bg-indigo-50 p-4 rounded-full mb-4">
                        <Phone className="w-8 h-8 text-indigo-600" />
                    </div>
                    <h3 className="font-bold text-lg text-slate-900 mb-2">Practice with AI Officer</h3>
                    <p className="text-sm text-slate-500 mb-6">
                        The AI will pretend to be a MOHRE officer. Practice answering tough questions safely.
                    </p>
                    <button 
                        onClick={startSimulation}
                        className="bg-indigo-600 text-white px-8 py-3 rounded-xl font-bold hover:bg-indigo-700 transition flex items-center shadow-lg"
                    >
                        <PlayCircle className="w-5 h-5 mr-2" /> Start Simulation
                    </button>
                </div>
            )}

            {(simHistory.length > 0 || simLoading) && (
                <>
                    <div className="flex-grow bg-slate-50 overflow-y-auto p-4 space-y-4" ref={scrollRef}>
                        {simHistory.map((msg, i) => (
                            <div key={i} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                                <div className={`max-w-[80%] p-4 rounded-2xl text-sm ${
                                    msg.role === 'user' 
                                        ? 'bg-indigo-600 text-white rounded-br-none' 
                                        : 'bg-white border border-slate-200 text-slate-800 rounded-bl-none shadow-sm'
                                }`}>
                                    <span className="text-[10px] font-bold opacity-70 block mb-1 uppercase tracking-wider">
                                        {msg.role === 'user' ? 'You' : 'Officer'}
                                    </span>
                                    {msg.text}
                                </div>
                            </div>
                        ))}
                        {simLoading && (
                            <div className="flex justify-start">
                                <div className="bg-white p-3 rounded-2xl rounded-bl-none border border-slate-200 shadow-sm">
                                    <Loader2 className="w-5 h-5 animate-spin text-indigo-500" />
                                </div>
                            </div>
                        )}
                    </div>
                    <div className="p-4 bg-white border-t border-slate-200">
                        <div className="flex space-x-2">
                            <input
                                type="text"
                                className="flex-grow p-3 border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                                placeholder="Type your answer..."
                                value={simInput}
                                onChange={e => setSimInput(e.target.value)}
                                onKeyDown={e => e.key === 'Enter' && handleSimSend()}
                                disabled={simLoading}
                            />
                            <button 
                                onClick={handleSimSend}
                                disabled={simLoading || !simInput.trim()}
                                className="bg-indigo-600 text-white p-3 rounded-xl hover:bg-indigo-700 disabled:bg-slate-300"
                            >
                                <MessageCircle className="w-5 h-5" />
                            </button>
                        </div>
                    </div>
                </>
            )}
        </div>
      )}
    </div>
  );
};

export default CallCoach;

import React, { useState } from 'react';
import { Case, EvidenceItem } from '../types';
import { analyzeEvidence } from '../services/geminiService';
import { Upload, FileText, Tag, Trash2, Loader2, AlertTriangle, CheckCircle, Info } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface Props {
  currentCase: Case;
  onUpdate: (c: Case) => void;
}

const EvidenceAnalyzer: React.FC<Props> = ({ currentCase, onUpdate }) => {
  const [analyzing, setAnalyzing] = useState(false);
  const { language, t } = useLanguage();

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setAnalyzing(true);

    const reader = new FileReader();
    reader.onloadend = async () => {
      const base64String = reader.result as string;
      const base64Data = base64String.split(',')[1]; // Remove data URL prefix

      try {
        const analysis = await analyzeEvidence(base64Data, file.type, language);

        const newEvidence: EvidenceItem = {
          id: Date.now().toString(),
          type: analysis.type as any || 'Other',
          description: file.name,
          summary: analysis.summary,
          tags: analysis.tags,
          dateAdded: new Date().toISOString(),
          analysis: analysis.analysis
        };

        onUpdate({
          ...currentCase,
          evidence: [newEvidence, ...currentCase.evidence]
        });
      } catch (error) {
        alert("Failed to analyze image. Please try again.");
      } finally {
        setAnalyzing(false);
      }
    };
    reader.readAsDataURL(file);
  };

  const deleteEvidence = (id: string) => {
    onUpdate({
        ...currentCase,
        evidence: currentCase.evidence.filter(e => e.id !== id)
    })
  }

  return (
    <div className="space-y-6">
      <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-sm text-center">
        <input 
          type="file" 
          id="evidence-upload" 
          className="hidden" 
          accept="image/*"
          onChange={handleFileUpload}
          disabled={analyzing}
        />
        <label 
          htmlFor="evidence-upload"
          className="cursor-pointer flex flex-col items-center justify-center p-10 border-2 border-dashed border-royal-200 rounded-2xl bg-royal-50 hover:bg-royal-100 transition group"
        >
          {analyzing ? (
            <Loader2 className="w-12 h-12 text-royal-600 animate-spin mb-4" />
          ) : (
            <div className="bg-white p-4 rounded-full shadow-sm mb-4 group-hover:scale-110 transition">
                <Upload className="w-8 h-8 text-royal-600" />
            </div>
          )}
          <span className="text-royal-900 font-bold text-lg">
            {analyzing ? "AI is Analyzing..." : "Upload Screenshot or Document"}
          </span>
          <span className="text-royal-600 text-sm mt-2 opacity-80">Supports: PNG, JPG (Chats, Emails, Contracts)</span>
        </label>
        <div className="mt-4 flex items-center justify-center text-xs text-slate-400 space-x-4">
             <span className="flex items-center"><AlertTriangle className="w-3 h-3 mr-1 text-red-400"/> Detects Threats</span>
             <span className="flex items-center"><CheckCircle className="w-3 h-3 mr-1 text-emerald-400"/> Finds Admissions</span>
        </div>
      </div>

      <div className="space-y-4">
        <h3 className="font-bold text-slate-800 flex items-center">
          <FileText className="w-5 h-5 mr-2" />
          Analyzed Evidence ({currentCase.evidence.length})
        </h3>

        {currentCase.evidence.length === 0 && (
            <div className="text-center py-10 opacity-50">
                <FileText className="w-12 h-12 mx-auto mb-2 text-slate-300" />
                <p className="text-slate-400 italic text-sm">No evidence uploaded yet.</p>
            </div>
        )}

        {currentCase.evidence.map((item) => (
          <div key={item.id} className="bg-white p-5 rounded-2xl border border-slate-200 shadow-sm transition hover:shadow-md">
            <div className="flex justify-between items-start mb-3">
              <div className="flex items-center">
                  <span className="font-bold text-slate-900 text-sm mr-2">{item.type}</span>
                  <span className="text-xs text-slate-400">{new Date(item.dateAdded).toLocaleDateString()}</span>
              </div>
              <button onClick={() => deleteEvidence(item.id)} className="text-slate-300 hover:text-red-500 transition">
                <Trash2 className="w-4 h-4" />
              </button>
            </div>

            <p className="text-sm text-slate-600 mb-4 leading-relaxed">
              {item.summary}
            </p>

            {item.analysis && (
                <div className="space-y-2 mb-4">
                    {item.analysis.threats?.map((t, i) => (
                        <div key={i} className="flex items-start text-xs text-red-700 bg-red-50 p-2 rounded-lg border border-red-100">
                             <AlertTriangle className="w-3 h-3 mr-2 mt-0.5 flex-shrink-0" /> {t}
                        </div>
                    ))}
                    {item.analysis.admissions?.map((t, i) => (
                        <div key={i} className="flex items-start text-xs text-emerald-700 bg-emerald-50 p-2 rounded-lg border border-emerald-100">
                             <CheckCircle className="w-3 h-3 mr-2 mt-0.5 flex-shrink-0" /> {t}
                        </div>
                    ))}
                </div>
            )}

            <div className="flex flex-wrap gap-2">
              {item.tags.map((tag, idx) => (
                <span key={idx} className="inline-flex items-center text-[10px] uppercase tracking-wide font-bold bg-slate-100 text-slate-600 px-2 py-1 rounded">
                  <Tag className="w-3 h-3 mr-1" /> {tag}
                </span>
              ))}
            </div>
          </div>
        ))}
      </div>
      <p className="text-[10px] text-center text-slate-400 mt-2">{t('inline_disclaimer')}</p>
    </div>
  );
};

export default EvidenceAnalyzer;

import React, { useState, useEffect } from 'react';
import { useParams, Link } from 'react-router-dom';
import { Case, RoadmapTask, TimelineEvent } from '../types';
import { generateRoadmap } from '../services/geminiService';
import { MessageSquare, FileText, Send, PhoneCall, LayoutDashboard, ChevronLeft, CheckCircle, XCircle, Calendar, CheckSquare } from 'lucide-react';
import ChatInterface from './ChatInterface';
import EvidenceAnalyzer from './EvidenceAnalyzer';
import ReplyGenerator from './ReplyGenerator';
import CallCoach from './CallCoach';
import TimelineBuilder from './TimelineBuilder';

interface Props {
  cases: Case[];
  onUpdate: (c: Case) => void;
}

type Tab = 'overview' | 'timeline' | 'chat' | 'evidence' | 'reply' | 'coach';

const CaseDetail: React.FC<Props> = ({ cases, onUpdate }) => {
  const { id } = useParams<{ id: string }>();
  const [activeTab, setActiveTab] = useState<Tab>('overview');
  const [roadmapLoading, setRoadmapLoading] = useState(false);

  const currentCase = cases.find(c => c.id === id);

  useEffect(() => {
      // Auto-generate roadmap if missing
      if (currentCase && !currentCase.roadmap && !roadmapLoading) {
          setRoadmapLoading(true);
          generateRoadmap(currentCase).then(tasks => {
              onUpdate({ ...currentCase, roadmap: tasks });
              setRoadmapLoading(false);
          });
      }
  }, [currentCase, roadmapLoading]);

  if (!currentCase) {
    return <div className="p-12 text-center text-slate-400 font-medium">Case not found</div>;
  }

  const toggleTask = (taskId: string) => {
      if (!currentCase.roadmap) return;
      const updatedTasks = currentCase.roadmap.map(t => 
          t.id === taskId ? { ...t, isCompleted: !t.isCompleted } : t
      );
      onUpdate({ ...currentCase, roadmap: updatedTasks });
  };

  const handleTimelineSave = (timeline: TimelineEvent[]) => {
      onUpdate({ ...currentCase, timeline });
  };

  const renderTabContent = () => {
    switch (activeTab) {
      case 'overview':
        return (
          <div className="space-y-6 animate-fade-in-up">
            {/* Summary Card */}
            <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/50">
              <div className="flex justify-between items-start mb-6">
                 <div>
                    <h2 className="text-lg font-extrabold text-slate-900">Case Dashboard</h2>
                    <span className="text-[10px] text-slate-400 font-mono">#{currentCase.id.substring(0,8)}</span>
                 </div>
                 <div className={`px-3 py-1 rounded-full text-xs font-bold ${
                    currentCase.stage === 'Closed' ? 'bg-slate-100 text-slate-500' : 'bg-royal-50 text-royal-700'
                 }`}>
                    {currentCase.stage}
                 </div>
              </div>

              <div className="bg-slate-50 p-5 rounded-2xl border border-slate-100 mb-6">
                <p className="text-slate-700 leading-relaxed text-sm font-medium">
                    {currentCase.description}
                </p>
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 gap-6 text-sm">
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Jurisdiction</span>
                    <span className="font-bold text-slate-900" title={currentCase.freezone}>
                        {currentCase.employerType === 'Freezone' && currentCase.freezone 
                            ? currentCase.freezone.split('(')[0].trim() 
                            : currentCase.employerType}
                    </span>
                 </div>
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Main Issue</span>
                    <span className="font-bold text-slate-900 truncate">{currentCase.issueTypes[0]}</span>
                 </div>
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Risk</span>
                    <span className={`font-bold px-2 py-0.5 rounded-md inline-block w-fit text-xs ${
                        currentCase.riskLevel === 'High' ? 'bg-red-50 text-red-600' : 
                        currentCase.riskLevel === 'Medium' ? 'bg-amber-50 text-amber-600' : 'bg-emerald-50 text-emerald-600'
                    }`}>
                        {currentCase.riskLevel}
                    </span>
                 </div>
                 <div className="flex flex-col">
                    <span className="text-slate-400 font-bold text-[10px] uppercase tracking-wider mb-1">Created</span>
                    <span className="font-bold text-slate-900">{new Date(currentCase.createdAt).toLocaleDateString()}</span>
                 </div>
              </div>
            </div>

            {/* Roadmap Widget */}
            <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                <div className="flex justify-between items-center mb-4">
                    <h3 className="font-bold text-slate-900 flex items-center">
                        <CheckSquare className="w-5 h-5 mr-2 text-royal-600" /> Case Roadmap
                    </h3>
                    <span className="text-xs text-slate-400">
                        {currentCase.roadmap?.filter(t => t.isCompleted).length || 0} / {currentCase.roadmap?.length || 0}
                    </span>
                </div>
                {currentCase.roadmap ? (
                    <div className="space-y-3">
                        {currentCase.roadmap.map(task => (
                            <button 
                                key={task.id}
                                onClick={() => toggleTask(task.id)}
                                className={`w-full text-left p-3 rounded-xl border transition-all duration-200 flex items-start ${
                                    task.isCompleted ? 'bg-slate-50 border-slate-100 opacity-60' : 'bg-white border-slate-200 hover:border-royal-400'
                                }`}
                            >
                                <div className={`w-5 h-5 rounded-md border-2 mr-3 flex items-center justify-center flex-shrink-0 transition ${
                                    task.isCompleted ? 'bg-royal-600 border-royal-600' : 'border-slate-300'
                                }`}>
                                    {task.isCompleted && <CheckCircle className="w-3.5 h-3.5 text-white" />}
                                </div>
                                <div>
                                    <p className={`text-sm font-bold ${task.isCompleted ? 'text-slate-500 line-through' : 'text-slate-800'}`}>{task.title}</p>
                                    <p className="text-xs text-slate-400 mt-0.5">{task.description}</p>
                                </div>
                            </button>
                        ))}
                    </div>
                ) : (
                   <div className="p-4 text-center text-sm text-slate-400 bg-slate-50 rounded-xl">Generatng Roadmap...</div>
                )}
            </div>

            {/* Actionable Advice Grid */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
               {currentCase.actionableDos && currentCase.actionableDos.length > 0 && (
                   <div className="bg-white p-6 rounded-3xl border border-emerald-100 shadow-sm">
                       <h3 className="font-bold text-emerald-700 mb-4 flex items-center text-sm uppercase tracking-wide">
                           <CheckCircle className="w-5 h-5 mr-2" /> Recommended Actions
                       </h3>
                       <ul className="space-y-3">
                           {currentCase.actionableDos.map((item, i) => (
                               <li key={i} className="text-sm text-slate-700 flex items-start">
                                   <span className="mr-2 text-emerald-500 font-bold">•</span> {item}
                               </li>
                           ))}
                       </ul>
                   </div>
               )}

               {currentCase.actionableDonts && currentCase.actionableDonts.length > 0 && (
                   <div className="bg-white p-6 rounded-3xl border border-red-100 shadow-sm">
                       <h3 className="font-bold text-red-700 mb-4 flex items-center text-sm uppercase tracking-wide">
                           <XCircle className="w-5 h-5 mr-2" /> What To Avoid
                       </h3>
                       <ul className="space-y-3">
                           {currentCase.actionableDonts.map((item, i) => (
                               <li key={i} className="text-sm text-slate-700 flex items-start">
                                   <span className="mr-2 text-red-500 font-bold">•</span> {item}
                               </li>
                           ))}
                       </ul>
                   </div>
               )}
            </div>
          </div>
        );
      case 'timeline':
          return <TimelineBuilder currentCase={currentCase} onSave={handleTimelineSave} />;
      case 'chat':
        return <ChatInterface currentCase={currentCase} onUpdate={onUpdate} />;
      case 'evidence':
        return <EvidenceAnalyzer currentCase={currentCase} onUpdate={onUpdate} />;
      case 'reply':
        return <ReplyGenerator currentCase={currentCase} />;
      case 'coach':
        return <CallCoach currentCase={currentCase} />;
      default:
        return null;
    }
  };

  const tabs: { id: Tab; label: string; icon: any }[] = [
    { id: 'overview', label: 'Overview', icon: LayoutDashboard },
    { id: 'timeline', label: 'Timeline', icon: Calendar },
    { id: 'chat', label: 'AI Assistant', icon: MessageSquare },
    { id: 'evidence', label: 'Evidence', icon: FileText },
    { id: 'reply', label: 'Reply Gen', icon: Send },
    { id: 'coach', label: 'Call Prep', icon: PhoneCall },
  ];

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex items-center space-x-4 mb-2">
        <Link to="/" className="p-2.5 rounded-full bg-white border border-slate-200 text-slate-500 hover:text-royal-900 hover:bg-royal-50 transition shadow-sm">
          <ChevronLeft className="w-5 h-5 rtl:rotate-180" />
        </Link>
        <div>
           <h1 className="text-2xl font-extrabold text-slate-900 tracking-tight leading-tight">{currentCase.title}</h1>
           <div className="flex space-x-2 text-xs text-slate-500 font-medium mt-1">
              <span>{currentCase.issueTypes.join(', ')}</span>
           </div>
        </div>
      </div>

      {/* Modern Pill Tabs */}
      <div className="flex overflow-x-auto pb-4 space-x-3 no-scrollbar rtl:space-x-reverse px-1">
        {tabs.map(tab => (
          <button
            key={tab.id}
            onClick={() => setActiveTab(tab.id)}
            className={`flex items-center px-5 py-3 rounded-full text-sm font-bold whitespace-nowrap transition-all duration-300 border ${
              activeTab === tab.id
                ? 'bg-royal-900 text-white border-royal-900 shadow-lg shadow-royal-900/20 transform scale-[1.02]'
                : 'bg-white text-slate-500 border-slate-200 hover:bg-slate-50 hover:text-slate-700'
            }`}
          >
            <tab.icon className={`w-4 h-4 mr-2 rtl:ml-2 ${activeTab === tab.id ? 'text-royal-200' : 'text-slate-400'}`} />
            {tab.label}
          </button>
        ))}
      </div>

      {/* Tab Content */}
      <div className="min-h-[400px]">
        {renderTabContent()}
      </div>
    </div>
  );
};

export default CaseDetail;

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import CaseList from './components/CaseList';
import NewCaseWizard from './components/NewCaseWizard';
import CaseDetail from './components/CaseDetail';
import KnowledgeBase from './components/KnowledgeBase';
import RightsChecker from './components/RightsChecker';
import DisclaimerModal from './components/DisclaimerModal';
import Settings from './components/Settings';
import { Case } from './types';
import { LanguageProvider } from './contexts/LanguageContext';

const AppContent: React.FC = () => {
  const [cases, setCases] = useState<Case[]>([]);
  const [acceptedDisclaimer, setAcceptedDisclaimer] = useState(false);

  // Load from local storage on mount
  useEffect(() => {
    const storedCases = localStorage.getItem('ws_cases');
    if (storedCases) {
      setCases(JSON.parse(storedCases));
    }
    const storedDisclaimer = localStorage.getItem('ws_disclaimer');
    if (storedDisclaimer === 'true') {
      setAcceptedDisclaimer(true);
    }
  }, []);

  // Save to local storage on change
  useEffect(() => {
    localStorage.setItem('ws_cases', JSON.stringify(cases));
  }, [cases]);

  const handleDisclaimerAccept = () => {
    setAcceptedDisclaimer(true);
    localStorage.setItem('ws_disclaimer', 'true');
  };

  const addCase = (newCase: Case) => {
    setCases([newCase, ...cases]);
  };

  const updateCase = (updatedCase: Case) => {
    setCases(cases.map(c => c.id === updatedCase.id ? updatedCase : c));
  };

  const deleteCase = (id: string) => {
    setCases(cases.filter(c => c.id !== id));
  };

  return (
    <HashRouter>
      {!acceptedDisclaimer && <DisclaimerModal onAccept={handleDisclaimerAccept} />}
      <Layout>
        <Routes>
          <Route path="/" element={<CaseList cases={cases} onDelete={deleteCase} />} />
          <Route path="/new" element={<NewCaseWizard onSave={addCase} />} />
          <Route path="/case/:id/*" element={<CaseDetail cases={cases} onUpdate={updateCase} />} />
          <Route path="/knowledge" element={<KnowledgeBase />} />
          <Route path="/rights" element={<RightsChecker />} />
          <Route path="/settings" element={<Settings />} />
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

const App: React.FC = () => {
  return (
    <LanguageProvider>
      <AppContent />
    </LanguageProvider>
  );
};

export default App;

