export const diagnoseCase = async (description: string, issues: string[], employerType: string, freezone: string | undefined, lang: AppLanguage): Promise<{ diagnosis: string; risk: 'Low' | 'Medium' | 'High'; dos: string[]; donts: string[] }> => {
  const ai = getAI();
  if (ai) {
      try {
          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `Analyze this UAE labour case.
                Issues: ${issues.join(', ')}
                Employer: ${employerType} ${freezone ? `(${freezone})` : ''}
                Description: ${description}

                Respond in Language: ${lang}
                Return valid JSON with properties: diagnosis (string summary), risk (Low/Medium/High), dos (array of strings), donts (array of strings).`,
              config: {
                  responseMimeType: 'application/json',
                  responseSchema: {
                      type: Type.OBJECT,
                      properties: {
                          diagnosis: { type: Type.STRING },
                          risk: { type: Type.STRING, enum: ['Low', 'Medium', 'High'] },
                          dos: { type: Type.ARRAY, items: { type: Type.STRING } },
                          donts: { type: Type.ARRAY, items: { type: Type.STRING } }
                      }
                  }
              }
          });
          if (response.text) {
              return JSON.parse(response.text);
          }
      } catch (e) {
          console.warn("Gemini API call failed, falling back to mock.", e);
      }
  }

  // Fallback Mock
  await new Promise(resolve => setTimeout(resolve, 1500)); 
  const isFreezone = employerType === 'Freezone';
  const specificAdvice = isFreezone 
    ? (lang === 'id' ? `Hubungi departemen tenaga kerja ${freezone || 'Freezone'}` : `Contact the ${freezone || 'Freezone'} labour department`)
    : (lang === 'id' ? "Ajukan keluhan melalui aplikasi MOHRE segera" : "File a complaint via the MOHRE app immediately");

  return {
    diagnosis: `${getMockResponseText(lang, 'diagnosis')} (${issues.join(", ")})`,
    risk: "Medium",
    dos: [
        lang === 'id' ? "Simpan salinan semua korespondensi" : "Keep a copy of all correspondence",
        lang === 'id' ? "Jangan tanda tangani pembatalan visa sebelum dibayar" : "Do not sign any cancellation papers until paid",
        specificAdvice
    ],
    donts: [
        lang === 'id' ? "Mengundurkan diri tanpa pemberitahuan" : "Resign without notice",
        lang === 'id' ? "Terima uang tunai tanpa tanda terima" : "Accept cash without a receipt",
        lang === 'id' ? "Serahkan paspor Anda" : "Hand over your passport"
    ]
  };
};

export const chatWithAI = async (history: ChatMessage[], newMessage: string, caseContext: Case, lang: AppLanguage): Promise<{ text: string; isFlagged: boolean }> => {
  const ai = getAI();
  if (ai) {
      try {
          // Construct chat history for context
          const chatHistoryForPrompt = history.map(h => `${h.role === 'user' ? 'User' : 'Assistant'}: ${h.text}`).join('\n');

          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `Context: You are WorkShield UAE, a helpful labor law assistant.
                Current Case: ${caseContext.title} (${caseContext.employerType})
                Issue: ${caseContext.issueTypes.join(', ')}
                Description: ${caseContext.description}

                Chat History:
                ${chatHistoryForPrompt}
                User: ${newMessage}

                Task: Answer the user's question clearly and safely based on UAE labor law.
                Constraint: Answer strictly in ${lang} language.`,
          });
          return { text: response.text || "Error generating response.", isFlagged: false };
      } catch (e) {
           console.warn("Gemini Chat API failed", e);
      }
  }

  // Fallback Mock
  await new Promise(resolve => setTimeout(resolve, 1000));
  return { 
    text: `${getMockResponseText(lang, 'chat')}\n\n(Context: ${newMessage})`, 
    isFlagged: false 
  };
};

