import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { chatWithAI } from '../services/geminiService';
import { Send, User, Shield, Loader2, Sparkles, MessageCircle } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

const GeneralAssistant: React.FC = () => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);
  const { language, t, dir } = useLanguage();

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    const newHistory = [...messages, userMsg];
    setMessages(newHistory);
    setInput('');
    setLoading(true);

    try {
      const result = await chatWithAI(messages, input, null, language);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: result.text,
        timestamp: Date.now(),
        isFlaggedForReview: result.isFlagged
      };
      setMessages([...newHistory, aiMsg]);
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6 animate-fade-in-up">
      <div className="bg-gradient-to-r from-royal-900 to-royal-700 rounded-3xl p-8 text-white shadow-xl shadow-royal-900/20 relative overflow-hidden">
        <div className="absolute top-0 right-0 w-64 h-64 bg-white opacity-5 rounded-full -mr-20 -mt-20 blur-3xl"></div>
        <div className="relative z-10 flex items-center">
          <div className="bg-white/20 p-3 rounded-2xl mr-4 rtl:mr-0 rtl:ml-4">
             <MessageCircle className="w-8 h-8 text-white" />
          </div>
          <div>
            <h2 className="text-2xl font-extrabold mb-1">General Assistant</h2>
            <p className="text-royal-100 font-medium text-sm">Ask anything about UAE Labour Law</p>
          </div>
        </div>
      </div>

      <div className="flex flex-col h-[550px] bg-white rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden" dir={dir}>
        <div className="flex-grow overflow-y-auto space-y-6 p-6" ref={scrollRef}>
          {messages.length === 0 && (
             <div className="flex flex-col items-center justify-center h-full text-center text-slate-400">
               <div className="bg-royal-50 p-4 rounded-full mb-4">
                   <Sparkles className="w-8 h-8 text-royal-600" />
               </div>
               <p className="font-medium text-slate-600">How can I help you today?</p>
               <p className="text-sm mt-1 max-w-xs mx-auto">Ask about visa rules, gratuity calculation, or general worker rights.</p>

               <div className="grid grid-cols-1 gap-2 mt-6 w-full max-w-xs">
                  <button onClick={() => { setInput("How is gratuity calculated?"); }} className="text-xs bg-slate-50 border border-slate-100 p-3 rounded-xl hover:bg-slate-100 transition text-slate-600">
                    How is gratuity calculated?
                  </button>
                  <button onClick={() => { setInput("Can my employer hold my passport?"); }} className="text-xs bg-slate-50 border border-slate-100 p-3 rounded-xl hover:bg-slate-100 transition text-slate-600">
                    Can my employer hold my passport?
                  </button>
                  <button onClick={() => { setInput("What is the notice period rule?"); }} className="text-xs bg-slate-50 border border-slate-100 p-3 rounded-xl hover:bg-slate-100 transition text-slate-600">
                    What is the notice period rule?
                  </button>
               </div>
             </div>
          )}

          {messages.map((msg) => (
            <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
              <div className={`flex items-end max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>

                <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 mb-1 shadow-sm ${
                  msg.role === 'user' ? 'bg-royal-600 mx-2' : 'bg-white border border-slate-200 mx-2'
                }`}>
                  {msg.role === 'user' ? <User className="w-5 h-5 text-white" /> : <Shield className="w-5 h-5 text-royal-600" />}
                </div>

                <div className="flex flex-col">
                  <div className={`p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${
                    msg.role === 'user' 
                      ? 'bg-royal-600 text-white rounded-br-none rtl:rounded-bl-none rtl:rounded-br-2xl' 
                      : 'bg-slate-50 text-slate-800 rounded-bl-none rtl:rounded-br-none rtl:rounded-bl-2xl border border-slate-100'
                  }`}>
                    <div className="whitespace-pre-wrap">{msg.text}</div>
                  </div>
                  {msg.role === 'model' && (
                    <div className="mt-1.5 pl-1">
                        <p className="text-[10px] text-slate-300">{t('inline_disclaimer')}</p>
                    </div>
                  )}
                </div>
              </div>
            </div>
          ))}

          {loading && (
            <div className="flex justify-start">
               <div className="flex items-center space-x-2 bg-slate-50 rounded-2xl p-4 border border-slate-100">
                 <Loader2 className="w-4 h-4 animate-spin text-royal-600" />
                 <span className="text-xs text-slate-500 font-medium">Consulting Regulations...</span>
               </div>
            </div>
          )}
        </div>

        <div className="p-4 bg-white border-t border-slate-100">
          <div className="flex space-x-2 items-center bg-slate-50 p-2 rounded-2xl border border-slate-200 focus-within:ring-2 focus-within:ring-royal-500/20 focus-within:border-royal-500 transition-all">
            <input
              type="text"
              className="flex-grow bg-transparent px-3 py-2 outline-none text-slate-900 placeholder:text-slate-400"
              placeholder="Type your question..."
              value={input}
              onChange={(e) => setInput(e.target.value)}
              onKeyDown={(e) => e.key === 'Enter' && handleSend()}
              disabled={loading}
            />
            <button
              onClick={handleSend}
              disabled={loading || !input.trim()}
              className="bg-royal-900 text-white p-2.5 rounded-xl hover:bg-royal-800 disabled:bg-slate-300 disabled:text-slate-400 transition shadow-sm"
            >
              <Send className="w-5 h-5 rtl:rotate-180" />
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default GeneralAssistant;

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import CaseList from './components/CaseList';
import NewCaseWizard from './components/NewCaseWizard';
import CaseDetail from './components/CaseDetail';
import KnowledgeBase from './components/KnowledgeBase';
import RightsChecker from './components/RightsChecker';
import GeneralAssistant from './components/GeneralAssistant';
import DisclaimerModal from './components/DisclaimerModal';
import Settings from './components/Settings';
import { Case } from './types';
import { LanguageProvider } from './contexts/LanguageContext';

const AppContent: React.FC = () => {
  const [cases, setCases] = useState<Case[]>([]);
  const [acceptedDisclaimer, setAcceptedDisclaimer] = useState(false);

  // Load from local storage on mount
  useEffect(() => {
    const storedCases = localStorage.getItem('ws_cases');
    if (storedCases) {
      setCases(JSON.parse(storedCases));
    }
    const storedDisclaimer = localStorage.getItem('ws_disclaimer');
    if (storedDisclaimer === 'true') {
      setAcceptedDisclaimer(true);
    }
  }, []);

  // Save to local storage on change
  useEffect(() => {
    localStorage.setItem('ws_cases', JSON.stringify(cases));
  }, [cases]);

  const handleDisclaimerAccept = () => {
    setAcceptedDisclaimer(true);
    localStorage.setItem('ws_disclaimer', 'true');
  };

  const addCase = (newCase: Case) => {
    setCases([newCase, ...cases]);
  };

  const updateCase = (updatedCase: Case) => {
    setCases(cases.map(c => c.id === updatedCase.id ? updatedCase : c));
  };

  const deleteCase = (id: string) => {
    setCases(cases.filter(c => c.id !== id));
  };

  return (
    <HashRouter>
      {!acceptedDisclaimer && <DisclaimerModal onAccept={handleDisclaimerAccept} />}
      <Layout>
        <Routes>
          <Route path="/" element={<CaseList cases={cases} onDelete={deleteCase} />} />
          <Route path="/new" element={<NewCaseWizard onSave={addCase} />} />
          <Route path="/case/:id/*" element={<CaseDetail cases={cases} onUpdate={updateCase} />} />
          <Route path="/knowledge" element={<KnowledgeBase />} />
          <Route path="/rights" element={<RightsChecker />} />
          <Route path="/chat" element={<GeneralAssistant />} />
          <Route path="/settings" element={<Settings />} />
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

const App: React.FC = () => {
  return (
    <LanguageProvider>
      <AppContent />
    </LanguageProvider>
  );
};

export default App;

