import React, { useState } from 'react';
import { Calculator, DollarSign, Calendar, AlertCircle, ChevronLeft } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useLanguage } from '../contexts/LanguageContext';

const GratuityCalculator: React.FC = () => {
  const { t, dir } = useLanguage();
  const [basicSalary, setBasicSalary] = useState<number>(0);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [result, setResult] = useState<number | null>(null);
  const [breakdown, setBreakdown] = useState<string>('');
  const [tenureStr, setTenureStr] = useState('');

  const calculate = () => {
    if (!basicSalary || !startDate || !endDate) return;

    const start = new Date(startDate);
    const end = new Date(endDate);
    const diffTime = Math.abs(end.getTime() - start.getTime());
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    const years = diffDays / 365;

    let gratuity = 0;
    let explanation = '';

    if (years < 1) {
      gratuity = 0;
      explanation = "Less than 1 year of service: No gratuity is entitled.";
    } else if (years <= 5) {
      // 21 days per year
      const dailyBasic = basicSalary * 12 / 365; // Or simple basic/30 is commonly used, usually basic/30
      const dailyWage = basicSalary / 30;
      gratuity = dailyWage * 21 * years;
      explanation = `1-5 Years: 21 days of basic salary per year.\n(${years.toFixed(2)} years × 21 days × AED ${dailyWage.toFixed(2)})`;
    } else {
      // First 5 years at 21 days
      const dailyWage = basicSalary / 30;
      const first5Years = dailyWage * 21 * 5;

      // Excess years at 30 days
      const excessYears = years - 5;
      const subsequentYears = dailyWage * 30 * excessYears;

      gratuity = first5Years + subsequentYears;
      explanation = `First 5 years: 21 days/year.\nSubsequent ${excessYears.toFixed(2)} years: 30 days/year.`;
    }

    // Cap at 2 years salary
    const twoYearsSalary = basicSalary * 24;
    if (gratuity > twoYearsSalary) {
        gratuity = twoYearsSalary;
        explanation += "\n(Capped at 2 years total salary)";
    }

    setResult(gratuity);
    setBreakdown(explanation);
    setTenureStr(`${years.toFixed(2)} Years`);
  };

  return (
    <div className="space-y-6 animate-fade-in-up" dir={dir}>
      <div className="flex items-center space-x-4 mb-2">
        <Link to="/" className="p-2.5 rounded-full bg-white border border-slate-200 text-slate-500 hover:text-royal-900 hover:bg-royal-50 transition shadow-sm">
          <ChevronLeft className="w-5 h-5 rtl:rotate-180" />
        </Link>
        <h1 className="text-2xl font-extrabold text-slate-900 tracking-tight">{t('tool_gratuity')}</h1>
      </div>

      <div className="bg-white rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/50 p-6 md:p-8">

        <div className="bg-emerald-50 border border-emerald-100 rounded-2xl p-4 mb-6 flex items-start">
            <AlertCircle className="w-5 h-5 text-emerald-600 mr-3 mt-0.5 flex-shrink-0" />
            <p className="text-sm text-emerald-800 leading-relaxed">
                Calculated based on the latest UAE Labour Law (Decree-Law No. 33 of 2021). Use your <strong>Basic Salary</strong> only (exclude allowances).
            </p>
        </div>

        <div className="space-y-6">
            <div>
                <label className="block text-sm font-bold text-slate-900 mb-2">{t('calc_basic_salary')}</label>
                <div className="relative">
                    <DollarSign className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                    <input 
                        type="number" 
                        value={basicSalary || ''}
                        onChange={(e) => setBasicSalary(Number(e.target.value))}
                        className="w-full pl-12 p-4 rounded-2xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-royal-500 outline-none transition font-medium text-lg"
                        placeholder="e.g. 5000"
                    />
                </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                    <label className="block text-sm font-bold text-slate-900 mb-2">{t('calc_start_date')}</label>
                    <div className="relative">
                        <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                        <input 
                            type="date"
                            value={startDate}
                            onChange={(e) => setStartDate(e.target.value)}
                            className="w-full pl-12 p-4 rounded-2xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-royal-500 outline-none transition font-medium"
                        />
                    </div>
                </div>
                <div>
                    <label className="block text-sm font-bold text-slate-900 mb-2">{t('calc_end_date')}</label>
                    <div className="relative">
                        <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                        <input 
                            type="date"
                            value={endDate}
                            onChange={(e) => setEndDate(e.target.value)}
                            className="w-full pl-12 p-4 rounded-2xl border border-slate-200 bg-slate-50 focus:bg-white focus:ring-2 focus:ring-royal-500 outline-none transition font-medium"
                        />
                    </div>
                </div>
            </div>

            <button 
                onClick={calculate}
                className="w-full bg-royal-900 text-white font-bold py-5 rounded-2xl shadow-xl shadow-royal-900/20 hover:bg-royal-800 transition transform active:scale-95 flex items-center justify-center"
            >
                <Calculator className="w-5 h-5 mr-2" /> {t('calc_calculate')}
            </button>
        </div>

        {result !== null && (
            <div className="mt-8 pt-8 border-t border-slate-100 animate-fade-in-up">
                <div className="text-center mb-6">
                    <p className="text-slate-400 text-xs font-bold uppercase tracking-wider mb-2">{t('calc_result')}</p>
                    <h2 className="text-4xl font-extrabold text-royal-600">
                        AED {result.toLocaleString('en-AE', { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                    </h2>
                    <p className="text-slate-500 font-medium mt-2">{t('calc_tenure')}: {tenureStr}</p>
                </div>

                <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                    <h4 className="font-bold text-slate-900 text-sm mb-2">Calculation Logic</h4>
                    <p className="text-sm text-slate-600 whitespace-pre-line leading-relaxed">
                        {breakdown}
                    </p>
                </div>
            </div>
        )}

      </div>
    </div>
  );
};

export default GratuityCalculator;

