import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import CaseList from './components/CaseList';
import NewCaseWizard from './components/NewCaseWizard';
import CaseDetail from './components/CaseDetail';
import KnowledgeBase from './components/KnowledgeBase';
import RightsChecker from './components/RightsChecker';
import GeneralAssistant from './components/GeneralAssistant';
import DisclaimerModal from './components/DisclaimerModal';
import Settings from './components/Settings';
import GratuityCalculator from './components/GratuityCalculator';
import { Case } from './types';
import { LanguageProvider } from './contexts/LanguageContext';

const AppContent: React.FC = () => {
  const [cases, setCases] = useState<Case[]>([]);
  const [acceptedDisclaimer, setAcceptedDisclaimer] = useState(false);

  // Load from local storage on mount
  useEffect(() => {
    const storedCases = localStorage.getItem('ws_cases');
    if (storedCases) {
      setCases(JSON.parse(storedCases));
    }
    const storedDisclaimer = localStorage.getItem('ws_disclaimer');
    if (storedDisclaimer === 'true') {
      setAcceptedDisclaimer(true);
    }
  }, []);

  // Save to local storage on change
  useEffect(() => {
    localStorage.setItem('ws_cases', JSON.stringify(cases));
  }, [cases]);

  const handleDisclaimerAccept = () => {
    setAcceptedDisclaimer(true);
    localStorage.setItem('ws_disclaimer', 'true');
  };

  const addCase = (newCase: Case) => {
    setCases([newCase, ...cases]);
  };

  const updateCase = (updatedCase: Case) => {
    setCases(cases.map(c => c.id === updatedCase.id ? updatedCase : c));
  };

  const deleteCase = (id: string) => {
    setCases(cases.filter(c => c.id !== id));
  };

  return (
    <HashRouter>
      {!acceptedDisclaimer && <DisclaimerModal onAccept={handleDisclaimerAccept} />}
      <Layout>
        <Routes>
          <Route path="/" element={<CaseList cases={cases} onDelete={deleteCase} />} />
          <Route path="/new" element={<NewCaseWizard onSave={addCase} />} />
          <Route path="/case/:id/*" element={<CaseDetail cases={cases} onUpdate={updateCase} />} />
          <Route path="/knowledge" element={<KnowledgeBase />} />
          <Route path="/rights" element={<RightsChecker />} />
          <Route path="/chat" element={<GeneralAssistant />} />
          <Route path="/settings" element={<Settings />} />
          <Route path="/gratuity" element={<GratuityCalculator />} />
          <Route path="*" element={<Navigate to="/" />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

const App: React.FC = () => {
  return (
    <LanguageProvider>
      <AppContent />
    </LanguageProvider>
  );
};

export default App;

import React, { useState } from 'react';
import { Calculator, Calendar, AlertCircle, ChevronLeft } from 'lucide-react';
import { Link } from 'react-router-dom';
import { useLanguage } from '../contexts/LanguageContext';

const GratuityCalculator: React.FC = () => {
  const { t, dir } = useLanguage();
  const [basicSalary, setBasicSalary] = useState<number>(0);
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');
  const [result, setResult] = useState<number | null>(null);
  const [breakdown, setBreakdown] = useState<string>('');
  const [tenureStr, setTenureStr] = useState('');

  const calculate = () => {
    if (!basicSalary || !startDate || !endDate) return;

    const start = new Date(startDate);
    const end = new Date(endDate);
    const diffTime = Math.abs(end.getTime() - start.getTime());
    const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));
    const years = diffDays / 365;

    let gratuity = 0;
    let explanation = '';

    if (years < 1) {
      gratuity = 0;
      explanation = "Less than 1 year of service: No gratuity is entitled.";
    } else if (years <= 5) {
      // 21 days per year
      const dailyBasic = basicSalary * 12 / 365; // Or simple basic/30 is commonly used, usually basic/30
      const dailyWage = basicSalary / 30;
      gratuity = dailyWage * 21 * years;
      explanation = `1-5 Years: 21 days of basic salary per year.\n(${years.toFixed(2)} years × 21 days × AED ${dailyWage.toFixed(2)})`;
    } else {
      // First 5 years at 21 days
      const dailyWage = basicSalary / 30;
      const first5Years = dailyWage * 21 * 5;

      // Excess years at 30 days
      const excessYears = years - 5;
      const subsequentYears = dailyWage * 30 * excessYears;

      gratuity = first5Years + subsequentYears;
      explanation = `First 5 years: 21 days/year.\nSubsequent ${excessYears.toFixed(2)} years: 30 days/year.`;
    }

    // Cap at 2 years salary
    const twoYearsSalary = basicSalary * 24;
    if (gratuity > twoYearsSalary) {
        gratuity = twoYearsSalary;
        explanation += "\n(Capped at 2 years total salary)";
    }

    setResult(gratuity);
    setBreakdown(explanation);
    setTenureStr(`${years.toFixed(2)} Years`);
  };

  return (
    <div className="space-y-6 animate-fade-in-up" dir={dir}>
      <div className="flex items-center space-x-4 mb-2">
        <Link to="/" className="p-2.5 rounded-full bg-white border border-slate-200 text-slate-500 hover:text-royal-900 hover:bg-royal-50 transition shadow-sm">
