export const diagnoseCase = async (description: string, issues: string[], employerType: string, freezone: string | undefined, lang: AppLanguage): Promise<{ 
    diagnosis: string; 
    risk: 'Low' | 'Medium' | 'High'; 
    dos: string[]; 
    donts: string[];
    authorityContact?: { name: string, phone: string, email: string, portal: string };
    suggestedEmail?: { subject: string, body: string };
}> => {
  const ai = getAI();
  if (ai) {
      try {
          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `
                SYSTEM INSTRUCTION: ${UAE_LABOUR_LAW_CONTEXT}

                USER CASE DATA:
                - Issues: ${issues.join(', ')}
                - Employer Type: ${employerType} ${freezone ? `(${freezone})` : ''}
                - User Description: "${description}"

                TASK:
                1. Identify the specific jurisdiction (MOHRE Mainland, DMCC, JAFZA, DIFC, etc) and customize the "Next Steps".
                2. Assess risk. "High" if there is coercion, passport holding, fake absconding, or amount > 50k AED unpaid.
                3. Create a strict list of DOs and DONTs.
                4. **CRITICAL**: Provide exact contact details for the authority (Phone, Email) from the database.
                5. **CRITICAL**: Draft a formal inquiry email that the user can send to the Authority (MOHRE/Freezone) to ask for help or file a dispute.

                OUTPUT REQUIREMENT:
                - Respond strictly in ${lang} language.
                - JSON format only.
                - Properties: 
                    diagnosis (summary string), 
                    risk (Low/Medium/High), 
                    dos (array of strings), 
                    donts (array of strings),
                    authorityContact (object with name, phone, email, portal),
                    suggestedEmail (object with subject, body)
              `,
              config: {
                  responseMimeType: 'application/json',
                  responseSchema: {
                      type: Type.OBJECT,
                      properties: {
                          diagnosis: { type: Type.STRING },
                          risk: { type: Type.STRING, enum: ['Low', 'Medium', 'High'] },
                          dos: { type: Type.ARRAY, items: { type: Type.STRING } },
                          donts: { type: Type.ARRAY, items: { type: Type.STRING } },
                          authorityContact: {
                              type: Type.OBJECT,
                              properties: {
                                  name: { type: Type.STRING },
                                  phone: { type: Type.STRING },
                                  email: { type: Type.STRING },
                                  portal: { type: Type.STRING }
                              }
                          },
                          suggestedEmail: {
                              type: Type.OBJECT,
                              properties: {
                                  subject: { type: Type.STRING },
                                  body: { type: Type.STRING }
                              }
                          }
                      }
                  }
              }
          });
          if (response.text) {
              return JSON.parse(response.text);
          }
      } catch (e) {
          console.warn("Gemini API call failed, falling back to mock.", e);
      }
  }

  // Improved Fallback Mock Logic
  await new Promise(resolve => setTimeout(resolve, 1500)); 

  const isFreezone = employerType === 'Freezone';
  const specificAuth = freezone || 'Freezone Authority';

  // Specific mock logic for the user's likely scenario if AI fails
