      try {
          // Construct chat history for context
          const chatHistoryForPrompt = history.map(h => `${h.role === 'user' ? 'User' : 'Assistant'}: ${h.text}`).join('\n');

          const contextText = caseContext 
            ? `Current Case: ${caseContext.title} (${caseContext.employerType} - ${caseContext.freezone || 'Mainland'})\nIssue: ${caseContext.issueTypes.join(', ')}\nDescription: ${caseContext.description}`
            : `Context: General inquiry about UAE labor law. No specific case file selected.`;

          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `
                SYSTEM INSTRUCTION: ${UAE_LABOUR_LAW_CONTEXT}

                CASE CONTEXT:
                ${contextText}

