          });
          return { text: response.text || "Error generating response.", isFlagged: false };
      } catch (e) {
           console.warn("Gemini Chat API failed", e);
      }
  }

  // Fallback Mock
  await new Promise(resolve => setTimeout(resolve, 1000));
  return { 
    text: `${getMockResponseText(lang, 'chat')}\n\n(Context: ${newMessage})`, 
    isFlagged: false 
  };
};

