    return lang === 'id' 
        ? "**Persiapan Pertemuan (Simulasi)**\n\n- Tetap tenang.\n- Siapkan ID Emirates.\n- Nyatakan dengan jelas: 'Saya belum menerima gaji'."
        : "**Meeting Prep (Simulation)**\n\n- Stay calm and professional.\n- Have your Emirates ID ready.\n- Clearly state: 'I have not received salary for X months'.";
}

