import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { ISSUE_TYPES, FREEZONES } from '../constants';
import { diagnoseCase } from '../services/geminiService';
import { Case, EmployerType } from '../types';
import { Loader2, CheckCircle, XCircle, ChevronRight, AlertCircle, Building2, HelpCircle, Phone, Globe, Mail, Copy } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

const generateId = () => Math.random().toString(36).substr(2, 9);

interface Props {
  onSave: (c: Case) => void;
}

const NewCaseWizard: React.FC<Props> = ({ onSave }) => {
  const navigate = useNavigate();
  const { t, language } = useLanguage();
  const [step, setStep] = useState(1);
  const [loading, setLoading] = useState(false);
  const [emailCopied, setEmailCopied] = useState(false);

  const [formData, setFormData] = useState({
    employerType: 'Unknown' as EmployerType,
    freezone: '',
    issues: [] as string[],
    description: '',
    title: ''
  });

  const [aiResult, setAiResult] = useState<{
      diagnosis: string, 
      risk: 'Low' | 'Medium' | 'High', 
      dos: string[], 
      donts: string[],
      authorityContact?: { name: string, phone: string, email: string, portal: string },
      suggestedEmail?: { subject: string, body: string }
  } | null>(null);

  const toggleIssue = (issue: string) => {
    setFormData(prev => ({
      ...prev,
      issues: prev.issues.includes(issue) 
        ? prev.issues.filter(i => i !== issue) 
        : [...prev.issues, issue]
    }));
  };

  const handleDiagnose = async () => {
    if (!formData.description) return;
    setLoading(true);
    try {
      const result = await diagnoseCase(formData.description, formData.issues, formData.employerType, formData.freezone, language);
      setAiResult(result);
      setStep(3);
    } catch (error) {
      console.error(error);
      setStep(3);
    } finally {
      setLoading(false);
    }
  };

  const copyEmail = () => {
      if (aiResult?.suggestedEmail) {
          const text = `Subject: ${aiResult.suggestedEmail.subject}\n\n${aiResult.suggestedEmail.body}`;
          navigator.clipboard.writeText(text);
          setEmailCopied(true);
          setTimeout(() => setEmailCopied(false), 2000);
      }
  }

  const handleSave = () => {
    const newCase: Case = {
      id: generateId(),
      title: formData.title || `Case ${new Date().toLocaleDateString()}`,
      employerType: formData.employerType,
      freezone: formData.employerType === 'Freezone' ? formData.freezone : undefined,
      issueTypes: formData.issues,
      description: formData.description,
      aiDiagnosis: aiResult?.diagnosis,
      riskLevel: aiResult?.risk,
      actionableDos: aiResult?.dos,
      actionableDonts: aiResult?.donts,
      stage: 'Pre-complaint',
      createdAt: new Date().toISOString(),
      evidence: [],
      chatHistory: []
    };
    onSave(newCase);
    navigate(`/case/${newCase.id}`);
  };

  return (
    <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 border border-slate-100 p-6 md:p-8 transition-all duration-500">
      {/* Progress */}
      <div className="mb-8">
        <div className="flex justify-between items-center text-[10px] font-bold uppercase tracking-widest text-slate-300 mb-3">
            <span className={`transition-colors duration-300 ${step >= 1 ? "text-royal-600" : ""}`}>1. Profile</span>
            <span className={`transition-colors duration-300 ${step >= 2 ? "text-royal-600" : ""}`}>2. Situation</span>
            <span className={`transition-colors duration-300 ${step >= 3 ? "text-royal-600" : ""}`}>3. Analysis</span>
        </div>
        <div className="h-2 bg-slate-100 rounded-full overflow-hidden">
            <div 
                className="h-full bg-royal-900 rounded-full transition-all duration-700 ease-in-out shadow-[0_0_10px_rgba(12,74,110,0.3)]"
                style={{ width: `${(step / 3) * 100}%` }}
            />
        </div>
      </div>

      {step === 1 && (
        <div className="space-y-8 animate-fade-in-up">
          <div>
            <label className="block text-sm font-bold text-slate-900 mb-4">{t('label_employer_type')}</label>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              {[
                  { id: 'Mainland', icon: Building2, desc: 'MOHRE Regulated' },
                  { id: 'Freezone', icon: Building2, desc: 'DMCC, JAFZA, etc.' },
                  { id: 'Unknown', icon: HelpCircle, desc: 'Not sure' }
              ].map((type) => (
                <button
                  key={type.id}
                  onClick={() => setFormData({...formData, employerType: type.id as EmployerType, freezone: ''})}
                  className={`relative overflow-hidden group py-5 px-4 rounded-2xl border-2 flex flex-col items-center justify-center text-center transition-all duration-200 ${
                    formData.employerType === type.id 
                      ? 'bg-royal-50 border-royal-600 text-royal-900 shadow-md' 
                      : 'bg-white border-slate-100 text-slate-500 hover:border-slate-300 hover:bg-slate-50'
                  }`}
                >
                  <type.icon className={`w-8 h-8 mb-2 transition-colors duration-200 ${formData.employerType === type.id ? 'text-royal-600' : 'text-slate-300 group-hover:text-slate-400'}`} strokeWidth={1.5} />
                  <span className="font-bold text-sm">{type.id}</span>
                  <span className="text-[10px] mt-1 opacity-60 font-medium">{type.desc}</span>
                  {formData.employerType === type.id && <div className="absolute top-2 right-2 w-2 h-2 bg-royal-600 rounded-full animate-pulse" />}
                </button>
              ))}
            </div>

            {/* Freezone Selector */}
            {formData.employerType === 'Freezone' && (
                <div className="mt-6 animate-fade-in-up">
                    <label className="block text-xs font-bold text-slate-500 mb-2 uppercase tracking-wide">Which Freezone Authority?</label>
                    <select
                        value={formData.freezone}
                        onChange={(e) => setFormData({...formData, freezone: e.target.value})}
                        className="w-full p-4 rounded-2xl border border-slate-200 bg-slate-50 text-slate-900 focus:ring-2 focus:ring-royal-500 focus:border-royal-500 outline-none transition font-medium appearance-none"
                        style={{ backgroundImage: 'none' }} // Custom arrow could be added here
                    >
                        <option value="">Select specific Freezone...</option>
                        {FREEZONES.map(fz => <option key={fz} value={fz}>{fz}</option>)}
                    </select>
                    <p className="text-[10px] text-royal-600 mt-2 ml-1 flex items-center font-medium">
                        <AlertCircle className="w-3 h-3 mr-1" />
                        We'll customize the advice based on this selection.
                    </p>
                </div>
            )}
          </div>

          <div>
            <label className="block text-sm font-bold text-slate-900 mb-4">{t('label_issues')}</label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {ISSUE_TYPES.map(issue => (
                <button
                  key={issue}
                  onClick={() => toggleIssue(issue)}
                  className={`relative text-left rtl:text-right px-5 py-4 rounded-2xl border transition-all duration-200 text-sm font-medium ${
                    formData.issues.includes(issue)
                      ? 'bg-royal-900 text-white border-royal-900 shadow-lg shadow-royal-900/20 transform scale-[1.01]'
                      : 'bg-white border-slate-200 text-slate-600 hover:bg-slate-50 hover:border-slate-300'
                  }`}
                >
                  {issue}
                </button>
              ))}
            </div>
          </div>

          <button 
            disabled={formData.issues.length === 0 || (formData.employerType === 'Freezone' && !formData.freezone)}
            onClick={() => setStep(2)}
            className="w-full bg-royal-600 disabled:bg-slate-200 disabled:text-slate-400 text-white font-bold py-5 rounded-2xl mt-4 hover:bg-royal-700 transition-all shadow-xl shadow-royal-600/20 active:scale-95 flex justify-center items-center"
          >
            Continue <ChevronRight className="w-5 h-5 ml-2 rtl:rotate-180" />
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-fade-in-up">
           <div>
            <label className="block text-sm font-bold text-slate-900 mb-2">Give your case a title</label>
            <input 
              type="text"
              placeholder="e.g. Unpaid Salary 2 Months"
              className="w-full border border-slate-200 rounded-2xl p-5 focus:ring-2 focus:ring-royal-500 focus:border-royal-500 outline-none transition shadow-sm font-medium text-slate-900 placeholder:text-slate-300"
              value={formData.title}
              onChange={e => setFormData({...formData, title: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-900 mb-2">{t('label_desc')}</label>
            <textarea
              className="w-full border border-slate-200 rounded-2xl p-5 h-48 focus:ring-2 focus:ring-royal-500 focus:border-royal-500 outline-none transition resize-none shadow-sm text-slate-900 placeholder:text-slate-300 leading-relaxed"
              placeholder="Start typing..."
              value={formData.description}
              onChange={e => setFormData({...formData, description: e.target.value})}
            ></textarea>
            <div className="flex items-start mt-3 text-xs text-slate-600 bg-slate-50 p-4 rounded-xl border border-slate-100">
                <AlertCircle className="w-4 h-4 mr-2 text-royal-500 flex-shrink-0 mt-0.5" />
                <span className="leading-relaxed">Tip: Include dates, specific amounts owed, and mention if you have a written contract or salary slips. This helps the AI be more accurate.</span>
            </div>
          </div>

          <button 
            onClick={handleDiagnose}
            disabled={loading || !formData.description || !formData.title}
            className="w-full bg-royal-900 disabled:bg-slate-200 text-white font-bold py-5 rounded-2xl flex justify-center items-center shadow-xl shadow-royal-900/20 hover:bg-royal-800 transition-all active:scale-95"
          >
            {loading ? <Loader2 className="animate-spin mr-2" /> : t('btn_analyze')}
          </button>
        </div>
      )}

      {step === 3 && aiResult && (
        <div className="space-y-6 animate-fade-in-up">
          <div className={`p-6 rounded-3xl border shadow-sm ${
            aiResult.risk === 'High' ? 'bg-red-50 border-red-100' : 
            aiResult.risk === 'Medium' ? 'bg-amber-50 border-amber-100' : 'bg-emerald-50 border-emerald-100'
          }`}>
            <h3 className={`font-extrabold text-lg mb-2 flex items-center ${
                 aiResult.risk === 'High' ? 'text-red-900' : 
                 aiResult.risk === 'Medium' ? 'text-amber-900' : 'text-emerald-900'
            }`}>
              {t('app_name')} Assessment: {aiResult.risk}
            </h3>
            <p className="text-slate-800 text-sm leading-relaxed opacity-90">
              {aiResult.diagnosis}
            </p>
          </div>

          {/* New Action Center for Authority Contact */}
          {aiResult.authorityContact && (
              <div className="bg-slate-900 text-white p-6 rounded-3xl shadow-xl shadow-slate-900/20">
                  <div className="flex justify-between items-center mb-4">
                      <div>
                        <h4 className="font-bold text-lg">Contact {aiResult.authorityContact.name}</h4>
                        <p className="text-xs text-slate-400">Direct Official Channels</p>
                      </div>
                      <div className="bg-white/10 p-2 rounded-full"><Building2 className="w-5 h-5"/></div>
                  </div>

                  <div className="grid grid-cols-2 gap-3 mb-4">
                      {aiResult.authorityContact.phone && (
                          <a href={`tel:${aiResult.authorityContact.phone}`} className="flex items-center justify-center p-3 bg-white/10 rounded-xl hover:bg-white/20 transition text-sm font-bold">
                              <Phone className="w-4 h-4 mr-2" /> Call
                          </a>
                      )}
                      {aiResult.authorityContact.portal && (
                           <a href={`https://${aiResult.authorityContact.portal.replace(/^https?:\/\//, '')}`} target="_blank" rel="noreferrer" className="flex items-center justify-center p-3 bg-white/10 rounded-xl hover:bg-white/20 transition text-sm font-bold">
                              <Globe className="w-4 h-4 mr-2" /> Portal
                           </a>
                      )}
                      {aiResult.authorityContact.email && (
                           <a href={`mailto:${aiResult.authorityContact.email}`} className="col-span-2 flex items-center justify-center p-3 bg-white/10 rounded-xl hover:bg-white/20 transition text-sm font-bold">
                              <Mail className="w-4 h-4 mr-2" /> Email: {aiResult.authorityContact.email}
                           </a>
                      )}
                  </div>

                  {aiResult.suggestedEmail && (
                      <div className="bg-slate-800 rounded-xl p-4 border border-slate-700">
                          <div className="flex justify-between items-center mb-2">
                              <span className="text-xs font-bold text-slate-400 uppercase">Draft Inquiry Email</span>
                              <button onClick={copyEmail} className="text-xs flex items-center text-royal-300 hover:text-white transition">
                                  {emailCopied ? <CheckCircle className="w-3 h-3 mr-1"/> : <Copy className="w-3 h-3 mr-1"/>}
                                  {emailCopied ? "Copied" : "Copy Draft"}
                              </button>
                          </div>
                          <p className="text-xs text-slate-300 line-clamp-3 italic">
                              {aiResult.suggestedEmail.body}
                          </p>
                      </div>
                  )}
              </div>
          )}

          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="bg-white p-6 rounded-3xl border border-emerald-100 shadow-sm relative overflow-hidden">
               <div className="absolute top-0 right-0 w-20 h-20 bg-emerald-50 rounded-full -mr-10 -mt-10 blur-xl"></div>
              <h4 className="font-bold text-emerald-700 mb-4 flex items-center relative z-10">
                <CheckCircle className="w-5 h-5 mr-2" /> Immediate Actions
              </h4>
              <ul className="space-y-3 relative z-10">
                {aiResult.dos?.map((rec, i) => (
                  <li key={i} className="text-sm text-slate-700 flex items-start">
                    <span className="mr-2 text-emerald-500 font-bold">•</span> {rec}
                  </li>
                ))}
              </ul>
            </div>

            <div className="bg-white p-6 rounded-3xl border border-red-100 shadow-sm relative overflow-hidden">
              <div className="absolute top-0 right-0 w-20 h-20 bg-red-50 rounded-full -mr-10 -mt-10 blur-xl"></div>
              <h4 className="font-bold text-red-700 mb-4 flex items-center relative z-10">
                <XCircle className="w-5 h-5 mr-2" /> Avoid This
              </h4>
              <ul className="space-y-3 relative z-10">
                {aiResult.donts?.map((rec, i) => (
                  <li key={i} className="text-sm text-slate-700 flex items-start">
                    <span className="mr-2 text-red-500 font-bold">•</span> {rec}
                  </li>
                ))}
              </ul>
            </div>
          </div>

          <button 
            onClick={handleSave}
            className="w-full bg-royal-900 hover:bg-royal-800 text-white font-bold py-5 rounded-2xl shadow-xl shadow-royal-900/20 transition transform active:scale-95"
          >
            {t('btn_save_dashboard')}
          </button>
        </div>
      )}
    </div>
  );
};

export default NewCaseWizard;

