import React, { useState, useRef, useEffect } from 'react';
import { Case, ChatMessage, EvidenceItem } from '../types';
import { chatWithAI, analyzeEvidence } from '../services/geminiService';
import { Send, User, Shield, Loader2, Flag, Paperclip, FileText } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';

interface Props {
  currentCase: Case;
  onUpdate: (c: Case) => void;
}

const ChatInterface: React.FC<Props> = ({ currentCase, onUpdate }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [analyzingFile, setAnalyzingFile] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { language, t, dir } = useLanguage();

  const messages = currentCase.chatHistory || [];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, loading, analyzingFile]);

  const handleSend = async () => {
    if (!input.trim()) return;

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    const newHistory = [...messages, userMsg];

    // Optimistic update
    onUpdate({
      ...currentCase,
      chatHistory: newHistory
    });
    setInput('');
    setLoading(true);

    try {
      const result = await chatWithAI(messages, input, currentCase, language);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: result.text,
        timestamp: Date.now(),
        isFlaggedForReview: result.isFlagged
      };
      onUpdate({
        ...currentCase,
        chatHistory: [...newHistory, aiMsg]
      });
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (!file) return;

      setAnalyzingFile(true);

      const reader = new FileReader();
      reader.onloadend = async () => {
          const base64String = reader.result as string;
          const base64Data = base64String.split(',')[1];

          try {
              // 1. Analyze the file
              const analysis = await analyzeEvidence(base64Data, file.type, language);

              // 2. Create Evidence Item
              const newEvidence: EvidenceItem = {
                  id: Date.now().toString(),
                  type: analysis.type as any || 'Other',
                  description: file.name,
                  summary: analysis.summary,
                  tags: analysis.tags,
                  dateAdded: new Date().toISOString(),
                  analysis: analysis.analysis
              };

              // 3. Update Case with new Evidence (This is crucial for the AI context in the next step)
              const updatedEvidenceList = [newEvidence, ...currentCase.evidence];
              const updatedCaseForAI = {
                  ...currentCase,
                  evidence: updatedEvidenceList
              };

              // 4. Create User Message indicating upload
              const userMsg: ChatMessage = {
                  id: Date.now().toString(),
                  role: 'user',
                  text: `I have uploaded a document: ${file.name}. Please analyze it.`,
                  timestamp: Date.now(),
                  attachments: [{ name: file.name, type: file.type }]
              };

              const newHistory = [...messages, userMsg];

              // Update state immediately to show the uploaded file bubble
              onUpdate({
                  ...updatedCaseForAI,
                  chatHistory: newHistory
              });
              setAnalyzingFile(false); // Stop analyzing spinner, start thinking spinner
              setLoading(true);

              // 5. Trigger AI Chat Response with the UPDATED case context (so it sees the new evidence)
              // We pass the "I uploaded..." text as the prompt. The AI will see the evidence summary in the system prompt.
              const result = await chatWithAI(newHistory, userMsg.text, updatedCaseForAI, language);

              const aiMsg: ChatMessage = {
                  id: (Date.now() + 1).toString(),
                  role: 'model',
                  text: result.text,
                  timestamp: Date.now(),
                  isFlaggedForReview: result.isFlagged
              };

              onUpdate({
                  ...updatedCaseForAI,
                  chatHistory: [...newHistory, aiMsg]
              });

          } catch (error) {
              console.error("Upload/Analysis failed", error);
              alert("Failed to analyze the document.");
              setAnalyzingFile(false);
          } finally {
              setLoading(false);
              // Reset input
              if (fileInputRef.current) fileInputRef.current.value = '';
          }
      };
      reader.readAsDataURL(file);
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden animate-fade-in-up" dir={dir}>
      <div className="flex-grow overflow-y-auto space-y-6 p-6" ref={scrollRef}>
        {messages.length === 0 && (
           <div className="flex flex-col items-center justify-center h-full text-center text-slate-400">
             <div className="bg-royal-50 p-4 rounded-full mb-4">
                 <Shield className="w-8 h-8 text-royal-600" />
             </div>
             <p className="font-medium text-slate-600">I know the details of your case.</p>
             <p className="text-sm mt-1">Ask me specifically about your {currentCase.issueTypes[0]} situation.</p>
           </div>
        )}

        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex items-end max-w-[85%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>

              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 mb-1 shadow-sm ${
                msg.role === 'user' ? 'bg-royal-600 mx-2' : 'bg-white border border-slate-200 mx-2'
              }`}>
                {msg.role === 'user' ? <User className="w-5 h-5 text-white" /> : <Shield className="w-5 h-5 text-royal-600" />}
              </div>

              <div className="flex flex-col">
                <div className={`p-4 rounded-2xl text-sm leading-relaxed shadow-sm ${
                  msg.role === 'user' 
                    ? 'bg-royal-600 text-white rounded-br-none rtl:rounded-bl-none rtl:rounded-br-2xl' 
                    : 'bg-slate-50 text-slate-800 rounded-bl-none rtl:rounded-br-none rtl:rounded-bl-2xl border border-slate-100'
                }`}>
                  <div className="whitespace-pre-wrap">{msg.text}</div>

                  {/* Attachments Display */}
                  {msg.attachments && msg.attachments.length > 0 && (
                      <div className="mt-3 bg-white/20 p-2 rounded-lg flex items-center">
                          <FileText className="w-4 h-4 mr-2" />
                          <span className="text-xs font-bold underline truncate max-w-[150px]">{msg.attachments[0].name}</span>
                      </div>
                  )}
                </div>
                {msg.role === 'model' && (
                  <div className="mt-1.5 pl-1">
                      {msg.isFlaggedForReview && (
                        <div className="flex items-center text-[10px] text-amber-600 mb-1">
                          <Flag className="w-3 h-3 mr-1" /> Uncertain - Please verify
                        </div>
                      )}
                      <p className="text-[10px] text-slate-300">{t('inline_disclaimer')}</p>
                  </div>
                )}
              </div>
            </div>
          </div>
        ))}

        {analyzingFile && (
             <div className="flex justify-end">
                <div className="flex items-center space-x-2 bg-royal-50 rounded-2xl p-4 border border-royal-100">
                    <Loader2 className="w-4 h-4 animate-spin text-royal-600" />
                    <span className="text-xs text-royal-700 font-bold">Scanning Document...</span>
                </div>
             </div>
        )}

        {loading && !analyzingFile && (
          <div className="flex justify-start">
             <div className="flex items-center space-x-2 bg-slate-50 rounded-2xl p-4 border border-slate-100">
               <Loader2 className="w-4 h-4 animate-spin text-royal-600" />
               <span className="text-xs text-slate-500 font-medium">Analyzing UAE regulations...</span>
             </div>
          </div>
        )}
      </div>

      <div className="p-4 bg-white border-t border-slate-100">
        <div className="flex space-x-2 items-center bg-slate-50 p-2 rounded-2xl border border-slate-200 focus-within:ring-2 focus-within:ring-royal-500/20 focus-within:border-royal-500 transition-all">
          <input 
            type="file" 
            ref={fileInputRef}
            className="hidden" 
            onChange={handleFileUpload}
            accept="image/*,.pdf" // Accepting images and PDFs (though logic currently treats as image for simple mock)
          />
          <button 
             onClick={() => fileInputRef.current?.click()}
             className="p-2 text-slate-400 hover:text-royal-600 hover:bg-slate-100 rounded-xl transition"
             disabled={loading || analyzingFile}
             title="Upload Document"
          >
             <Paperclip className="w-5 h-5" />
          </button>

          <input
            type="text"
            className="flex-grow bg-transparent px-3 py-2 outline-none text-slate-900 placeholder:text-slate-400"
            placeholder="Type your question..."
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === 'Enter' && handleSend()}
            disabled={loading || analyzingFile}
          />
          <button
            onClick={handleSend}
            disabled={loading || analyzingFile || !input.trim()}
            className="bg-royal-900 text-white p-2.5 rounded-xl hover:bg-royal-800 disabled:bg-slate-300 disabled:text-slate-400 transition shadow-sm"
          >
            <Send className="w-5 h-5 rtl:rotate-180" />
          </button>
        </div>
      </div>
    </div>
  );
};

export default ChatInterface;

