export const diagnoseCase = async (description: string, issues: string[], employerType: string, freezone: string | undefined, lang: AppLanguage): Promise<{ 
    diagnosis: string; 
    risk: 'Low' | 'Medium' | 'High'; 
    dos: string[]; 
    donts: string[];
    strategicQuestions: string[];
    authorityContact?: { name: string, phone: string, email: string, portal: string };
    suggestedEmail?: { subject: string, body: string };
}> => {
  const ai = getAI();
  if (ai) {
      try {
          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `
                SYSTEM INSTRUCTION: ${UAE_LABOUR_LAW_CONTEXT}

                USER CASE DATA:
                - Issues: ${issues.join(', ')}
                - Employer Type: ${employerType} ${freezone ? `(${freezone})` : ''}
                - User Description: "${description}"

                TASK:
                1. Identify the specific jurisdiction (MOHRE Mainland, DMCC, JAFZA, DIFC, etc) and customize the "Next Steps".
                2. Assess risk. "High" if there is coercion, passport holding, fake absconding, or amount > 50k AED unpaid.
                3. Create a strict list of DOs and DONTs.
                4. **CRITICAL**: Provide exact contact details for the authority (Phone, Email) from the database.
                5. **CRITICAL**: Draft a formal inquiry email that the user can send to the Authority.
                6. **CRITICAL (Strategic Questions)**: Analyze the user's description. If the employer has made claims (e.g., "we paid you", "no money now", "we will ban you"), generate 3-4 specific, hard-hitting questions the employee should ask the employer to demand proof or expose lies.
                   Example: If employer says "We paid", the question should be: "Please provide the WPS Salary Information File (SIF) reference number for this payment."

                OUTPUT REQUIREMENT:
                - Respond strictly in ${lang} language.
                - JSON format only.
                - Properties: 
                    diagnosis (summary string), 
                    risk (Low/Medium/High), 
                    dos (array of strings), 
                    donts (array of strings),
                    strategicQuestions (array of strings - "Questions to ask your employer"),
                    authorityContact (object with name, phone, email, portal),
                    suggestedEmail (object with subject, body)
              `,
              config: {
                  responseMimeType: 'application/json',
                  responseSchema: {
                      type: Type.OBJECT,
                      properties: {
                          diagnosis: { type: Type.STRING },
                          risk: { type: Type.STRING, enum: ['Low', 'Medium', 'High'] },
                          dos: { type: Type.ARRAY, items: { type: Type.STRING } },
                          donts: { type: Type.ARRAY, items: { type: Type.STRING } },
                          strategicQuestions: { type: Type.ARRAY, items: { type: Type.STRING } },
                          authorityContact: {
                              type: Type.OBJECT,
                              properties: {
                                  name: { type: Type.STRING },
                                  phone: { type: Type.STRING },
                                  email: { type: Type.STRING },
                                  portal: { type: Type.STRING }
                              }
                          },
                          suggestedEmail: {
                              type: Type.OBJECT,
                              properties: {
                                  subject: { type: Type.STRING },
                                  body: { type: Type.STRING }
                              }
                          }
                      }
                  }
              }
          });
          if (response.text) {
              return JSON.parse(response.text);
          }
      } catch (e) {
          console.warn("Gemini API call failed, falling back to mock.", e);
      }
  }

  // Improved Fallback Mock Logic
  await new Promise(resolve => setTimeout(resolve, 1500)); 

  const isFreezone = employerType === 'Freezone';
  const specificAuth = freezone || 'Freezone Authority';

  // Specific mock logic for the user's likely scenario if AI fails
  const mockDos = [
      "Keep a copy of all WhatsApp/Email proofs.",
      "Calculate your exact gratuity and unpaid salary.",
      isFreezone 
        ? `Log into the ${specificAuth} portal and search for 'Labour Dispute'.`
        : "Download the MOHRE App and select 'Register Labour Complaint'."
  ];

  const mockDonts = [
      "DO NOT sign the visa cancellation paper if you haven't received cash/transfer.",
      "DO NOT resign if they are forcing you (unless you cite Article 45 for non-payment).",
      "DO NOT accept a cheque as final settlement (high risk of bouncing)."
  ];

  const mockQuestions = [
      "If you state payment has been made, please provide the WPS Reference Number.",
      "Please confirm in writing (email) exactly when the End of Service Benefits will be released.",
      "Can you provide a breakdown of the deduction you are mentioning?"
  ];

  return {
    diagnosis: `${getMockResponseText(lang, 'diagnosis')} (${issues.join(", ")})`,
    risk: "Medium",
    dos: mockDos,
    donts: mockDonts,
    strategicQuestions: mockQuestions,
    authorityContact: {
        name: isFreezone ? specificAuth : "MOHRE",
        phone: isFreezone ? "See Freezone Website" : "600590000",
        email: isFreezone ? "info@freezone.ae" : "ask@mohre.gov.ae",
        portal: isFreezone ? "Portal" : "MOHRE App"
    },
    suggestedEmail: {
        subject: "Urgent: Labour Dispute Inquiry",
        body: "To whom it may concern,\n\nI am writing to file a formal complaint regarding unpaid salary..."
    }
  };
};

export const chatWithAI = async (history: ChatMessage[], newMessage: string, caseContext: Case | null, lang: AppLanguage): Promise<{ text: string; isFlagged: boolean }> => {
  const ai = getAI();
  if (ai) {
      try {
          // Construct chat history for context
          const chatHistoryForPrompt = history.map(h => `${h.role === 'user' ? 'User' : 'Assistant'}: ${h.text}`).join('\n');

          let contextText = "";

          if (caseContext) {
             // Basic Context
             contextText = `Current Case: ${caseContext.title} (${caseContext.employerType} - ${caseContext.freezone || 'Mainland'})\nIssue: ${caseContext.issueTypes.join(', ')}\nDescription: ${caseContext.description}`;

             // EVIDENCE INJECTION: Critical for handling uploads
             if (caseContext.evidence && caseContext.evidence.length > 0) {
                 const evidenceSummaries = caseContext.evidence.map(e => 
                     `[Evidence Type: ${e.type}] - Summary: "${e.summary}" - Extracted Info: ${JSON.stringify(e.analysis)}`
                 ).join('\n');
                 contextText += `\n\nEVIDENCE ANALYZED SO FAR:\n${evidenceSummaries}\n\n(Use this evidence to answer the user's questions or confirm their statements)`;
             }
          } else {
             contextText = `Context: General inquiry about UAE labor law. No specific case file selected.`;
          }

          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `
                SYSTEM INSTRUCTION: ${UAE_LABOUR_LAW_CONTEXT}

                CASE CONTEXT:
                ${contextText}

                CHAT HISTORY:
                ${chatHistoryForPrompt}
                User: ${newMessage}

                TASK: Answer the user's question clearly. If they ask about "where to file", look at the Employer Type in context. If DMCC, say DMCC Portal. If Mainland, say MOHRE.
                Constraint: Answer strictly in ${lang} language.`,
          });
          return { text: response.text || "Error generating response.", isFlagged: false };
      } catch (e) {
           console.warn("Gemini Chat API failed", e);
      }
  }

  // Fallback Mock
  await new Promise(resolve => setTimeout(resolve, 1000));
  return { 
    text: `${getMockResponseText(lang, 'chat')}\n\n(Context: ${newMessage})`, 
    isFlagged: false 
  };
};

