import React, { useState } from 'react';
import { analyzeOfferLetter } from '../services/geminiService';
import { OfferAnalysisResult } from '../types';
import { useLanguage } from '../contexts/LanguageContext';
import { Link } from 'react-router-dom';
import { ChevronLeft, Upload, Loader2, Shield, CheckCircle, AlertTriangle, Building2, TrendingUp } from 'lucide-react';

const OfferAnalyzer: React.FC = () => {
    const { t, language, dir } = useLanguage();
    const [analyzing, setAnalyzing] = useState(false);
    const [result, setResult] = useState<OfferAnalysisResult | null>(null);

    const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file) return;

        setAnalyzing(true);
        const reader = new FileReader();
        reader.onloadend = async () => {
            const base64String = reader.result as string;
            const base64Data = base64String.split(',')[1];
            try {
                const data = await analyzeOfferLetter(base64Data, file.type, language);
                setResult(data);
            } catch (error) {
                console.error(error);
                alert("Failed to analyze.");
            } finally {
                setAnalyzing(false);
            }
        };
        reader.readAsDataURL(file);
    };

    return (
        <div className="space-y-6 animate-fade-in-up" dir={dir}>
            <div className="flex items-center space-x-4 mb-2">
                <Link to="/" className="p-2.5 rounded-full bg-white border border-slate-200 text-slate-500 hover:text-royal-900 hover:bg-royal-50 transition shadow-sm">
                    <ChevronLeft className="w-5 h-5 rtl:rotate-180" />
                </Link>
                <h1 className="text-2xl font-extrabold text-slate-900 tracking-tight">{t('tool_offer')}</h1>
            </div>

            {!result && (
                <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/50 text-center py-12">
                    <div className="bg-royal-50 p-4 rounded-full inline-block mb-4">
                        <Building2 className="w-10 h-10 text-royal-600" />
                    </div>
                    <h2 className="text-xl font-bold text-slate-900 mb-2">{t('offer_upload_title')}</h2>
                    <p className="text-slate-500 text-sm max-w-sm mx-auto mb-8">
                        Upload your offer letter (PDF/Image). We will check the salary, red flags, and estimate the company's health/reputation.
