          promises: ["'We will pay 50% next week.'"],
          inconsistencies: ["HR says payment next week, but Contract says 1st of month.", "Claimed 'bank issue' but other colleagues got paid."],
          redFlags: ["Asking you to sign cancellation paper before receiving the cheque."]
