          promises: ["'سندفع 50% الأسبوع القادم.'"],
          inconsistencies: ["الموارد البشرية تقول الدفع الأسبوع القادم بينما العقد ينص على الأول من الشهر."],
          redFlags: ["طلب التوقيع على الإلغاء قبل استلام الشيك."]
