                  <span className="font-bold text-sm">{type.id}</span>
                  <span className="text-[10px] mt-1 opacity-60 font-medium">{type.desc}</span>
                  {formData.employerType === type.id && <div className="absolute top-2 right-2 w-2 h-2 bg-royal-600 rounded-full animate-pulse" />}
                </button>
              ))}
            </div>

            {/* Freezone Selector */}
            {formData.employerType === 'Freezone' && (
                <div className="mt-6 animate-fade-in-up">
                    <label className="block text-xs font-bold text-slate-500 mb-2 uppercase tracking-wide">Which Freezone Authority?</label>
