          </div>

          <div>
            <label className="block text-sm font-bold text-slate-900 mb-4">{t('label_issues')}</label>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              {ISSUE_TYPES.map(issue => (
