                >
                  {issue}
                </button>
              ))}
            </div>
          </div>

          <button 
            disabled={formData.issues.length === 0 || (formData.employerType === 'Freezone' && !formData.freezone)}
            onClick={() => setStep(2)}
            className="w-full bg-royal-600 disabled:bg-slate-200 disabled:text-slate-400 text-white font-bold py-5 rounded-2xl mt-4 hover:bg-royal-700 transition-all shadow-xl shadow-royal-600/20 active:scale-95 flex justify-center items-center"
          >
            Continue <ChevronRight className="w-5 h-5 ml-2 rtl:rotate-180" />
          </button>
        </div>
      )}

      {step === 2 && (
        <div className="space-y-6 animate-fade-in-up">
           <div>
            <label className="block text-sm font-bold text-slate-900 mb-2">Give your case a title</label>
            <input 
