              value={formData.title}
              onChange={e => setFormData({...formData, title: e.target.value})}
            />
          </div>
          <div>
            <label className="block text-sm font-bold text-slate-900 mb-2">{t('label_desc')}</label>
            <textarea
              className="w-full border border-slate-200 rounded-2xl p-5 h-48 focus:ring-2 focus:ring-royal-500 focus:border-royal-500 outline-none transition resize-none shadow-sm text-slate-900 placeholder:text-slate-300 leading-relaxed"
              placeholder="Start typing..."
              value={formData.description}
              onChange={e => setFormData({...formData, description: e.target.value})}
            ></textarea>
            <div className="flex items-start mt-3 text-xs text-slate-600 bg-slate-50 p-4 rounded-xl border border-slate-100">
