              {t('app_name')} Assessment: {aiResult.risk}
            </h3>
            <p className="text-slate-800 text-sm leading-relaxed opacity-90">
              {aiResult.diagnosis}
            </p>
          </div>

          {/* Strategic Questions - PREMIUM GATE */}
          {aiResult.strategicQuestions && aiResult.strategicQuestions.length > 0 && (
             <div className="bg-gradient-to-br from-indigo-50 to-blue-50 p-6 rounded-3xl border border-indigo-100 shadow-sm relative overflow-hidden">
                <div className="absolute top-0 right-0 w-24 h-24 bg-indigo-100 rounded-full -mr-12 -mt-12 blur-2xl opacity-50"></div>
                <h4 className="font-bold text-indigo-900 mb-4 flex items-center relative z-10">
