          }`}>
            <h3 className={`font-extrabold text-lg mb-2 flex items-center ${
                 aiResult.risk === 'High' ? 'text-red-900' : 
                 aiResult.risk === 'Medium' ? 'text-amber-900' : 'text-emerald-900'
