                   <MessageSquare className="w-5 h-5 mr-2" /> Challenge Them {isPremium && <span className="ml-2 text-[10px] bg-royal-200 px-2 py-0.5 rounded-full text-royal-800">PRO</span>}
                </h4>

                {isPremium ? (
