const STORAGE_KEY = "wg_license_status";

// 1. CONFIGURATION
// Replace this with your actual WordPress Site URL
const WP_SITE_URL = "https://your-wordpress-site.com"; 

// 2. DEMO CODES (Keep these for your own testing, remove in production)
const DEMO_CODES = ["WG-DEMO-TEST", "ADMIN-OVERRIDE"];

export const PaymentService = {
  // 1. Check status
  isPremium: (): boolean => {
    return localStorage.getItem(STORAGE_KEY) === 'active';
  },

  // 2. Get the Payment Link (Your WordPress Product Page)
  getPaymentLink: (): string => {
    return `${WP_SITE_URL}/product/wageguard-premium-license`; 
  },

  // 3. Validate the code entered by the user
  activateLicense: async (code: string): Promise<boolean> => {
    const normalizedCode = code.trim();

    // A. Check Demo Codes first (Instant success for testing)
    if (DEMO_CODES.includes(normalizedCode.toUpperCase())) {
        localStorage.setItem(STORAGE_KEY, 'active');
        return true;
    }

    // B. Call Real WordPress API
    // This assumes you have an endpoint that accepts ?license_key=XYZ and returns { success: true }
    // Many plugins like "License Manager for WooCommerce" provide this.
    try {
        // Example Endpoint: Change this path based on your WordPress plugin documentation
        const response = await fetch(`${WP_SITE_URL}/wp-json/lmfwc/v2/licenses/validate/${normalizedCode}?consumer_key=ck_XXX&consumer_secret=cs_XXX`, {
            method: 'GET', // or POST depending on plugin
            headers: {
                'Content-Type': 'application/json'
            }
        });

        // Parse JSON response
        const data = await response.json();

        // Check logic (Adjust based on what your API returns)
        // Common pattern: data.success === true or data.status === 'active'
        if (data.success === true || data.status === 'active') {
            localStorage.setItem(STORAGE_KEY, 'active');
            return true;
        } else {
            return false;
        }

    } catch (error) {
        console.error("License Validation Error:", error);
        // If API fails (network error), we return false so we don't accidentally unlock
        return false;
    }
  },

  // 4. Restore
  restorePurchases: async (): Promise<boolean> => {
     return localStorage.getItem(STORAGE_KEY) === 'active';
  },

  // 5. Purchase Subscription
  purchaseSubscription: async (): Promise<boolean> => {
     if (typeof window !== 'undefined') {
         window.open(`${WP_SITE_URL}/product/wageguard-premium-license`, '_blank');
     }
     return false; 
  },

  // 6. Debug
  reset: () => {
    localStorage.removeItem(STORAGE_KEY);
  }
};

