            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    { inlineData: { mimeType: mimeType, data: base64Data } },
                    { text: `Analyze this image/document for a UAE labour dispute. 
                      Extract specific excerpts or key facts into these critical categories:
                      1. Threats: Intimidation, threats of bans, absconding reports, or police cases.
                      2. Admissions: Employer explicitly admits they owe money or haven't paid.
                      3. Promises: Employer promises to pay on specific dates.
                      4. Inconsistencies: Contradictions (e.g., HR says one thing, contract says another).
                      5. Red Flags: Illegal clauses, asking to sign 'cancellation' before payment.

                      For each point, try to extract the direct quote or specific detail if possible.
                      Summarize the document content briefly.` 
                    }
                ]
            },
            config: {
