import { defineConfig } from 'vite';
import react from '@vitejs/plugin-react';

export default defineConfig({
  plugins: [react()],
  build: {
    outDir: 'dist',
  },
  define: {
    // Map process.env to window.process.env for runtime injection compatibility
    'process.env': 'window.process.env'
  }
});

import express from 'express';
import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const app = express();
const PORT = process.env.PORT || 8080;

// Serve static files from the dist directory
app.use(express.static(path.join(__dirname, 'dist')));

// Handle all other routes by serving index.html with environment variable injection
app.get('*', (req, res) => {
  const indexPath = path.join(__dirname, 'dist', 'index.html');

  fs.readFile(indexPath, 'utf8', (err, data) => {
    if (err) {
      console.error('Error reading index.html:', err);
      return res.status(500).send('Internal Server Error');
    }

    // Inject API Key from runtime environment
    // We look for the placeholder in index.html and replace it
    const apiKey = process.env.API_KEY || '';
    const result = data.replace(
      "window.process = { env: { API_KEY: '' } };",
      `window.process = { env: { API_KEY: '${apiKey}' } };`
    );

    res.send(result);
  });
});

app.listen(PORT, '0.0.0.0', () => {
  console.log(`Server is running on port ${PORT}`);
});

