// This service manages the "Pay & Activate" flow.

const STORAGE_KEY = "wg_license_status";

// 1. CONFIGURATION
const WP_SITE_URL = "https://epictcgvault.com"; 
// ⚠️ REPLACE THESE WITH YOUR ACTUAL KEYS FROM WORDPRESS ⚠️
const CONSUMER_KEY = "YOUR_CONSUMER_KEY_HERE"; 
const CONSUMER_SECRET = "YOUR_CONSUMER_SECRET_HERE";

// 2. DEMO CODES (Keep these for your own testing, remove in production)
const DEMO_CODES = ["WG-DEMO-TEST", "ADMIN-OVERRIDE"];

export const PaymentService = {
  // 1. Check status
  isPremium: (): boolean => {
    return localStorage.getItem(STORAGE_KEY) === 'active';
  },

  // 2. Get the Payment Link
  getPaymentLink: (): string => {
    return "https://epictcgvault.com/product/wageguard-premium-subscription-1-month/"; 
  },

  // 3. Validate the code entered by the user
  activateLicense: async (code: string): Promise<boolean> => {
    const normalizedCode = code.trim();

    // A. Check Demo Codes first (Instant success for testing)
    if (DEMO_CODES.includes(normalizedCode.toUpperCase())) {
        localStorage.setItem(STORAGE_KEY, 'active');
        return true;
    }

    // B. Call Real WordPress API (License Manager for WooCommerce)
    try {
        // Construct Basic Auth Header
        const authHeader = 'Basic ' + btoa(`${CONSUMER_KEY}:${CONSUMER_SECRET}`);

        const response = await fetch(`${WP_SITE_URL}/wp-json/lmfwc/v2/licenses/activate/${normalizedCode}`, {
            method: 'GET',
            headers: {
                'Authorization': authHeader,
                'Content-Type': 'application/json'
            }
        });

        // Parse JSON response
        const data = await response.json();

        // Check logic: The plugin returns success: true inside the data object or at root
        if (data.success === true || data.data?.success === true) {
            localStorage.setItem(STORAGE_KEY, 'active');
            return true;
        } else {
            return false;
        }

    } catch (error) {
        console.error("License Validation Error:", error);
        return false;
    }
  },

  // 4. Restore
  restorePurchases: async (): Promise<boolean> => {
     return localStorage.getItem(STORAGE_KEY) === 'active';
  },

  // 5. Purchase Subscription
  purchaseSubscription: async (): Promise<boolean> => {
     if (typeof window !== 'undefined') {
         window.open("https://epictcgvault.com/product/wageguard-premium-subscription-1-month/", '_blank');
     }
     return false; 
  },

  // 6. Debug
  reset: () => {
    localStorage.removeItem(STORAGE_KEY);
  }
};

