    const [formData, setFormData] = useState({
        name: '',
        email: '',
        phone: ''
    });

    if (!showPaywall) return null;

    const handleCheckoutSubmit = (e: React.FormEvent) => {
        e.preventDefault();
        // Here you would typically send this data to your backend.
        // For now, we simulate capturing it and redirect.

        // Construct basic analytics or tracking if needed here
        console.log("User initiating payment:", formData);

        // Open Ziina
        window.open(PaymentService.getPaymentLink(), '_blank');

        // Switch to activation view
        setView('activation');
    };

    const handleActivate = async () => {
        if (!code) return;
        setIsLoading(true);
        setError('');

        // Small delay to simulate network check (improves UX)
        await new Promise(r => setTimeout(r, 800));

        const success = await PaymentService.activateLicense(code);

        if (success) {
            window.location.reload(); 
        } else {
            setError('Invalid license key. Please check the code sent to your email.');
            setIsLoading(false);
        }
    };

    return (
