                                    <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-slate-400" />
                                    <input 
                                        required
                                        type="email" 
                                        className="w-full pl-12 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-royal-500 outline-none font-medium"
                                        placeholder="john@example.com"
                                        value={formData.email}
                                        onChange={e => setFormData({...formData, email: e.target.value})}
                                    />
                                </div>
                                <p className="text-[10px] text-amber-600 mt-1 ml-1 font-medium">
                                    * Key will be sent to this email.
                                </p>
                            </div>
                            <div>
