// This service manages the "Pay & Activate" flow.

const STORAGE_KEY = "wg_license_status";
const ZIINA_URL = "https://pay.ziina.com/ChiChi27/KfLxzYEVC";

// --- LICENSE KEY SYSTEM CONFIGURATION ---
// We use a local hash algorithm to verify keys offline.
// Format: WG-{RANDOM_4_CHARS}-{CHECKSUM_4_CHARS}
const KEY_PREFIX = "WG-";
const SALT = "WAGEGUARD_SECURE_2024_UAE"; // Secret salt for hash generation

// Simple hash function for checksum (Fowler-Noll-Vo variant for short strings)
const simpleHash = (str: string): string => {
    let hash = 0x811c9dc5;
    for (let i = 0; i < str.length; i++) {
        hash ^= str.charCodeAt(i);
        hash = Math.imul(hash, 0x01000193);
    }
    // Convert to hex and take last 4 chars
    return (hash >>> 0).toString(16).toUpperCase().slice(-4).padStart(4, '0');
};

/**
 * --- ADMIN TOOL: HOW TO GENERATE KEYS ---
 * 
 * Since we don't have a backend database connected, we use this algorithm.
 * You (the admin) can generate valid keys for your users manually.
 * 
 * 1. Pick any 4 random characters (e.g., "ABCD", "USER", "JANE").
 * 2. The key will be: WG-{RANDOM}-{HASH}
 * 
 * TO GENERATE A KEY IN BROWSER CONSOLE:
 * Run this function: PaymentService.adminGenerateKey("ANY4")
 * Example: PaymentService.adminGenerateKey("A1B2") might output "WG-A1B2-9F3A"
 * Send "WG-A1B2-9F3A" to the user. They enter it, and it works.
 */

export const PaymentService = {
  // 1. Check status
  isPremium: (): boolean => {
    return localStorage.getItem(STORAGE_KEY) === 'active';
  },

  // 2. Get the Payment Link
  getPaymentLink: (): string => {
    return ZIINA_URL; 
  },

  // 3. Validate the code entered by the user
  activateLicense: async (code: string): Promise<boolean> => {
    const normalizedCode = code.trim().toUpperCase();

    // Demo Override for Testing
    if (normalizedCode === "WG-DEMO-TEST") {
        localStorage.setItem(STORAGE_KEY, 'active');
        return true;
    }

    // Validation Logic
    // 1. Check Prefix
    if (!normalizedCode.startsWith(KEY_PREFIX)) return false;

    // 2. Split parts: WG - {RANDOM} - {CHECKSUM}
    const parts = normalizedCode.split('-');
    if (parts.length !== 3) return false;

    const randomPart = parts[1];
    const userChecksum = parts[2];

    // 3. Verify Checksum
    // We recreate the hash using the random part + our secret salt
    const calculatedChecksum = simpleHash(randomPart + SALT);

    if (userChecksum === calculatedChecksum) {
        localStorage.setItem(STORAGE_KEY, 'active');
        return true;
    }

    return false;
  },

  // 4. Restore
  restorePurchases: async (): Promise<boolean> => {
     return localStorage.getItem(STORAGE_KEY) === 'active';
  },

  // 5. Purchase Subscription
  purchaseSubscription: async (): Promise<boolean> => {
     if (typeof window !== 'undefined') {
         window.open(ZIINA_URL, '_blank');
     }
     return false; 
  },

  // 6. Debug / Admin Helper
  // Admin can use this to generate keys to email to users
  adminGenerateKey: (random4Chars: string) => {
      const r = random4Chars.toUpperCase().slice(0, 4);
      const checksum = simpleHash(r + SALT);
      const fullKey = `${KEY_PREFIX}${r}-${checksum}`;
      console.log(`%c GENERATED KEY: ${fullKey} `, 'background: #222; color: #bada55; font-size: 16px; padding: 4px;');
      return fullKey;
  },

  reset: () => {
    localStorage.removeItem(STORAGE_KEY);
  }
};

// Expose to window for Admin use in console
if (typeof window !== 'undefined') {
    (window as any).GenerateLicense = PaymentService.adminGenerateKey;
    console.log("Admin Tool Loaded: Type GenerateLicense('ABCD') to create a key.");
}

