export const chatWithAI = async (history: ChatMessage[], newMessage: string, caseContext: Case | null, lang: AppLanguage): Promise<{ text: string; isFlagged: boolean }> => {
  const ai = getAI();
  if (ai) {
      try {
          // Construct chat history for context
          const chatHistoryForPrompt = history.map(h => `${h.role === 'user' ? 'User' : 'Assistant'}: ${h.text}`).join('\n');

          let contextText = "";

          if (caseContext) {
             // Basic Context
             contextText = `Current Case: ${caseContext.title} (${caseContext.employerType} - ${caseContext.freezone || 'Mainland'})\nIssue: ${caseContext.issueTypes.join(', ')}\nDescription: ${caseContext.description}`;

             // EVIDENCE INJECTION: Critical for handling uploads
             if (caseContext.evidence && caseContext.evidence.length > 0) {
                 const evidenceSummaries = caseContext.evidence.map(e => 
                     `[Evidence Type: ${e.type}] - Summary: "${e.summary}" - Extracted Info: ${JSON.stringify(e.analysis)}`
                 ).join('\n');
                 contextText += `\n\nEVIDENCE ANALYZED SO FAR:\n${evidenceSummaries}\n\n(Use this evidence to answer the user's questions or confirm their statements)`;
             }
          } else {
             contextText = `Context: General inquiry about UAE labor law. No specific case file selected.`;
          }

          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `
                SYSTEM INSTRUCTION: ${UAE_LABOUR_LAW_CONTEXT}

                CASE CONTEXT:
                ${contextText}

                CHAT HISTORY:
                ${chatHistoryForPrompt}
                User: ${newMessage}

                TASK: Answer the user's question clearly. If they ask about "where to file", look at the Employer Type in context. If DMCC, say DMCC Portal. If Mainland, say MOHRE.
                Constraint: Answer strictly in ${lang} language.`,
          });
          return { text: response.text || "Error generating response.", isFlagged: false };
      } catch (e) {
           console.warn("Gemini Chat API failed", e);
      }
  }

  // Fallback Mock
  await new Promise(resolve => setTimeout(resolve, 1000));
  return { 
    text: `${getMockResponseText(lang, 'chat')}\n\n(Context: ${newMessage})`, 
    isFlagged: false 
  };
};

export const analyzeEvidence = async (base64Data: string, mimeType: string, lang: AppLanguage): Promise<{ type: string; summary: string; tags: string[]; analysis: EvidenceItem['analysis'] }> => {
  const ai = getAI();
  if (ai) {
    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: {
                parts: [
                    { inlineData: { mimeType: mimeType, data: base64Data } },
                    { text: `Analyze this image/document for a UAE labour dispute. 
                      Extract specific excerpts or key facts into these critical categories:
                      1. Threats: Intimidation, threats of bans, absconding reports, or police cases.
                      2. Admissions: Employer explicitly admits they owe money or haven't paid.
                      3. Promises: Employer promises to pay on specific dates.
                      4. Inconsistencies: Contradictions (e.g., HR says one thing, contract says another).
                      5. Red Flags: Illegal clauses, asking to sign 'cancellation' before payment.

                      For each point, try to extract the direct quote or specific detail if possible.
                      Summarize the document content briefly.` 
                    }
                ]
            },
            config: {
                responseMimeType: 'application/json',
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        type: { type: Type.STRING, enum: ['Communication', 'Contract', 'Payment Proof', 'Other'] },
                        summary: { type: Type.STRING },
                        tags: { type: Type.ARRAY, items: { type: Type.STRING } },
                        analysis: {
                            type: Type.OBJECT,
                            properties: {
                                threats: { type: Type.ARRAY, items: { type: Type.STRING } },
                                admissions: { type: Type.ARRAY, items: { type: Type.STRING } },
                                promises: { type: Type.ARRAY, items: { type: Type.STRING } },
                                inconsistencies: { type: Type.ARRAY, items: { type: Type.STRING } },
                                redFlags: { type: Type.ARRAY, items: { type: Type.STRING } }
                            }
                        }
                    }
                }
            }
        });
        if (response.text) return JSON.parse(response.text);
    } catch (e) { console.warn("Gemini Vision API failed", e); }
  }

  // Fallback Mock with enhanced categories
  console.log("Mock Analyze called");
  await new Promise(resolve => setTimeout(resolve, 2000));

  const mockAnalysis = {
      en: { 
          summary: "WhatsApp chat screenshot where HR discusses the delayed salary payment.",
          threats: ["'If you complain to MOHRE, we will ban you.' (Direct Threat)"], 
          admissions: ["'Yes, we know we owe you 2 months salary.' (Admission of Debt)"],
          promises: ["'We will pay 50% next week.'"],
          inconsistencies: ["HR claims 'bank issue' but other colleagues were paid."],
          redFlags: ["Asking you to sign cancellation paper before receiving the cheque."]
      },
      ar: {
          summary: "لقطة شاشة لمحادثة واتساب تناقش فيها الموارد البشرية تأخر الراتب.",
          threats: ["'إذا اشتكيت للوزارة، سنسوي لك حرمان.'"], 
          admissions: ["'نعلم أننا مدينون لك براتب شهرين.'"],
          promises: ["'سندفع 50% الأسبوع القادم.'"],
          inconsistencies: ["الموارد البشرية تقول الدفع الأسبوع القادم بينما العقد ينص على الأول من الشهر."],
          redFlags: ["طلب التوقيع على الإلغاء قبل استلام الشيك."]
      }
  };

  const localized = mockAnalysis[lang as keyof typeof mockAnalysis] || mockAnalysis['en'];

  return { 
    type: "Communication", 
    summary: localized.summary, 
    tags: ["Evidence", "WhatsApp", "High Priority"],
    analysis: {
        threats: localized.threats,
        admissions: localized.admissions,
        promises: localized.promises,
        inconsistencies: localized.inconsistencies,
        redFlags: localized.redFlags
    }
  };
};

export const analyzeOfferLetter = async (base64Data: string, mimeType: string, lang: AppLanguage): Promise<OfferAnalysisResult> => {
    const ai = getAI();
    if (ai) {
        try {
            // Using gemini-2.0-flash-exp (or stable flash) for reliable multimodal analysis
            // Schema validation often fails on complex docs, so we use pure JSON generation
            const response = await ai.models.generateContent({
                model: 'gemini-2.0-flash-exp', 
                contents: {
                    parts: [
                        {
                            inlineData: {
                                mimeType: mimeType,
                                data: base64Data
                            }
                        },
                        {
                            text: `Analyze this UAE Offer Letter / Employment Contract. 
                            1. Extract Company Name, Role, and Salary.
                            2. Evaluate the "Trust Score" (0-100) based on:
                               - Clarity of terms (compliance with UAE Law Decree 33).
                               - Any illegal clauses (e.g. "visa cost deduction", "ban if resignation").
                               - Reputation Check: Based on your general knowledge of this company (if famous) or the professionalism of this document.
                            3. Identify Red Flags (Bad) and Green Flags (Good).
                            4. Summarize the reputation/health.

                            Return strictly JSON in the following format:
                            {
                                "companyName": "string",
                                "role": "string",
                                "salary": "string",
                                "trustScore": number,
                                "trustRationale": "string",
                                "redFlags": ["string"],
                                "greenFlags": ["string"],
                                "reputationSummary": "string"
                            }`
                        }
                    ]
                },
                config: {
                    responseMimeType: 'application/json'
                    // removed strict schema to allow model flexibility in extracting messy text
                }
            });
            if (response.text) return JSON.parse(response.text);
        } catch (e) { console.error("Analyze Offer Failed:", e); }
    }

    // ERROR STATE: Return clear error message so user knows API failed
    await new Promise(resolve => setTimeout(resolve, 1000));
    return {
        companyName: "Analysis Failed",
        role: "Please check internet or API Key",
        salary: "0",
        trustScore: 0,
        trustRationale: "We could not process this document. It might be blurry or the AI service is unreachable.",
        redFlags: ["API Connection Error"],
        greenFlags: [],
        reputationSummary: "Please try uploading a clearer image or PDF."
    };
};

