export const generateRoadmap = async (caseContext: Case): Promise<RoadmapTask[]> => {
    const ai = getAI();
    if (ai) {
        try {
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `
                  SYSTEM INSTRUCTION: ${UAE_LABOUR_LAW_CONTEXT}

                  CASE CONTEXT:
                  Title: ${caseContext.title}
                  Issues: ${caseContext.issueTypes.join(', ')}
                  Employer: ${caseContext.employerType} ${caseContext.freezone || ''}
                  Desc: ${caseContext.description}

                  TASK: Generate a 5-step roadmap (To-Do list) for the employee to resolve this case.
                  Categories: 'Document', 'Action', 'Official'.
                  Return JSON.
                `,
                config: {
                    responseMimeType: 'application/json',
                    responseSchema: {
                        type: Type.ARRAY,
                        items: {
                            type: Type.OBJECT,
                            properties: {
                                title: { type: Type.STRING },
                                description: { type: Type.STRING },
                                category: { type: Type.STRING, enum: ['Document', 'Action', 'Official'] }
                            }
                        }
                    }
                }
            });
            if (response.text) {
                const rawTasks = JSON.parse(response.text);
                return rawTasks.map((t: any, i: number) => ({
                    id: Date.now().toString() + i,
                    isCompleted: false,
                    title: t.title,
                    description: t.description,
                    category: t.category
                }));
            }
        } catch (e) {
            console.error(e);
        }
    }

    await new Promise(resolve => setTimeout(resolve, 1000));
    return [
        { id: '1', title: 'Upload Employment Contract', description: 'We need this to verify your salary.', isCompleted: false, category: 'Document' },
        { id: '2', title: 'Save WhatsApp Chats', description: 'Export chats with HR as evidence.', isCompleted: false, category: 'Action' }
