export const chatWithAI = async (history: ChatMessage[], newMessage: string, caseContext: Case | null, lang: AppLanguage): Promise<{ text: string; isFlagged: boolean }> => {
  const ai = getAI();
  if (ai) {
      try {
          // Construct chat history for context
          const chatHistoryForPrompt = history.map(h => `${h.role === 'user' ? 'User' : 'Assistant'}: ${h.text}`).join('\n');

          let contextText = "";

          if (caseContext) {
             // Basic Context
             contextText = `Current Case: ${caseContext.title} (${caseContext.employerType} - ${caseContext.freezone || 'Mainland'})\nIssue: ${caseContext.issueTypes.join(', ')}\nDescription: ${caseContext.description}`;

             // EVIDENCE INJECTION: Critical for handling uploads
             if (caseContext.evidence && caseContext.evidence.length > 0) {
                 const evidenceSummaries = caseContext.evidence.map(e => 
                     `[Evidence Type: ${e.type}] - Summary: "${e.summary}" - Extracted Info: ${JSON.stringify(e.analysis)}`
                 ).join('\n');
                 contextText += `\n\nEVIDENCE ANALYZED SO FAR:\n${evidenceSummaries}\n\n(Use this evidence to answer the user's questions or confirm their statements)`;
             }
          } else {
             contextText = `Context: General inquiry about UAE labor law. No specific case file selected.`;
          }

          const response = await ai.models.generateContent({
              model: 'gemini-3-flash-preview',
              contents: `
                SYSTEM INSTRUCTION: ${UAE_LABOUR_LAW_CONTEXT}

                CASE CONTEXT:
                ${contextText}

                CHAT HISTORY:
                ${chatHistoryForPrompt}
                User: ${newMessage}

                TASK: Answer the user's question with authority. Cite specific Articles of the Decree-Law No. 33. Be structured (Direct Answer -> Law -> Next Step).
                Constraint: Answer strictly in ${lang} language.`,
          });
          return { text: response.text || "Error generating response.", isFlagged: false };
      } catch (e) {
           console.warn("Gemini Chat API failed", e);
      }
  }

  // Fallback Mock
  await new Promise(resolve => setTimeout(resolve, 1000));
  return { 
    text: `${getMockResponseText(lang, 'chat')}\n\n(Context: ${newMessage})`, 
    isFlagged: false 
  };
};

