export const analyzeOfferLetter = async (base64Data: string, mimeType: string, lang: AppLanguage): Promise<OfferAnalysisResult> => {
    const ai = getAI();
    if (ai) {
        try {
            // Using gemini-2.0-flash-exp as it's often more capable with complex documents than standard flash
            // Added JSON cleaning logic to handle markdown code blocks
            const response = await ai.models.generateContent({
                model: 'gemini-2.0-flash-exp', 
                contents: {
                    parts: [
                        {
                            inlineData: {
                                mimeType: mimeType,
                                data: base64Data
                            }
                        },
                        {
                            text: `Analyze this UAE Offer Letter / Employment Contract. 
                            1. Extract Company Name, Role, and Salary.
                            2. Evaluate the "Trust Score" (0-100) based on:
                               - Clarity of terms (compliance with UAE Law Decree 33).
                               - Any illegal clauses (e.g. "visa cost deduction", "ban if resignation").
                               - Reputation Check: Based on your general knowledge of this company (if famous) or the professionalism of this document.
                            3. Identify Red Flags (Bad) and Green Flags (Good).
                            4. Summarize the reputation/health.

                            Return strictly JSON in the following format:
                            {
                                "companyName": "string",
                                "role": "string",
                                "salary": "string",
                                "trustScore": number,
                                "trustRationale": "string",
                                "redFlags": ["string"],
                                "greenFlags": ["string"],
                                "reputationSummary": "string"
                            }`
                        }
                    ]
                },
                config: {
                    responseMimeType: 'application/json'
                }
            });

            if (response.text) {
                // Remove markdown code blocks if present to prevent parsing errors
                const cleanText = response.text.replace(/```json/g, '').replace(/```/g, '').trim();
                return JSON.parse(cleanText);
            }
        } catch (e) { console.error("Analyze Offer Failed:", e); }
    }

    // ERROR STATE: Return clear error message so user knows API failed
    await new Promise(resolve => setTimeout(resolve, 1000));
    return {
        companyName: "Analysis Failed",
        role: "Please check internet or API Key",
        salary: "0",
        trustScore: 0,
        trustRationale: "We could not process this document. It might be blurry, the file type is unsupported, or the AI service is currently unreachable.",
        redFlags: ["API Connection Error"],
        greenFlags: [],
        reputationSummary: "Please try uploading a clearer image or PDF."
    };
};

