import React, { useState, useRef, useEffect } from 'react';
import { ChatMessage } from '../types';
import { chatWithAI } from '../services/geminiService';
import { Send, User, Shield, Loader2, Sparkles, MessageCircle, Lock, Crown, Trash2, Gavel, CheckCircle2, ListTodo, BookOpen } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { useSubscription } from '../contexts/SubscriptionContext';

// --- SMART FORMATTER COMPONENT ---
const SmartMessage: React.FC<{ text: string }> = ({ text }) => {
    // 1. Check if this is a structured "Legal Brief" response (contains headers like **1. Direct Answer**)
    const isStructured = text.includes('**1.') || text.includes('**Direct Answer');

    const formatInline = (str: string) => {
        // Split by bold syntax (**text**)
        const parts = str.split(/(\*\*.*?\*\*)/g);
        return parts.map((part, i) => {
            if (part.startsWith('**') && part.endsWith('**')) {
                const content = part.slice(2, -2);

                // Special Highlighting for Money (AED)
                if (content.includes('AED')) {
                    return <span key={i} className="bg-emerald-100 text-emerald-800 px-1.5 py-0.5 rounded font-extrabold mx-0.5 border border-emerald-200 shadow-sm">{content}</span>;
                }
                // Special Highlighting for Articles
                if (content.toLowerCase().includes('article')) {
                    return <span key={i} className="bg-indigo-100 text-indigo-700 px-1.5 py-0.5 rounded font-bold mx-0.5 border border-indigo-200">{content}</span>;
                }
                return <strong key={i} className="font-bold text-slate-900">{content}</strong>;
            }
            return <span key={i}>{part}</span>;
        });
    };

    if (isStructured) {
        // Split into sections based on the standard prompt structure
        const sections = text.split(/(?=\*\*\d+\.|(?:\*\*Direct Answer)|(?:\*\*The Law)|(?:\*\*Your Rights)|(?:\*\*Action Plan))/g).filter(s => s.trim());

        return (
            <div className="space-y-3 w-full">
                {sections.map((sec, idx) => {
                    const cleanSec = sec.trim();

                    if (cleanSec.match(/^\*\*(1\.|Direct)/i)) {
                        // Direct Answer Card
                        return (
                            <div key={idx} className="bg-emerald-50 border border-emerald-100 p-4 rounded-xl shadow-sm">
                                <div className="flex items-center mb-2 text-emerald-800 font-bold text-xs uppercase tracking-wider">
                                    <CheckCircle2 className="w-4 h-4 mr-2" /> Direct Answer
                                </div>
                                <p className="text-slate-800 text-sm leading-relaxed font-medium">
                                    {formatInline(cleanSec.replace(/\*\*.*?\*\*:/, '').replace(/^\*\*\d+\.\s*Direct Answer\*\*:/, ''))}
                                </p>
                            </div>
                        );
                    }

                    if (cleanSec.match(/^\*\*(2\.|The Law)/i)) {
                        // The Law Card
                        return (
                            <div key={idx} className="bg-slate-50 border-l-4 border-royal-500 p-4 rounded-r-xl my-2">
                                <div className="flex items-center mb-2 text-royal-700 font-bold text-xs uppercase tracking-wider">
                                    <BookOpen className="w-4 h-4 mr-2" /> The Law
                                </div>
                                <p className="text-slate-700 text-sm italic leading-relaxed">
                                    {formatInline(cleanSec.replace(/\*\*.*?\*\*:/, '').replace(/^\*\*\d+\.\s*The Law\*\*:/, ''))}
                                </p>
                            </div>
                        );
                    }

                    if (cleanSec.match(/^\*\*(3\.|Your Rights)/i)) {
                         // Rights Card
                         return (
                            <div key={idx} className="p-1">
                                <h4 className="font-bold text-slate-900 text-sm mb-1 flex items-center">
                                    <Shield className="w-4 h-4 mr-2 text-amber-500" /> Your Entitlements
                                </h4>
                                <div className="text-slate-700 text-sm leading-relaxed pl-6">
                                    {formatInline(cleanSec.replace(/\*\*.*?\*\*:/, '').replace(/^\*\*\d+\.\s*Your Rights\*\*:/, ''))}
                                </div>
                            </div>
                        );
                    }

                    if (cleanSec.match(/^\*\*(4\.|Action)/i)) {
                        // Action Plan Card
                        const actions = cleanSec.replace(/\*\*.*?\*\*:/, '').replace(/^\*\*\d+\.\s*Action Plan\*\*:/, '').split(/[-•]/).filter(s => s.trim());
                        return (
                            <div key={idx} className="bg-white border border-slate-200 rounded-xl p-4 mt-2 shadow-sm">
                                <div className="flex items-center mb-3 text-slate-800 font-bold text-xs uppercase tracking-wider">
                                    <ListTodo className="w-4 h-4 mr-2 text-royal-600" /> Recommended Actions
                                </div>
                                <ul className="space-y-2">
                                    {actions.map((action, aIdx) => (
                                        <li key={aIdx} className="flex items-start text-sm text-slate-700">
                                            <span className="bg-royal-100 text-royal-700 font-bold rounded-full w-5 h-5 flex items-center justify-center text-[10px] mr-2 flex-shrink-0 mt-0.5">{aIdx + 1}</span>
                                            <span>{formatInline(action.trim())}</span>
                                        </li>
                                    ))}
                                </ul>
                            </div>
                        );
                    }

                    // Fallback for other sections
                    return <div key={idx} className="text-sm text-slate-700 whitespace-pre-wrap leading-relaxed mt-2">{formatInline(cleanSec)}</div>;
                })}
            </div>
        );
    }

    // Fallback for simple/unstructured messages
    return (
        <div className="text-sm leading-relaxed whitespace-pre-wrap">
            {formatInline(text)}
        </div>
    );
};


