import React from 'react';
import { CheckCircle2, BookOpen, Shield, ListTodo, AlertCircle } from 'lucide-react';

const formatInline = (text: string) => {
  // Split by **bold** segments
  const parts = text.split(/(\*\*.*?\*\*)/g);
  return parts.map((part, i) => {
    if (part.startsWith('**') && part.endsWith('**')) {
      const content = part.slice(2, -2);

      // Highlight Money (AED)
      if (content.includes('AED')) {
         return <span key={i} className="bg-emerald-100 text-emerald-800 px-1.5 rounded font-bold border border-emerald-200 shadow-sm mx-0.5">{content}</span>;
      }

      // Highlight Articles/Laws
      if (content.toLowerCase().includes('article') || content.toLowerCase().includes('decree') || content.toLowerCase().includes('law')) {
         return <span key={i} className="bg-indigo-50 text-indigo-700 px-1.5 rounded-md font-bold border border-indigo-100 mx-0.5">{content}</span>;
      }

      return <strong key={i} className="font-bold text-slate-900">{content}</strong>;
    }
    return part;
  });
};

const renderMarkdownBlock = (text: string) => {
    if (!text) return null;

    const lines = text.split('\n');
    const elements: React.ReactNode[] = [];
    let listItems: React.ReactNode[] = [];
    let inList = false;

    lines.forEach((line, i) => {
        const trimmed = line.trim();
        if (!trimmed) return;

        // Check for bullet points (* or - or 1.)
        const isBullet = trimmed.match(/^[\*\-]\s/) || trimmed.match(/^\d+\.\s/);

        if (isBullet) {
            const content = trimmed.replace(/^[\*\-]\s/, '').replace(/^\d+\.\s/, '');
            listItems.push(
                <li key={`li-${i}`} className="mb-2 pl-1 flex items-start text-slate-700 text-sm leading-relaxed">
                    <span className="mr-2 mt-1.5 w-1.5 h-1.5 bg-royal-400 rounded-full flex-shrink-0"></span>
                    <span>{formatInline(content)}</span>
                </li>
            );
            inList = true;
        } else {
            // Flush list if we were in one
            if (inList) {
                elements.push(<ul key={`ul-${i}`} className="mb-3">{listItems}</ul>);
                listItems = [];
                inList = false;
            }
            // Regular paragraph
            elements.push(<p key={`p-${i}`} className="mb-2 text-slate-700 text-sm leading-relaxed">{formatInline(trimmed)}</p>);
        }
    });

    if (inList) {
        elements.push(<ul key={`ul-end`} className="mb-0">{listItems}</ul>);
    }

    return <div>{elements}</div>;
};

const SmartMessage: React.FC<{ text: string }> = ({ text }) => {
    // Detect if this is the structured response we requested in System Prompt
    const isStructured = 
        text.includes('**Direct Answer') || 
        text.includes('**The Law') ||
        text.includes('**1.');

    if (isStructured) {
        // Regex to split by our known headers (1. Direct Answer, 2. The Law, etc)
        const sections = text.split(/(?=\*\*(?:1\.|Direct Answer)|(?:\*\*2\.|The Law)|(?:\*\*3\.|Your Rights)|(?:\*\*4\.|Action Plan))/g).filter(s => s.trim());

        return (
            <div className="space-y-4 w-full">
                {sections.map((sec, idx) => {
                    const cleanSec = sec.trim();

                    // --- 1. DIRECT ANSWER CARD ---
                    if (cleanSec.match(/^\*\*(1\.|Direct)/i)) {
                        const content = cleanSec.replace(/\*\*.*?\*\*[:]?/, '').replace(/^\*\*\d+\.\s*Direct Answer\*\*[:]?/, '');
                        return (
                            <div key={idx} className="bg-emerald-50/80 border border-emerald-100 p-4 rounded-2xl shadow-sm">
                                <div className="flex items-center mb-2 text-emerald-800 font-bold text-xs uppercase tracking-wider">
                                    <CheckCircle2 className="w-4 h-4 mr-2" /> Direct Answer
                                </div>
                                <div className="text-slate-800">
                                    {renderMarkdownBlock(content)}
                                </div>
                            </div>
                        );
                    }

                    // --- 2. THE LAW CARD ---
                    if (cleanSec.match(/^\*\*(2\.|The Law)/i)) {
                        const content = cleanSec.replace(/\*\*.*?\*\*[:]?/, '').replace(/^\*\*\d+\.\s*The Law\*\*[:]?/, '');
                        return (
                            <div key={idx} className="bg-indigo-50/50 border-l-4 border-indigo-500 p-4 rounded-r-xl my-2">
                                <div className="flex items-center mb-2 text-indigo-700 font-bold text-xs uppercase tracking-wider">
                                    <BookOpen className="w-4 h-4 mr-2" /> Legal Basis
                                </div>
                                <div className="text-slate-700 italic">
                                    {renderMarkdownBlock(content)}
                                </div>
                            </div>
                        );
                    }

                    // --- 3. YOUR RIGHTS CARD ---
                    if (cleanSec.match(/^\*\*(3\.|Your Rights)/i)) {
                         const content = cleanSec.replace(/\*\*.*?\*\*[:]?/, '').replace(/^\*\*\d+\.\s*Your Rights\*\*[:]?/, '');
                         return (
                            <div key={idx} className="bg-amber-50/50 border border-amber-100 p-4 rounded-2xl">
                                <h4 className="font-bold text-amber-900 text-sm mb-2 flex items-center uppercase tracking-wide">
                                    <Shield className="w-4 h-4 mr-2" /> Your Entitlements
                                </h4>
                                <div className="text-slate-700">
                                    {renderMarkdownBlock(content)}
                                </div>
                            </div>
                        );
                    }

                    // --- 4. ACTION PLAN CARD ---
                    if (cleanSec.match(/^\*\*(4\.|Action)/i)) {
                        const content = cleanSec.replace(/\*\*.*?\*\*[:]?/, '').replace(/^\*\*\d+\.\s*Action Plan\*\*[:]?/, '');
                        return (
                            <div key={idx} className="bg-white border border-slate-200 rounded-2xl p-4 mt-2 shadow-sm">
                                <div className="flex items-center mb-3 text-slate-800 font-bold text-xs uppercase tracking-wider">
                                    <ListTodo className="w-4 h-4 mr-2 text-royal-600" /> Recommended Next Steps
                                </div>
                                {renderMarkdownBlock(content)}
                            </div>
                        );
                    }

                    // Fallback for sections that don't match headers perfectly
                    return <div key={idx} className="mt-2">{renderMarkdownBlock(cleanSec)}</div>;
                })}
            </div>
        );
    }

    // Fallback for non-structured simple chats
    return <div className="text-sm leading-relaxed">{renderMarkdownBlock(text)}</div>;
};

export default SmartMessage;

import React, { useState, useRef, useEffect } from 'react';
import { Case, ChatMessage, EvidenceItem } from '../types';
import { chatWithAI, analyzeEvidence } from '../services/geminiService';
import { Send, User, Shield, Loader2, Flag, Paperclip, FileText, Lock, Crown, Sparkles } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { useSubscription } from '../contexts/SubscriptionContext';
import SmartMessage from './SmartMessage';

interface Props {
  currentCase: Case;
  onUpdate: (c: Case) => void;
}

const ChatInterface: React.FC<Props> = ({ currentCase, onUpdate }) => {
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const [analyzingFile, setAnalyzingFile] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const { language, t, dir } = useLanguage();
  const { isPremium, remainingFreeChats, decrementFreeChat, setShowPaywall } = useSubscription();

  const messages = currentCase.chatHistory || [];

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, loading, analyzingFile]);

  const handleSend = async () => {
    if (!input.trim()) return;

    // Check Limits
    if (!isPremium && remainingFreeChats <= 0) {
        setShowPaywall(true);
        return;
    }

    const userMsg: ChatMessage = {
      id: Date.now().toString(),
      role: 'user',
      text: input,
      timestamp: Date.now()
    };

    const newHistory = [...messages, userMsg];
    onUpdate({ ...currentCase, chatHistory: newHistory });
    setInput('');
    setLoading(true);

    if (!isPremium) decrementFreeChat();

    try {
      const result = await chatWithAI(messages, input, currentCase, language);
      const aiMsg: ChatMessage = {
        id: (Date.now() + 1).toString(),
        role: 'model',
        text: result.text,
        timestamp: Date.now(),
        isFlaggedForReview: result.isFlagged
      };
      onUpdate({ ...currentCase, chatHistory: [...newHistory, aiMsg] });
    } catch (error) {
      console.error(error);
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
      // Documents strictly for Premium
      if (!isPremium) {
          setShowPaywall(true);
          if (fileInputRef.current) fileInputRef.current.value = '';
          return;
      }

      const file = e.target.files?.[0];
      if (!file) return;

      setAnalyzingFile(true);
      const reader = new FileReader();
      reader.onloadend = async () => {
          const base64String = reader.result as string;
          const base64Data = base64String.split(',')[1];

          try {
              const analysis = await analyzeEvidence(base64Data, file.type, language);
              const newEvidence: EvidenceItem = {
                  id: Date.now().toString(),
                  type: analysis.type as any || 'Other',
                  description: file.name,
                  summary: analysis.summary,
                  tags: analysis.tags,
                  dateAdded: new Date().toISOString(),
                  analysis: analysis.analysis
              };

              const updatedEvidenceList = [newEvidence, ...currentCase.evidence];
              const updatedCaseForAI = { ...currentCase, evidence: updatedEvidenceList };

              const userMsg: ChatMessage = {
                  id: Date.now().toString(),
                  role: 'user',
                  text: `I have uploaded a document: ${file.name}. Please analyze it.`,
                  timestamp: Date.now(),
                  attachments: [{ name: file.name, type: file.type }]
              };

              const newHistory = [...messages, userMsg];
              onUpdate({ ...updatedCaseForAI, chatHistory: newHistory });
              setAnalyzingFile(false); 
              setLoading(true);

              const result = await chatWithAI(newHistory, userMsg.text, updatedCaseForAI, language);
              const aiMsg: ChatMessage = {
                  id: (Date.now() + 1).toString(),
                  role: 'model',
                  text: result.text,
                  timestamp: Date.now(),
                  isFlaggedForReview: result.isFlagged
              };
              onUpdate({ ...updatedCaseForAI, chatHistory: [...newHistory, aiMsg] });

          } catch (error) {
              console.error(error);
              setAnalyzingFile(false);
          } finally {
              setLoading(false);
              if (fileInputRef.current) fileInputRef.current.value = '';
          }
      };
      reader.readAsDataURL(file);
  };

  return (
    <div className="flex flex-col h-[600px] bg-white rounded-3xl border border-slate-100 shadow-xl shadow-slate-200/50 overflow-hidden animate-fade-in-up" dir={dir}>

      {/* Messages Area */}
      <div className="flex-grow overflow-y-auto space-y-6 p-6 scroll-smooth" ref={scrollRef}>
        {messages.length === 0 && (
           <div className="flex flex-col items-center justify-center h-full text-center text-slate-400">
             <div className="bg-royal-50 p-4 rounded-full mb-4">
                 <Shield className="w-8 h-8 text-royal-600" />
             </div>
             <p className="font-bold text-slate-700 text-lg">AI Case Strategist</p>
             <p className="text-sm mt-1 max-w-xs leading-relaxed">I have analyzed your case details. Ask me specifically about your {currentCase.issueTypes[0]} situation.</p>
           </div>
        )}

        {messages.map((msg) => (
          <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`flex items-end max-w-[90%] md:max-w-[80%] ${msg.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
              <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 mb-1 shadow-sm ${
                msg.role === 'user' ? 'bg-royal-600 mx-2' : 'bg-white border border-slate-200 mx-2'
              }`}>
                {msg.role === 'user' ? <User className="w-5 h-5 text-white" /> : <Shield className="w-5 h-5 text-royal-600" />}
              </div>
              <div className="flex flex-col w-full">
                <div className={`p-4 rounded-2xl shadow-sm ${
                  msg.role === 'user' 
                    ? 'bg-royal-600 text-white rounded-br-none rtl:rounded-bl-none rtl:rounded-br-2xl text-sm' 
                    : 'bg-white text-slate-800 rounded-bl-none rtl:rounded-br-none rtl:rounded-bl-2xl border border-slate-100'
                }`}>
                  <SmartMessage text={msg.text} />
                  {msg.attachments && msg.attachments.length > 0 && (
                      <div className="mt-3 bg-white/20 p-2 rounded-lg flex items-center">
                          <FileText className="w-4 h-4 mr-2" />
                          <span className="text-xs font-bold underline truncate max-w-[150px]">{msg.attachments[0].name}</span>
                      </div>
                  )}
                </div>
              </div>
            </div>
          </div>
        ))}

        {analyzingFile && (
             <div className="flex justify-end">
                <div className="flex items-center space-x-2 bg-royal-50 rounded-2xl p-4 border border-royal-100">
                    <Loader2 className="w-4 h-4 animate-spin text-royal-600" />
                    <span className="text-xs text-royal-700 font-bold">Scanning Document...</span>
                </div>
             </div>
        )}

        {loading && !analyzingFile && (
          <div className="flex justify-start">
             <div className="flex items-center space-x-2 bg-slate-50 rounded-2xl p-4 border border-slate-100">
               <Loader2 className="w-4 h-4 animate-spin text-royal-600" />
               <span className="text-xs text-slate-500 font-medium">Consulting Regulations...</span>
             </div>
          </div>
        )}
      </div>

      {/* Input Area */}
      <div className="p-4 bg-white border-t border-slate-100 relative">

        {/* LOCK STATE (If Free Limit Reached) */}
        {!isPremium && remainingFreeChats <= 0 ? (
            <div className="absolute inset-0 z-10 bg-white/95 backdrop-blur-sm flex items-center justify-center p-4">
                <button 
                    onClick={() => setShowPaywall(true)}
                    className="w-full h-full rounded-2xl border-2 border-royal-100 bg-gradient-to-r from-royal-50 to-white flex items-center justify-between px-6 hover:shadow-lg transition-all group"
                >
                    <div className="flex items-center text-left">
                        <div className="bg-royal-100 p-2 rounded-full mr-4 group-hover:scale-110 transition-transform">
                            <Lock className="w-6 h-6 text-royal-600" />
                        </div>
                        <div>
                            <span className="block font-bold text-royal-900">Daily Limit Reached</span>
                            <span className="text-xs text-royal-600">Unlock unlimited expert advice</span>
                        </div>
                    </div>
                    <div className="flex items-center bg-royal-900 text-white px-4 py-2 rounded-xl text-sm font-bold shadow-md">
                        <Crown className="w-4 h-4 mr-2" /> Upgrade
                    </div>
                </button>
            </div>
        ) : (
            <>
                {/* FREE COUNT INDICATOR */}
                {!isPremium && (
                    <div className="absolute -top-3 left-1/2 -translate-x-1/2 bg-slate-900 text-white text-[10px] font-bold px-3 py-1 rounded-full shadow-md z-10 flex items-center">
                         <Sparkles className="w-3 h-3 mr-1 text-yellow-400" />
                         {remainingFreeChats} Free Messages Left
                    </div>
                )}

                <div className="flex space-x-2 items-center bg-slate-50 p-2 rounded-2xl border border-slate-200 focus-within:ring-2 focus-within:ring-royal-500/20 focus-within:border-royal-500 transition-all">
                    <input 
                        type="file" 
                        ref={fileInputRef}
                        className="hidden" 
                        onChange={handleFileUpload}
                        accept="image/*,.pdf" 
                    />
                    <button 
                        onClick={() => fileInputRef.current?.click()}
                        className="p-2 text-slate-400 hover:text-royal-600 hover:bg-slate-100 rounded-xl transition"
                        disabled={loading || analyzingFile}
                        title="Upload Document (Premium)"
                    >
                        {isPremium ? <Paperclip className="w-5 h-5" /> : <Lock className="w-4 h-4" />}
                    </button>

                    <input
                        type="text"
                        className="flex-grow bg-transparent px-3 py-2 outline-none text-slate-900 placeholder:text-slate-400 font-medium"
                        placeholder="Ask specifically about your case..."
                        value={input}
                        onChange={(e) => setInput(e.target.value)}
                        onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                        disabled={loading || analyzingFile}
                    />
                    <button
                        onClick={handleSend}
                        disabled={loading || analyzingFile || !input.trim()}
                        className="bg-royal-900 text-white p-2.5 rounded-xl hover:bg-royal-800 disabled:bg-slate-300 disabled:text-slate-400 transition shadow-sm"
                    >
                        <Send className="w-5 h-5 rtl:rotate-180" />
                    </button>
                </div>
            </>
        )}
      </div>
    </div>
  );
};

