// This service manages the "Pay & Activate" flow with Expiration Logic.

const STORAGE_KEY = "wg_license_data"; // Changed key to avoid conflicts with old format
const ZIINA_URL = "https://pay.ziina.com/ChiChi27/KfLxzYEVC";

// --- LICENSE KEY SYSTEM CONFIGURATION ---
const KEY_PREFIX = "WG-";
const SALT = "WAGEGUARD_SECURE_2024_UAE";

// Simple hash function for checksum
const simpleHash = (str: string): string => {
    let hash = 0x811c9dc5;
    for (let i = 0; i < str.length; i++) {
        hash ^= str.charCodeAt(i);
        hash = Math.imul(hash, 0x01000193);
    }
    return (hash >>> 0).toString(16).toUpperCase().slice(-4).padStart(4, '0');
};

interface LicenseData {
    status: 'active' | 'expired';
    expiryDate: string; // ISO String
}

export const PaymentService = {
  // 1. Check status (Is active AND not expired)
  isPremium: (): boolean => {
    try {
        const data = localStorage.getItem(STORAGE_KEY);
        if (!data) return false;

        const license: LicenseData = JSON.parse(data);
        if (license.status !== 'active') return false;

        const now = new Date();
        const expiry = new Date(license.expiryDate);

        return now < expiry;
    } catch (e) {
        return false;
    }
  },

  // 2. Get Days Remaining
  getDaysRemaining: (): number => {
      try {
        const data = localStorage.getItem(STORAGE_KEY);
        if (!data) return 0;

        const license: LicenseData = JSON.parse(data);
        const now = new Date();
        const expiry = new Date(license.expiryDate);

        const diffTime = expiry.getTime() - now.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

        return diffDays > 0 ? diffDays : 0;
      } catch (e) {
          return 0;
      }
  },

  getPaymentLink: (): string => {
    return ZIINA_URL; 
  },

  // 3. Validate and Activate (Set 30 Day Timer)
  activateLicense: async (code: string): Promise<boolean> => {
    const normalizedCode = code.trim().toUpperCase();

    // Demo Override
    if (normalizedCode === "WG-DEMO-TEST") {
        const expiry = new Date();
        expiry.setDate(expiry.getDate() + 30); // +30 Days
        const data: LicenseData = { status: 'active', expiryDate: expiry.toISOString() };
        localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
        return true;
    }

    // Validation Logic
    if (!normalizedCode.startsWith(KEY_PREFIX)) return false;

    const parts = normalizedCode.split('-');
    if (parts.length !== 3) return false;

    const randomPart = parts[1];
    const userChecksum = parts[2];

    const calculatedChecksum = simpleHash(randomPart + SALT);

    if (userChecksum === calculatedChecksum) {
        const expiry = new Date();
        expiry.setDate(expiry.getDate() + 30); // +30 Days

        const data: LicenseData = { 
            status: 'active', 
            expiryDate: expiry.toISOString() 
        };
        localStorage.setItem(STORAGE_KEY, JSON.stringify(data));
        return true;
    }

    return false;
  },

  // 4. Check if a previous subscription existed but is now expired
  isExpired: (): boolean => {
     try {
        const data = localStorage.getItem(STORAGE_KEY);
        if (!data) return false; // Never subscribed

        const license: LicenseData = JSON.parse(data);
        const now = new Date();
        const expiry = new Date(license.expiryDate);

        return now >= expiry;
     } catch (e) {
         return false;
     }
  },

  restorePurchases: async (): Promise<boolean> => {
     return PaymentService.isPremium();
  },

  purchaseSubscription: async (): Promise<boolean> => {
     if (typeof window !== 'undefined') {
         window.open(ZIINA_URL, '_blank');
     }
     return false; 
  },

  adminGenerateKey: (random4Chars: string) => {
      const r = random4Chars.toUpperCase().slice(0, 4);
      const checksum = simpleHash(r + SALT);
      const fullKey = `${KEY_PREFIX}${r}-${checksum}`;
      console.log(`%c GENERATED KEY: ${fullKey} `, 'background: #222; color: #bada55; font-size: 16px; padding: 4px;');
      return fullKey;
  },

  reset: () => {
    localStorage.removeItem(STORAGE_KEY);
  }
};

if (typeof window !== 'undefined') {
    (window as any).GenerateLicense = PaymentService.adminGenerateKey;
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { PaymentService } from '../services/paymentService';

interface SubscriptionContextType {
  isPremium: boolean;
  isExpired: boolean;
  remainingFreeChats: number;
  daysRemaining: number;
  isLoading: boolean;
  upgradeToPremium: () => Promise<boolean>;
  restorePurchases: () => Promise<boolean>;
  decrementFreeChat: () => void;
  showPaywall: boolean;
  setShowPaywall: (show: boolean) => void;
}

const SubscriptionContext = createContext<SubscriptionContextType | undefined>(undefined);

const DAILY_FREE_CHAT_LIMIT = 3;

export const SubscriptionProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isPremium, setIsPremium] = useState(false);
  const [isExpired, setIsExpired] = useState(false);
  const [daysRemaining, setDaysRemaining] = useState(0);
  const [isLoading, setIsLoading] = useState(true);
  const [remainingFreeChats, setRemainingFreeChats] = useState(DAILY_FREE_CHAT_LIMIT);
  const [showPaywall, setShowPaywall] = useState(false);

  // Initial Security & Expiry Check
  useEffect(() => {
    const checkStatus = () => {
        const hasValidLicense = PaymentService.isPremium();
        const hasExpired = PaymentService.isExpired();
        const days = PaymentService.getDaysRemaining();

        setIsPremium(hasValidLicense);
        setIsExpired(hasExpired);
        setDaysRemaining(days);

        // Chat limit logic
        const storedChatData = localStorage.getItem('wg_chat_limit');
        if (storedChatData) {
            const { count, date } = JSON.parse(storedChatData);
            const today = new Date().toDateString();
            if (date === today) {
                setRemainingFreeChats(count);
            } else {
                setRemainingFreeChats(DAILY_FREE_CHAT_LIMIT);
                localStorage.setItem('wg_chat_limit', JSON.stringify({ count: DAILY_FREE_CHAT_LIMIT, date: today }));
            }
        }
        setIsLoading(false);
    };

    checkStatus();
  }, []);

  const upgradeToPremium = async () => {
    setIsLoading(true);
    const success = await PaymentService.purchaseSubscription();
    if (success) {
        // Note: Real update happens after key entry in Paywall
    }
    setIsLoading(false);
    return success;
  };

  const restorePurchases = async () => {
      setIsLoading(true);
      const success = await PaymentService.restorePurchases();
      if (success) {
          setIsPremium(true);
          setDaysRemaining(PaymentService.getDaysRemaining());
          setShowPaywall(false);
      }
      setIsLoading(false);
      return success;
  }

  const decrementFreeChat = () => {
      if (isPremium) return;
      const newCount = Math.max(0, remainingFreeChats - 1);
      setRemainingFreeChats(newCount);
      const today = new Date().toDateString();
      localStorage.setItem('wg_chat_limit', JSON.stringify({ count: newCount, date: today }));
  };

  return (
    <SubscriptionContext.Provider value={{ 
        isPremium,
        isExpired, 
        remainingFreeChats, 
        daysRemaining,
        isLoading,
        upgradeToPremium, 
        restorePurchases,
        decrementFreeChat, 
        showPaywall, 
        setShowPaywall
    }}>
      {children}
    </SubscriptionContext.Provider>
  );
};

export const useSubscription = () => {
  const context = useContext(SubscriptionContext);
  if (!context) {
    throw new Error('useSubscription must be used within a SubscriptionProvider');
  }
  return context;
};

