import React, { useState } from 'react';
import { Case } from '../types';
import { generateLegalNotice } from '../services/geminiService';
import { Printer, Copy, Globe, FileSignature, Loader2, Check, PenTool, Lock, Crown } from 'lucide-react';
import { useLanguage } from '../contexts/LanguageContext';
import { useSubscription } from '../contexts/SubscriptionContext';

interface Props {
  currentCase: Case;
}

const LetterGenerator: React.FC<Props> = ({ currentCase }) => {
  const { t } = useLanguage();
  const { isPremium, setShowPaywall } = useSubscription();
  const [loading, setLoading] = useState(false);
  const [letter, setLetter] = useState<{ subject: string; englishBody: string; arabicBody: string } | null>(null);
  const [viewLang, setViewLang] = useState<'en' | 'ar'>('en');
  const [copied, setCopied] = useState(false);

  const handleGenerate = async () => {
    setLoading(true);
    try {
      const result = await generateLegalNotice(currentCase);
      setLetter(result);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  const handleCopy = () => {
    if (!letter) return;
    const text = viewLang === 'en' ? letter.englishBody : letter.arabicBody;
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handlePrint = () => {
    if (!letter) return;
    const printWindow = window.open('', '', 'width=800,height=600');
    if (printWindow) {
      printWindow.document.write(`
        <html>
          <head>
            <title>Formal Notice - ${currentCase.title}</title>
            <style>
              body { font-family: 'Times New Roman', serif; padding: 40px; line-height: 1.6; max-width: 800px; margin: 0 auto; }
              h2 { text-align: center; text-decoration: underline; margin-bottom: 30px; }
              .content { white-space: pre-wrap; font-size: 14px; }
              .footer { margin-top: 50px; font-style: italic; font-size: 12px; color: #666; text-align: center; border-top: 1px solid #ccc; padding-top: 10px;}
            </style>
          </head>
          <body>
            <h2>${letter.subject}</h2>
